                <div style={{ textAlign: 'center', marginTop: '3rem', fontSize: '0.65rem', fontWeight: 900, color: '#94a3b8', letterSpacing: '0.2em', textTransform: 'uppercase' }}>
                    Documento certificado según normativas de seguridad industrial.
                </div>

            </div>
        </div>
    );
}

