import { useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { ADMIN_EMAILS } from '../config';

/**
 * usePaywall – call this in any page that has premium actions.
 */
export function usePaywall() {
    const navigate = useNavigate();
    const { currentUser } = useAuth();

    /** Returns true if the subscription exists AND has not expired yet OR if user is admin */
    const isActive = () => {
        // Master Bypass for Owner/Admin
        if (currentUser?.email && ADMIN_EMAILS.includes(currentUser.email)) {
            return true;
        }

        try {
            const subData = JSON.parse(localStorage.getItem('subscriptionData') || '{}');
            if (subData.status !== 'active') return false;

            const expiry = parseInt(subData.expiry || '0', 10);
            if (!expiry) return true; // Infinite if not set? Better to return false or handle as legacy
            if (Date.now() > expiry) {
                return false;
            }
            return true;
        } catch (e) {
            return false;
        }
    };

    const requirePro = (action) => {
        if (!currentUser) {
            navigate('/login');
            return;
        }
        if (!isActive()) {
            navigate('/subscribe');
            return;
        }
        if (typeof action === 'function') action();
    };

    const isPro = () => !!currentUser && isActive();

    /** Days remaining in current subscription period (0 if expired/none) */
    const daysRemaining = () => {
        if (!isPro()) return 0;
        
        // Master Bypass for Owner/Admin
        if (currentUser?.email && ADMIN_EMAILS.includes(currentUser.email)) {
            return Infinity;
        }

        try {
            const subData = JSON.parse(localStorage.getItem('subscriptionData') || '{}');
            const expiry = parseInt(subData.expiry || '0', 10);
            if (!expiry) return 0;
            return Math.max(0, Math.ceil((expiry - Date.now()) / (1000 * 60 * 60 * 24)));
        } catch (e) {
            return 0;
        }
    };

    /** Returns 'active', 'expired', or 'none' */
    const getStatus = () => {
        if (currentUser?.email && ADMIN_EMAILS.includes(currentUser.email)) {
            return 'active';
        }
        try {
            const subData = JSON.parse(localStorage.getItem('subscriptionData') || '{}');
            if (!subData.status) return 'none';
            if (subData.status !== 'active') return 'none'; // Could be 'inactive'
            
            const expiry = parseInt(subData.expiry || '0', 10);
            if (!expiry) return 'active'; // Assume active if status is active but no expiry set
            if (Date.now() > expiry) return 'expired';
            return 'active';
        } catch (e) {
            return 'none';
        }
    };

    const status = getStatus();

    return { 
        requirePro, 
        isPro, 
        daysRemaining, 
        status, // 'active', 'expired', 'none'
        isActive: status === 'active'
    };
}

import React, { useState, useRef, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { ArrowLeft, Camera, RefreshCw, CheckCircle, TriangleAlert, ShieldCheck, Zap, ZapOff, FlipHorizontal } from 'lucide-react';
import { API_BASE_URL } from '../config';
import { usePaywall } from '../hooks/usePaywall';
import { useSync } from '../contexts/SyncContext';
import toast from 'react-hot-toast';
import { useDocumentTitle } from '../hooks/useDocumentTitle';

export default function AICamera() {
    const navigate = useNavigate();
    const { requirePro } = usePaywall();
    const { syncCollection } = useSync();
    useDocumentTitle('Cámara Inteligente EPP');
    const videoRef = useRef(null);
    const canvasRef = useRef(null);
    const [stream, _setStream] = useState(null);
    const streamRef = useRef(null);
    const [capturedImage, setCapturedImage] = useState(null);
    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [analysisResult, setAnalysisResult] = useState(null);
    const [torchOn, setTorchOn] = useState(false);
    const [facingMode, setFacingMode] = useState('environment'); // 'environment' or 'user'

    const setStream = (newStream) => {
        streamRef.current = newStream;
        _setStream(newStream);
    };

    useEffect(() => {
        startCamera();
        return () => {
            stopStream();
        };
    }, [facingMode]);

    const stopStream = () => {
        if (streamRef.current) {
            streamRef.current.getTracks().forEach(track => {
                track.stop();
            });
            streamRef.current = null;
        }
        _setStream(null);
    };

    const startCamera = async () => {
        stopStream();
        try {
            const constraints = {
                video: {
                    facingMode: facingMode,
                    width: { ideal: 800 },
                    height: { ideal: 600 }
                }
            };
            const newStream = await navigator.mediaDevices.getUserMedia(constraints);
            setStream(newStream);
            if (videoRef.current) videoRef.current.srcObject = newStream;
            setTorchOn(false);
        } catch (err) {
            console.error("Error accessing camera:", err);
            toast.error("No se pudo acceder a la cámara. Por favor, asegúrese de dar los permisos necesarios.");
        }
    };

    const toggleTorch = async () => {
        if (!streamRef.current) return;
        const track = streamRef.current.getVideoTracks()[0];
        try {
            const capabilities = track.getCapabilities();
            if (!capabilities.torch) {
                toast.error("Este dispositivo no soporta linterna o no está disponible en esta cámara.");
                return;
            }
            const newTorchState = !torchOn;
            await track.applyConstraints({
                advanced: [{ torch: newTorchState }]
            });
            setTorchOn(newTorchState);
        } catch (err) {
            console.error("Torch error:", err);
            toast.error("Error al controlar la linterna.");
        }
    };

    const switchCamera = () => {
        setFacingMode(prev => prev === 'environment' ? 'user' : 'environment');
    };

    const handleCapture = () => {
        if (!videoRef.current || !canvasRef.current) return;

        const video = videoRef.current;
        const canvas = canvasRef.current;

        // Manual resizing to ensure small payload (max 800px width)
        const maxWidth = 800;
        const scale = video.videoWidth > maxWidth ? maxWidth / video.videoWidth : 1;
        canvas.width = video.videoWidth * scale;
        canvas.height = video.videoHeight * scale;
        console.log(`[CAPTURE] Resizing to ${canvas.width}x${canvas.height} (scale: ${scale.toFixed(2)})`);

        const ctx = canvas.getContext('2d');
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

        const imageData = canvas.toDataURL('image/jpeg', 0.6);
        setCapturedImage(imageData);

        stopStream();
        analyzeImage(imageData);
    };

    const analyzeImage = async (imageSrc) => {
        setIsAnalyzing(true);
        try {
            const fetchUrl = `${API_BASE_URL}/api/analyze-image`;
            const response = await fetch(fetchUrl, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ image: imageSrc })
            });
            const contentType = response.headers.get("content-type");
            let data;

            if (contentType && contentType.includes("application/json")) {
                data = await response.json();
            } else {
                const text = await response.text();
                console.error("Non-JSON response received:", text.substring(0, 200));
                throw new Error("El servidor no devolvió JSON (posible error de ruta o servidor)");
            }

            if (!response.ok) {
                console.error("Error from AI API:", data);
                toast.error(data.error || `Error ${response.status}`);
                handleRetry();
                return;
            }
            if (!data.personDetected && data.personDetected !== undefined) {
                toast.error("La IA no detectó a ninguna persona clara.");
            }

            if (data.detections && data.detections.length > 0) {
                const markedImage = await drawDetections(imageSrc, data.detections);
                setCapturedImage(markedImage);
            }

            setAnalysisResult(data);
        } catch (error) {
            console.error("Red / Error crítico de IA:", error);
            const detail = error.message || "Error desconocido";
            let msg = "Error de conexión.";
            if (detail.includes('404')) msg = "Modelo no disponible.";
            if (detail.includes('413')) msg = "Imagen demasiado pesada para el servidor.";

            toast.error(`Falla de IA: ${msg}`);
            handleRetry();
        } finally {
            setIsAnalyzing(false);
        }
    };

    const drawDetections = (imageSrc, detections) => {
        return new Promise((resolve) => {
            const img = new Image();
            img.onload = () => {
                const canvas = canvasRef.current;
                canvas.width = img.width;
                canvas.height = img.height;
                const ctx = canvas.getContext('2d');
                ctx.drawImage(img, 0, 0);

                detections.forEach((det, index) => {
                    if (!det.box_2d) return;
                    const [ymin, xmin, ymax, xmax] = det.box_2d;
                    const centerX = ((xmin + xmax) / 2 / 1000) * canvas.width;
                    const centerY = ((ymin + ymax) / 2 / 1000) * canvas.height;
                    const radius = Math.max(((xmax - xmin) / 2000) * canvas.width, 20);
                    const isRisk = det.label.toLowerCase().includes('riesgo');
                    const color = isRisk ? '#ef4444' : '#3b82f6';

                    ctx.strokeStyle = color;
                    ctx.lineWidth = 4;
                    ctx.beginPath();
                    ctx.arc(centerX, centerY, radius, 0, 2 * Math.PI);
                    ctx.stroke();

                    ctx.fillStyle = color;
                    ctx.beginPath();
                    ctx.arc(centerX + radius, centerY - radius, 15, 0, 2 * Math.PI);
                    ctx.fill();

                    ctx.fillStyle = 'var(--color-surface)';
                    ctx.font = 'bold 20px Inter, sans-serif';
                    ctx.textAlign = 'center';
                    ctx.textBaseline = 'middle';
                    ctx.fillText(index + 1, centerX + radius, centerY - radius);
                });

                resolve(canvas.toDataURL('image/jpeg', 0.8));
            };
            img.src = imageSrc;
        });
    };

    const handleSaveReport = () => {
        requirePro(() => {
            const currentReport = JSON.parse(localStorage.getItem('current_report') || '{}');
            const company = currentReport.company || currentReport.empresa || 'Empresa Local';
            const location = currentReport.location || currentReport.ubicacion || 'Planta Principal';

            const report = {
                id: Date.now(),
                image: capturedImage,
                analysis: analysisResult,
                date: new Date().toISOString(),
                company,
                location,
                type: 'ppe_check', // Always set type so history shows correct badge
            };
            
            // Save FULL report to a unique key to prevent history fragmentation
            localStorage.setItem(`ai_report_full_${report.id}`, JSON.stringify(report));
            
            // Still set current_ai_inspection for immediate navigation
            localStorage.setItem('current_ai_inspection', JSON.stringify(report));
            
            const history = JSON.parse(localStorage.getItem('ai_camera_history') || '[]');
            // Only add if not a duplicate (same id)
            if (!history.find(h => h.id === report.id)) {
                history.unshift({
                    id: report.id,
                    date: report.date,
                    company: report.company,
                    location: report.location,
                    type: report.type,
                    ppeComplete: report.analysis?.ppeComplete
                });
                localStorage.setItem('ai_camera_history', JSON.stringify(history));
                syncCollection('ai_camera_history', history);
            }
            navigate('/ai-report');
        });
    };


    const handleRetry = () => {
        setCapturedImage(null);
        setAnalysisResult(null);
        startCamera();
    };

    return (
        <div className="container" style={{ paddingBottom: '3rem', position: 'relative', minHeight: '100vh', display: 'flex', flexDirection: 'column' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '1.5rem', zIndex: 10 }}>
                <button onClick={() => navigate('/#tools')} style={{ padding: '0.5rem', background: 'rgba(255,255,255,0.1)', border: 'none', cursor: 'pointer', borderRadius: '50%', color: 'var(--color-primary)' }}>
                    <ArrowLeft />
                </button>
                <h1 style={{ margin: 0, fontSize: '1.5rem' }}>Escaneo con IA</h1>
            </div>

            <div style={{ flex: 1, position: 'relative', borderRadius: '24px', overflow: 'hidden', background: 'var(--color-text)', border: '4px solid var(--color-border)', boxShadow: '0 20px 50px rgba(0,0,0,0.3)' }}>
                {!capturedImage ? (
                    <>
                        <video
                            ref={videoRef}
                            autoPlay
                            playsInline
                            style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', objectFit: 'cover' }}
                        />
                        <div style={{ position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%, -50%)', border: '2px dashed rgba(255,255,255,0.3)', width: '70%', height: '60%', borderRadius: '20px', pointerEvents: 'none' }}></div>

                        {/* Controles de cámara superior */}
                        <div style={{ position: 'absolute', top: '1rem', right: '1rem', display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                            <button onClick={toggleTorch} style={{ width: '44px', height: '44px', borderRadius: '50%', background: torchOn ? 'var(--color-primary)' : 'rgba(0,0,0,0.5)', border: 'none', color: 'var(--color-surface)', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' }}>
                                {torchOn ? <Zap size={20} /> : <ZapOff size={20} />}
                            </button>
                            <button onClick={switchCamera} style={{ width: '44px', height: '44px', borderRadius: '50%', background: 'rgba(0,0,0,0.5)', border: 'none', color: 'var(--color-surface)', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' }}>
                                <FlipHorizontal size={20} />
                            </button>
                        </div>

                        <div style={{ position: 'absolute', bottom: '2rem', left: '0', width: '100%', display: 'flex', justifyContent: 'center' }}>
                            <button
                                onClick={handleCapture}
                                style={{ width: '80px', height: '80px', borderRadius: '50%', border: '6px solid #fff', background: 'rgba(59, 130, 246, 0.8)', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--color-surface)', boxShadow: '0 0 20px rgba(59, 130, 246, 0.5)' }}
                            >
                                <Camera size={32} />
                            </button>
                        </div>
                    </>
                ) : (
                    <div style={{ position: 'relative', width: '100%', height: '100%' }}>
                        <img src={capturedImage} alt="Captured" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />

                        {isAnalyzing && (
                            <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', background: 'rgba(0,0,0,0.7)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', color: 'var(--color-surface)' }}>
                                <RefreshCw size={48} className="spin" style={{ marginBottom: '1rem', color: 'var(--color-primary)' }} />
                                <p style={{ fontWeight: 700, fontSize: '1.2rem' }}>Analizando Persona...</p>
                            </div>
                        )}

                        {analysisResult && (
                            <div style={{ position: 'absolute', bottom: 0, left: 0, width: '100%', padding: '1.5rem', boxSizing: 'border-box', background: 'linear-gradient(transparent, rgba(0,0,0,0.95))', color: 'var(--color-surface)' }}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '1rem', flexWrap: 'wrap' }}>
                                    {analysisResult.helmetUsed ? (
                                        <div style={{ background: '#10b981', padding: '0.6rem 1rem', borderRadius: '12px', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                                            <ShieldCheck size={18} /> <span style={{ fontWeight: 700, fontSize: '0.9rem' }}>Casco Detectado</span>
                                        </div>
                                    ) : (
                                        <div style={{ background: '#ef4444', padding: '0.6rem 1rem', borderRadius: '12px', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                                            <TriangleAlert size={18} /> <span style={{ fontWeight: 700, fontSize: '0.9rem' }}>⚠️ FALTA CASCO</span>
                                        </div>
                                    )}
                                </div>
                                <div style={{ display: 'flex', gap: '0.6rem', width: '100%', justifyContent: 'center', flexWrap: 'wrap' }}>
                                    <button onClick={handleRetry} className="btn-outline" style={{ flex: 1, minWidth: '130px', borderColor: 'var(--color-surface)', color: 'var(--color-surface)', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.4rem', height: '46px', margin: 0, padding: '0 0.5rem', fontSize: '0.85rem' }}>
                                        <RefreshCw size={16} /> Reintentar
                                    </button>
                                    <button onClick={handleSaveReport} className="btn-primary" style={{ flex: 1, minWidth: '130px', height: '46px', margin: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '0 0.5rem', fontSize: '0.85rem' }}>Generar Informe</button>
                                </div>
                            </div>
                        )}
                    </div>
                )}
            </div>
            <canvas ref={canvasRef} style={{ display: 'none' }} />
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { ArrowLeft, Search, Trash2, Camera, Calendar, Building2, ShieldCheck, TriangleAlert, Share2, Info, FileText, QrCode, Download, BarChart2 } from 'lucide-react';
import { useSync } from '../contexts/SyncContext';
import { useAuth } from '../contexts/AuthContext';
import toast from 'react-hot-toast';
import QRModal from '../components/QRModal';
import { downloadCSV } from '../services/exportCsv';
import ShareModal from '../components/ShareModal';
import AiReportPdfGenerator from '../components/AiReportPdfGenerator';

function DeleteConfirm({ onConfirm, onCancel }) {
    return (
        <div style={{
            position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.45)',
            zIndex: 999, display: 'flex', alignItems: 'center', justifyContent: 'center',
            backdropFilter: 'blur(4px)'
        }}>
            <div style={{
                background: 'var(--color-surface)', borderRadius: '20px', padding: '2rem',
                maxWidth: '360px', width: '90%', boxShadow: '0 20px 60px rgba(0,0,0,0.2)',
                textAlign: 'center'
            }}>
                <div style={{ fontSize: '2.5rem', marginBottom: '0.8rem' }}>🗑️</div>
                <h3 style={{ margin: '0 0 0.5rem', fontWeight: 900, color: 'var(--color-text)' }}>¿Eliminar informe?</h3>
                <p style={{ margin: '0 0 1.5rem', color: 'var(--color-text-muted)', fontSize: '0.85rem' }}>Esta acción no se puede deshacer.</p>
                <div style={{ display: 'flex', gap: '0.8rem' }}>
                    <button onClick={onCancel} style={{ flex: 1, padding: '0.8rem', borderRadius: '12px', background: 'var(--color-background)', border: 'none', cursor: 'pointer', fontWeight: 800, fontSize: '0.85rem', color: 'var(--color-text)' }}>Cancelar</button>
                    <button onClick={onConfirm} style={{ flex: 1, padding: '0.8rem', borderRadius: '12px', background: 'linear-gradient(135deg,#ef4444,#dc2626)', border: 'none', cursor: 'pointer', fontWeight: 800, fontSize: '0.85rem', color: '#ffffff' }}>Eliminar</button>
                </div>
            </div>
        </div>
    );
}

export default function AICameraHistory() {
    const navigate = useNavigate();
    const { syncCollection, syncPulse } = useSync();
    const { currentUser } = useAuth();
    const [history, setHistory] = useState([]);
    const [searchTerm, setSearchTerm] = useState('');
    const [deleteTarget, setDeleteTarget] = useState(null);
    const [qrTarget, setQrTarget] = useState(null);
    const [shareItem, setShareItem] = useState(null);

    useEffect(() => {
        const raw = localStorage.getItem('ai_camera_history');
        if (!raw) return;
        try {
            const parsed = JSON.parse(raw);
            // Filtrar registros inválidos/corruptos
            const valid = parsed.filter(item => {
                if (!item || !item.id) return false;
                if (!item.date) return false;

                const company = String(item.company || '').trim();
                const location = String(item.location || '').trim();

                // Si ambos están vacíos o contienen 'undefined' literal, son corruptos
                const isBadCompany = !company || company === 'undefined' || company === 'null';
                const isBadLocation = !location || location === 'undefined' || location === 'null';

                if (isBadCompany && isBadLocation) return false;

                return true;
            });
            // Auto-cleanup: quita registros inválidos del localStorage y Firebase
            if (valid.length !== parsed.length) {
                localStorage.setItem('ai_camera_history', JSON.stringify(valid));
                // Push cleaned array to cloud so it doesn't come back
                syncCollection('ai_camera_history', valid);
            }
            setHistory(valid);
        } catch {
            setHistory([]);
        }
    }, [syncPulse]);

    const confirmDelete = () => {
        const updated = history.filter(item => item.id !== deleteTarget);
        setHistory(updated);
        localStorage.setItem('ai_camera_history', JSON.stringify(updated));
        
        // Cleanup the full report from storage to keep it lean
        localStorage.removeItem(`ai_report_full_${deleteTarget}`);
        
        syncCollection('ai_camera_history', updated);
        setDeleteTarget(null);
    };

    const filtered = history.filter(item =>
        item.company?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        item.location?.toLowerCase().includes(searchTerm.toLowerCase())
    );

    const total = history.length;
    const eppOk = history.filter(i => i.ppeComplete).length;
    const eppFail = history.filter(i => i.ppeComplete === false).length;
    const compliance = total > 0 ? Math.round((eppOk / Math.max(eppOk + eppFail, 1)) * 100) : 0;

    // Weekly stats for the chart
    const getWeeklyStats = () => {
        const stats = [];
        const now = new Date();
        for (let i = 5; i >= 0; i--) {
            const start = new Date(now);
            start.setDate(now.getDate() - (i * 7 + 6));
            start.setHours(0, 0, 0, 0);
            const end = new Date(now);
            end.setDate(now.getDate() - (i * 7));
            end.setHours(23, 59, 59, 999);

            const weekItems = history.filter(item => {
                const d = new Date(item.date);
                return d >= start && d <= end;
            });

            const wTotal = weekItems.length;
            const wOk = weekItems.filter(item => item.ppeComplete).length;
            const wFail = weekItems.filter(item => item.ppeComplete === false).length;
            const wComp = wTotal > 0 ? Math.round((wOk / Math.max(wOk + wFail, 1)) * 100) : 0;

            stats.push({ label: i === 0 ? 'Hoy' : `hace ${i}s`, value: wComp, count: wTotal });
        }
        return stats;
    };
    const weeklyStats = getWeeklyStats();

    const handleExportCSV = () => {
        downloadCSV(filtered.map(i => ({
            empresa: i.company, ubicacion: i.location,
            fecha: i.date ? new Date(i.date).toLocaleDateString('es-AR') : '',
            resultado: i.ppeComplete ? 'EPP OK' : (i.type === 'general_risks' ? 'Entorno' : 'Falta EPP')
        })), 'camara_ia_historial', {
            empresa: 'Empresa', ubicacion: 'Ubicación', fecha: 'Fecha', resultado: 'Resultado'
        });
    };

    return (
        <div className="container" style={{ maxWidth: '800px', paddingBottom: '5rem' }}>
            {deleteTarget && <DeleteConfirm onConfirm={confirmDelete} onCancel={() => setDeleteTarget(null)} />}
            {qrTarget && <QRModal text={qrTarget.text} title={qrTarget.title} onClose={() => setQrTarget(null)} />}

            <ShareModal
                open={!!shareItem}
                onClose={() => setShareItem(null)}
                title={`Inspección IA - ${shareItem?.company || ''}`}
                text={shareItem ? `📸 Inspección Visual con IA\n🏗️ Empresa: ${shareItem.company || 'Local'}\n📍 Tipo: ${shareItem.type === 'general_risks' ? 'Riesgos Generales' : 'Verificación EPP'}\n🛡️ Resultado: ${shareItem.type === 'general_risks' ? 'Análisis de entorno' : (shareItem.ppeComplete ? '✅ EPP OK' : '⚠️ Falta EPP')}` : ''}
                elementIdToPrint="pdf-content"
            />

            <div style={{ position: 'absolute', left: '-9999px', top: '-9999px', pointerEvents: 'none' }}>
                {shareItem && <AiReportPdfGenerator item={shareItem} />}
            </div>

            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: '1rem', marginBottom: '2rem', flexWrap: 'wrap' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.8rem', minWidth: '200px' }}>
                    <button onClick={() => navigate('/#activity')} style={{ padding: '0.5rem', background: 'transparent', border: 'none', cursor: 'pointer', color: 'var(--color-text)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                        <ArrowLeft />
                    </button>
                    <div>
                        <h1 style={{ margin: 0, fontSize: 'clamp(1.1rem, 4vw, 1.4rem)', fontWeight: 800, lineHeight: 1.2 }}>Cámara IA</h1>
                        <p style={{ margin: 0, fontSize: '0.75rem', color: 'var(--color-text-muted)', fontWeight: 600 }}>Inspecciones visuales</p>
                    </div>
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                    {history.length > 0 && (
                        <button onClick={handleExportCSV} style={{ display: 'flex', alignItems: 'center', gap: '0.4rem', background: '#36B37E', border: 'none', borderRadius: '8px', padding: '0.5rem 0.8rem', fontSize: '0.75rem', fontWeight: 800, cursor: 'pointer', color: '#ffffff', boxShadow: '0 4px 12px rgba(54, 179, 126, 0.3)' }}>
                            <Download size={14} /> <span className="hidden sm:inline">EXCEL</span>
                        </button>
                    )}
                    <button
                        onClick={() => navigate('/ai-camera')}
                        className="btn-primary"
                        style={{ padding: '0.6rem 1rem', display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.85rem', width: 'auto', margin: 0 }}
                    >
                        <Camera size={18} /> <span className="hidden sm:inline">NUEVO</span>
                    </button>
                </div>
            </div>

            {/* Stats panel */}
            {total > 0 && (
                <div style={{ marginBottom: '2rem' }}>
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '0.7rem', marginBottom: '1rem' }}>
                        <div style={{ background: 'rgba(6,182,212,0.08)', border: '1px solid rgba(6,182,212,0.2)', borderRadius: '12px', padding: '0.75rem 1rem', textAlign: 'center' }}>
                            <div style={{ fontSize: '1.5rem', fontWeight: 900, color: '#06b6d4' }}>{total}</div>
                            <div style={{ fontSize: '0.68rem', color: 'var(--color-text-muted)', fontWeight: 700 }}>INSPECCIONES</div>
                        </div>
                        <div style={{ background: 'rgba(16,185,129,0.08)', border: '1px solid rgba(16,185,129,0.2)', borderRadius: '12px', padding: '0.75rem 1rem', textAlign: 'center' }}>
                            <div style={{ fontSize: '1.5rem', fontWeight: 900, color: '#10b981' }}>{compliance}%</div>
                            <div style={{ fontSize: '0.68rem', color: 'var(--color-text-muted)', fontWeight: 700 }}>COMPLIANCE EPP</div>
                        </div>
                        <div style={{ background: eppFail > 0 ? 'rgba(239,68,68,0.08)' : 'rgba(16,185,129,0.08)', border: `1px solid ${eppFail > 0 ? 'rgba(239,68,68,0.2)' : 'rgba(16,185,129,0.2)'}`, borderRadius: '12px', padding: '0.75rem 1rem', textAlign: 'center' }}>
                            <div style={{ fontSize: '1.5rem', fontWeight: 900, color: eppFail > 0 ? '#ef4444' : '#10b981' }}>{eppFail}</div>
                            <div style={{ fontSize: '0.68rem', color: 'var(--color-text-muted)', fontWeight: 700 }}>SIN EPP</div>
                        </div>
                    </div>

                    {/* Weekly Chart */}
                    <div className="card" style={{ padding: '1.2rem', background: 'var(--color-surface)' }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.2rem' }}>
                            <h3 style={{ margin: 0, fontSize: '0.85rem', fontWeight: 800, color: 'var(--color-text)' }}>Tendencia de Compliance (últimas 6 semanas)</h3>
                            <BarChart2 size={16} color="var(--color-text-muted)" />
                        </div>
                        <div style={{ display: 'flex', alignItems: 'flex-end', justifyContent: 'space-between', height: '100px', gap: '8px', padding: '0 5px' }}>
                            {weeklyStats.map((s, i) => (
                                <div key={i} style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '8px' }}>
                                    <div style={{ position: 'relative', width: '100%', height: '80px', display: 'flex', alignItems: 'flex-end' }}>
                                        {/* Background track */}
                                        <div style={{ position: 'absolute', width: '100%', height: '100%', background: 'var(--color-background)', borderRadius: '4px', opacity: 0.5 }} />
                                        {/* Value bar */}
                                        <div style={{
                                            width: '100%',
                                            height: `${s.value}%`,
                                            background: s.value > 80 ? '#10b981' : (s.value > 50 ? '#f59e0b' : '#ef4444'),
                                            borderRadius: '4px',
                                            zIndex: 1,
                                            transition: 'height 1s ease-out'
                                        }} title={`${s.value}% compliance (${s.count} insp)`} />
                                    </div>
                                    <span style={{ fontSize: '0.6rem', color: 'var(--color-text-muted)', fontWeight: 700, textTransform: 'uppercase' }}>{s.label}</span>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            )}

            <div style={{ position: 'relative', marginBottom: '1.5rem' }}>
                <Search style={{ position: 'absolute', left: '1rem', top: '50%', transform: 'translateY(-50%)', color: 'var(--color-text-muted)' }} size={18} />
                <input
                    type="text"
                    placeholder="Buscar por empresa o ubicación..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    style={{
                        width: '100%', padding: '0.8rem 1rem 0.8rem 2.8rem',
                        borderRadius: '12px', border: '1px solid var(--color-border)',
                        background: 'var(--color-surface)', fontSize: '0.95rem'
                    }}
                />
            </div>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                {filtered.length > 0 ? (
                    filtered.map((item) => (
                        <div key={item.id} className="card" style={{ padding: '1.2rem' }}>
                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start', marginBottom: '1rem', flexWrap: 'wrap', gap: '1rem' }}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '0.8rem', flex: 1, minWidth: 0 }}>
                                    <div style={{ width: '45px', height: '45px', background: 'rgba(6,182,212,0.1)', borderRadius: '10px', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#06b6d4' }}>
                                        <Camera size={22} />
                                    </div>
                                    <div>
                                        <h3 style={{ margin: 0, fontSize: '1.05rem', fontWeight: 700, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{item.company || 'Empresa sin nombre'}</h3>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '0.4rem', fontSize: '0.8rem', color: 'var(--color-text-muted)', marginTop: '0.2rem' }}>
                                            <Calendar size={14} /> {new Date(item.date).toLocaleDateString()} — <Building2 size={14} /> {item.location}
                                        </div>
                                    </div>
                                </div>
                                {item.type === 'general_risks' ? (
                                    <div style={{
                                        display: 'flex', alignItems: 'center', gap: '0.4rem',
                                        fontSize: '0.75rem', fontWeight: 700,
                                        padding: '0.3rem 0.7rem', borderRadius: '20px',
                                        background: 'rgba(59, 130, 246, 0.1)',
                                        color: '#3b82f6',
                                        flexShrink: 0
                                    }}>
                                        <Info size={14} />
                                        ENTORNO
                                    </div>
                                ) : (
                                    <div style={{
                                        display: 'flex', alignItems: 'center', gap: '0.4rem',
                                        fontSize: '0.75rem', fontWeight: 700,
                                        padding: '0.3rem 0.7rem', borderRadius: '20px',
                                        background: item.ppeComplete ? 'rgba(16,185,129,0.1)' : 'rgba(239,68,68,0.1)',
                                        color: item.ppeComplete ? '#10b981' : '#ef4444',
                                        flexShrink: 0
                                    }}>
                                        {item.ppeComplete ? <ShieldCheck size={14} /> : <TriangleAlert size={14} />}
                                        {item.ppeComplete ? 'EPP OK' : 'Falta EPP'}
                                    </div>
                                )}
                            </div>

                            <div style={{ display: 'flex', gap: '0.8rem', marginTop: '1rem', borderTop: '1px solid var(--color-border)', paddingTop: '1rem', flexWrap: 'wrap' }}>
                                <button
                                    onClick={() => {
                                        const fullReportKey = `ai_report_full_${item.id}`;
                                        const savedFull = localStorage.getItem(fullReportKey);
                                        const reportToLoad = savedFull ? JSON.parse(savedFull) : item;
                                        localStorage.setItem('current_ai_inspection', JSON.stringify(reportToLoad));
                                        navigate('/ai-report');
                                    }}
                                    className="btn-primary"
                                    style={{ flex: 2, padding: '0.6rem', fontSize: '0.85rem', display: 'flex', alignItems: 'center', gap: '0.4rem', justifyContent: 'center' }}
                                >
                                    <FileText size={16} /> Ver Reporte
                                </button>
                                <button
                                    onClick={() => navigate('/ai-camera')}
                                    className="btn-secondary"
                                    style={{ flex: 1, padding: '0.6rem', fontSize: '0.85rem', display: 'flex', alignItems: 'center', gap: '0.4rem', justifyContent: 'center' }}
                                >
                                    <Camera size={16} /> Re-inspección
                                </button>
                                <button
                                    onClick={() => {
                                        const url = `${window.location.origin}/v/${currentUser?.uid}/camera/${item.id}?print=true`;
                                        setQrTarget({ text: url, title: `Inspección — ${item.company || 'IA'}` });
                                    }}
                                    style={{ padding: '0.6rem', background: 'rgba(139,92,246,0.06)', border: '1px solid rgba(139,92,246,0.18)', borderRadius: '8px', color: '#8b5cf6', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
                                    title="Generar QR"
                                >
                                    <QrCode size={16} />
                                </button>
                                <button
                                    onClick={() => setShareItem(item)}
                                    style={{ padding: '0.6rem', background: '#dcfce7', border: '1px solid #86efac', borderRadius: '8px', color: '#16a34a', display: 'flex', alignItems: 'center', justifyContent: 'center', textDecoration: 'none', minWidth: '40px' }}
                                    title="Compartir"
                                >
                                    <Share2 size={16} /> <span className="hidden sm:inline" style={{ marginLeft: '0.3rem', fontWeight: 700, fontSize: '0.75rem' }}>Compartir</span>
                                </button>
                                <button
                                    onClick={() => setDeleteTarget(item.id)}
                                    style={{ padding: '0.6rem', background: 'rgba(239,68,68,0.05)', border: '1px solid rgba(239,68,68,0.2)', borderRadius: '8px', color: '#ef4444', cursor: 'pointer' }}
                                >
                                    <Trash2 size={18} />
                                </button>
                            </div>
                        </div>
                    ))
                ) : (
                    <div style={{ textAlign: 'center', padding: '3rem', color: 'var(--color-text-muted)' }}>
                        <Camera size={48} style={{ opacity: 0.2, marginBottom: '1rem' }} />
                        <p>No hay inspecciones guardadas.</p>
                        <button onClick={() => navigate('/ai-camera')} className="btn-primary" style={{ marginTop: '1rem' }}>
                            Realizar Primera Inspección
                        </button>
                    </div>
                )}
            </div>
            {qrTarget && (
                <QRModal
                    text={qrTarget.text}
                    title={qrTarget.title}
                    onClose={() => setQrTarget(null)}
                />
            )}
        </div>
    );
}

import React, { useState, useRef, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { ArrowLeft, Camera, RefreshCw, CheckCircle, TriangleAlert, ShieldCheck, Zap, ZapOff, FlipHorizontal, Search } from 'lucide-react';
import { API_BASE_URL } from '../config';
import { usePaywall } from '../hooks/usePaywall';
import { useSync } from '../contexts/SyncContext';
import toast from 'react-hot-toast';
import { useDocumentTitle } from '../hooks/useDocumentTitle';

export default function AIGeneralCamera() {
    const navigate = useNavigate();
    const { requirePro } = usePaywall();
    const { syncCollection } = useSync();
    useDocumentTitle('Detección de Riesgos IA');
    const videoRef = useRef(null);
    const canvasRef = useRef(null);
    const [stream, _setStream] = useState(null);
    const streamRef = useRef(null);
    const [capturedImage, setCapturedImage] = useState(null);
    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const [analysisResult, setAnalysisResult] = useState(null);
    const [torchOn, setTorchOn] = useState(false);
    const [facingMode, setFacingMode] = useState('environment'); // 'environment' or 'user'

    const setStream = (newStream) => {
        streamRef.current = newStream;
        _setStream(newStream);
    };

    useEffect(() => {
        startCamera();
        return () => {
            stopStream();
        };
    }, [facingMode]);

    const stopStream = () => {
        if (streamRef.current) {
            streamRef.current.getTracks().forEach(track => {
                track.stop();
            });
            streamRef.current = null;
        }
        _setStream(null);
    };

    const startCamera = async () => {
        stopStream();
        try {
            const constraints = {
                video: {
                    facingMode: facingMode,
                    width: { ideal: 800 },
                    height: { ideal: 600 }
                }
            };
            const newStream = await navigator.mediaDevices.getUserMedia(constraints);
            setStream(newStream);
            if (videoRef.current) videoRef.current.srcObject = newStream;
            setTorchOn(false);
        } catch (err) {
            console.error("Error accessing camera:", err);
            toast.error("No se pudo acceder a la cámara. Por favor, asegúrese de dar los permisos necesarios.");
        }
    };

    const toggleTorch = async () => {
        if (!streamRef.current) return;
        const track = streamRef.current.getVideoTracks()[0];
        try {
            const capabilities = track.getCapabilities();
            if (!capabilities.torch) {
                toast.error("Este dispositivo no soporta linterna o no está disponible en esta cámara.");
                return;
            }
            const newTorchState = !torchOn;
            await track.applyConstraints({
                advanced: [{ torch: newTorchState }]
            });
            setTorchOn(newTorchState);
        } catch (err) {
            console.error("Torch error:", err);
            toast.error("Error al controlar la linterna.");
        }
    };

    const switchCamera = () => {
        setFacingMode(prev => prev === 'environment' ? 'user' : 'environment');
    };

    const handleCapture = () => {
        if (!videoRef.current || !canvasRef.current) return;

        const video = videoRef.current;
        const canvas = canvasRef.current;

        const maxWidth = 800;
        const scale = video.videoWidth > maxWidth ? maxWidth / video.videoWidth : 1;
        canvas.width = video.videoWidth * scale;
        canvas.height = video.videoHeight * scale;

        const ctx = canvas.getContext('2d');
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

        const imageData = canvas.toDataURL('image/jpeg', 0.6);
        setCapturedImage(imageData);

        stopStream();
        analyzeImage(imageData);
    };

    const analyzeImage = async (imageSrc) => {
        setIsAnalyzing(true);
        try {
            const fetchUrl = `${API_BASE_URL}/api/analyze-general-risks`;
            const response = await fetch(fetchUrl, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ image: imageSrc })
            });

            if (!response.ok) {
                const errorData = await response.json().catch(() => ({}));
                throw new Error(errorData.error || `Error ${response.status}`);
            }

            const data = await response.json();

            if (data.detections && data.detections.length > 0) {
                const markedImage = await drawDetections(imageSrc, data.detections);
                setCapturedImage(markedImage);
            } else {
                toast.info("No se detectaron riesgos evidentes en esta escena.");
            }

            setAnalysisResult(data);
        } catch (error) {
            console.error("Error en análisis de riesgos:", error);
            toast.error(`Error de IA: ${error.message}`);
            handleRetry();
        } finally {
            setIsAnalyzing(false);
        }
    };

    const drawDetections = (imageSrc, detections) => {
        return new Promise((resolve) => {
            const img = new Image();
            img.onload = () => {
                const canvas = canvasRef.current;
                canvas.width = img.width;
                canvas.height = img.height;
                const ctx = canvas.getContext('2d');
                ctx.drawImage(img, 0, 0);

                detections.forEach((det, index) => {
                    ctx.strokeStyle = '#ef4444';
                    ctx.lineWidth = 4;

                    if (det.box_2d) {
                        const [ymin, xmin, ymax, xmax] = det.box_2d;
                        const bx = (xmin / 1000) * canvas.width;
                        const by = (ymin / 1000) * canvas.height;
                        const bw = ((xmax - xmin) / 1000) * canvas.width;
                        const bh = ((ymax - ymin) / 1000) * canvas.height;

                        // Circle around the detection
                        const centerX = bx + bw / 2;
                        const centerY = by + bh / 2;
                        const radius = Math.max(bw, bh) / 1.5;

                        ctx.beginPath();
                        ctx.arc(centerX, centerY, radius, 0, 2 * Math.PI);
                        ctx.stroke();

                        // Label badge
                        ctx.fillStyle = '#ef4444';
                        ctx.beginPath();
                        ctx.arc(centerX + radius, centerY - radius, 15, 0, 2 * Math.PI);
                        ctx.fill();

                        ctx.fillStyle = 'var(--color-surface)';
                        ctx.font = 'bold 20px Inter, sans-serif';
                        ctx.textAlign = 'center';
                        ctx.textBaseline = 'middle';
                        ctx.fillText(index + 1, centerX + radius, centerY - radius);
                    }
                });

                resolve(canvas.toDataURL('image/jpeg', 0.8));
            };
            img.src = imageSrc;
        });
    };

    const handleRetry = () => {
        setCapturedImage(null);
        setAnalysisResult(null);
        startCamera();
    };

    const handleSaveReport = () => {
        requirePro(() => {
            const currentReport = JSON.parse(localStorage.getItem('current_report') || '{}');
            const company = currentReport.company || currentReport.empresa || 'Empresa Local';
            const location = currentReport.location || currentReport.ubicacion || 'Inspección in situ';

            const report = {
                id: Date.now(),
                image: capturedImage,
                analysis: analysisResult,
                date: new Date().toISOString(),
                type: 'general_risks',
                company,
                location,
                findingsCount: analysisResult?.detections?.length || 0
            };

            // Save FULL report to a unique key for history detail views
            localStorage.setItem(`ai_report_full_${report.id}`, JSON.stringify(report));

            // Save FULL report for immediate detail view
            localStorage.setItem('current_ai_inspection', JSON.stringify(report));

            // Save ONLY lightweight summary to history (no image, no full analysis)
            const history = JSON.parse(localStorage.getItem('ai_camera_history') || '[]');
            if (!history.find(h => h.id === report.id)) {
                history.unshift({
                    id: report.id,
                    date: report.date,
                    type: report.type,
                    company: report.company,
                    location: report.location,
                    findingsCount: report.findingsCount
                });
                localStorage.setItem('ai_camera_history', JSON.stringify(history));
                syncCollection('ai_camera_history', history);
            }

            navigate('/ai-report');
        });
    };


    return (
        <div className="container" style={{ paddingBottom: '3rem', position: 'relative', minHeight: '100vh', display: 'flex', flexDirection: 'column' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '1.5rem', zIndex: 10 }}>
                <button onClick={() => navigate('/#tools')} style={{ padding: '0.5rem', background: 'rgba(255,255,255,0.1)', border: 'none', cursor: 'pointer', borderRadius: '50%', color: 'var(--color-primary)' }}>
                    <ArrowLeft />
                </button>
                <h1 style={{ margin: 0, fontSize: '1.5rem' }}>Detector de Riesgos IA</h1>
            </div>

            <div style={{ flex: 1, position: 'relative', borderRadius: '24px', overflow: 'hidden', background: 'var(--color-text)', border: '4px solid var(--color-border)', boxShadow: '0 20px 50px rgba(0,0,0,0.3)' }}>
                {!capturedImage ? (
                    <>
                        <video
                            ref={videoRef}
                            autoPlay
                            playsInline
                            style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', objectFit: 'cover' }}
                        />

                        <div style={{ position: 'absolute', top: '1rem', right: '1rem', display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                            <button onClick={toggleTorch} style={{ width: '44px', height: '44px', borderRadius: '50%', background: torchOn ? 'var(--color-primary)' : 'rgba(0,0,0,0.5)', border: 'none', color: 'var(--color-surface)', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' }}>
                                {torchOn ? <Zap size={20} /> : <ZapOff size={20} />}
                            </button>
                            <button onClick={switchCamera} style={{ width: '44px', height: '44px', borderRadius: '50%', background: 'rgba(0,0,0,0.5)', border: 'none', color: 'var(--color-surface)', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' }}>
                                <FlipHorizontal size={20} />
                            </button>
                        </div>

                        <div style={{ position: 'absolute', bottom: '2rem', left: '0', width: '100%', display: 'flex', justifyContent: 'center' }}>
                            <button
                                onClick={handleCapture}
                                style={{ width: '80px', height: '80px', borderRadius: '50%', border: '6px solid #fff', background: 'rgba(236, 72, 153, 0.8)', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--color-surface)', boxShadow: '0 0 20px rgba(236, 72, 153, 0.5)' }}
                            >
                                <Search size={32} />
                            </button>
                        </div>
                    </>
                ) : (
                    <div style={{ position: 'relative', width: '100%', height: '100%' }}>
                        <img src={capturedImage} alt="Captured" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />

                        {isAnalyzing && (
                            <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', background: 'rgba(0,0,0,0.7)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', color: 'var(--color-surface)' }}>
                                <RefreshCw size={48} className="animate-spin" style={{ marginBottom: '1rem', color: 'var(--color-primary)' }} />
                                <p style={{ fontWeight: 700, fontSize: '1.2rem' }}>Analizando Entorno...</p>
                            </div>
                        )}

                        {analysisResult && (
                            <div style={{ position: 'absolute', bottom: 0, left: 0, width: '100%', padding: '1.5rem', boxSizing: 'border-box', background: 'linear-gradient(transparent, rgba(0,0,0,0.95))', color: 'var(--color-surface)' }}>
                                <div style={{ marginBottom: '1rem' }}>
                                    <h3 style={{ margin: 0, fontSize: '1.1rem', fontWeight: 800 }}>Hallazgos de IA:</h3>
                                    <p style={{ margin: '0.2rem 0 0', fontSize: '0.85rem', color: 'rgba(255,255,255,0.7)' }}>
                                        {analysisResult.detections?.length > 0
                                            ? `Se detectaron ${analysisResult.detections.length} riesgos potenciales.`
                                            : "No se identificaron riesgos críticos."}
                                    </p>
                                </div>
                                <div style={{ display: 'flex', gap: '0.6rem', width: '100%', justifyContent: 'center', flexWrap: 'wrap' }}>
                                    <button onClick={handleRetry} className="btn-outline" style={{ flex: 1, minWidth: '130px', borderColor: 'var(--color-surface)', color: 'var(--color-surface)', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.4rem', height: '46px', margin: 0, padding: '0 0.5rem', fontSize: '0.85rem' }}>
                                        <RefreshCw size={16} /> Reintentar
                                    </button>
                                    <button onClick={handleSaveReport} className="btn-primary" style={{ flex: 1, minWidth: '130px', height: '46px', margin: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '0 0.5rem', fontSize: '0.85rem' }}>Ver Detalles</button>
                                </div>
                            </div>
                        )}
                    </div>
                )}
            </div>
            <canvas ref={canvasRef} style={{ display: 'none' }} />
        </div>
    );
}

