import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import {
    ArrowLeft, Search, Calendar, ChevronRight,
    Trash2, Sparkles, Download, FileText, HardHat,
    ShieldAlert, Lightbulb, Gavel, Share2
} from 'lucide-react';
import { useSync } from '../contexts/SyncContext';
import ShareModal from '../components/ShareModal';
import AiAdvisorPdfGenerator from '../components/AiAdvisorPdfGenerator';
import toast from 'react-hot-toast';

export default function AIHistory() {
    const navigate = useNavigate();
    const { syncCollection, syncPulse } = useSync();
    const [history, setHistory] = useState([]);
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedItem, setSelectedItem] = useState(null);

    useEffect(() => {
        try {
            const raw = localStorage.getItem('ai_advisor_history');
            if (raw) {
                const parsed = JSON.parse(raw);
                if (Array.isArray(parsed)) {
                    setHistory(parsed.filter(item => item && item.id && item.task));
                } else {
                    setHistory([]);
                }
            } else {
                setHistory([]);
            }
        } catch (e) {
            console.error("Error parsing AI history:", e);
            setHistory([]);
        }
    }, [syncPulse]);

    const handleDelete = (id, e) => {
        e.stopPropagation();
        const toastId = toast(
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.8rem' }}>
                <span style={{ fontSize: '0.9rem' }}>¿Eliminar este registro?</span>
                <button
                    onClick={() => {
                        const updated = history.filter(item => item.id !== id);
                        setHistory(updated);
                        localStorage.setItem('ai_advisor_history', JSON.stringify(updated));
                        syncCollection('ai_advisor_history', updated);
                        if (selectedItem?.id === id) setSelectedItem(null);
                        toast.dismiss(toastId);
                        toast.success('Registro eliminado');
                    }}
                    style={{ background: '#ef4444', color: '#ffffff', border: 'none', borderRadius: '8px', padding: '0.3rem 0.7rem', cursor: 'pointer', fontWeight: 800, fontSize: '0.8rem' }}
                >Eliminar</button>
            </div>,
            { duration: 5000, icon: '🗑️' }
        );
    };

    const [shareItem, setShareItem] = useState(null);

    const filteredHistory = history.filter(item =>
        item.task.toLowerCase().includes(searchTerm.toLowerCase())
    );

    if (selectedItem) {
        return (
            <div className="container" style={{ paddingBottom: '3rem' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '2rem' }}>
                    <button onClick={() => setSelectedItem(null)} style={{ background: 'none', border: 'none', padding: 0, color: 'var(--color-text)', cursor: 'pointer' }}>
                        <ArrowLeft size={24} />
                    </button>
                    <h1 style={{ margin: 0, fontSize: '1.25rem', fontWeight: 800 }}>Detalle del Análisis IA</h1>
                </div>

                <div className="card" style={{ padding: '1.5rem', marginBottom: '1.5rem', background: 'var(--color-surface)' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '1rem', flexWrap: 'wrap', gap: '1rem' }}>
                        <div style={{ flex: 1, minWidth: 0 }}>
                            <span style={{ fontSize: '0.8rem', color: 'var(--color-text-muted)', display: 'block', marginBottom: '0.3rem' }}>
                                {new Date(selectedItem.date).toLocaleString()}
                            </span>
                            <h3 style={{ margin: 0, fontSize: '1.2rem', fontWeight: 800 }}>{selectedItem.task}</h3>
                        </div>
                        <button
                            onClick={() => setShareItem(selectedItem)}
                            className="btn-primary"
                            style={{ padding: '0.5rem 1rem', display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.85rem' }}
                        >
                            <Share2 size={16} /> Compartir Reporte
                        </button>
                    </div>

                    <ShareModal
                        open={!!shareItem}
                        onClose={() => setShareItem(null)}
                        title={`Análisis IA - ${shareItem?.task || ''}`}
                        text={shareItem ? `✨ Análisis de Seguridad (IA)\n📋 Tarea: ${shareItem.task}\n🚨 Riesgos: ${(shareItem.riesgos || []).slice(0, 2).join(', ')}...\n🛡️ EPP: ${(shareItem.epp || []).slice(0, 2).join(', ')}...\n📚 Normativa: ${(shareItem.normativa || []).join(', ')}` : ''}
                        elementIdToPrint="pdf-content"
                    />

                    <div style={{ position: 'absolute', left: '-9999px', top: '-9999px', pointerEvents: 'none' }}>
                        {shareItem && <AiAdvisorPdfGenerator data={shareItem} />}
                    </div>

                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '1.2rem', marginTop: '1.5rem' }}>
                        <div style={{ padding: '1rem', borderRadius: '12px', border: '1px solid var(--color-border)', borderLeft: '4px solid #ef4444' }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', color: '#ef4444', marginBottom: '0.8rem' }}>
                                <ShieldAlert size={18} /> <h4 style={{ margin: 0 }}>Riesgos</h4>
                            </div>
                            <ul style={{ fontSize: '0.85rem', paddingLeft: '1.2rem', margin: 0 }}>
                                {(selectedItem.riesgos || []).map((it, i) => <li key={i}>{it}</li>)}
                                {(!selectedItem.riesgos || selectedItem.riesgos.length === 0) && <li>No hay riesgos detectados</li>}
                            </ul>
                        </div>
                        <div style={{ padding: '1rem', borderRadius: '12px', border: '1px solid var(--color-border)', borderLeft: '4px solid #3b82f6' }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', color: '#3b82f6', marginBottom: '0.8rem' }}>
                                <HardHat size={18} /> <h4 style={{ margin: 0 }}>EPP</h4>
                            </div>
                            <ul style={{ fontSize: '0.85rem', paddingLeft: '1.2rem', margin: 0 }}>
                                {(selectedItem.epp || []).map((it, i) => <li key={i}>{it}</li>)}
                                {(!selectedItem.epp || selectedItem.epp.length === 0) && <li>No hay EPP recomendados</li>}
                            </ul>
                        </div>
                        <div style={{ padding: '1rem', borderRadius: '12px', border: '1px solid var(--color-border)', borderLeft: '4px solid #10b981' }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', color: '#10b981', marginBottom: '0.8rem' }}>
                                <Lightbulb size={18} /> <h4 style={{ margin: 0 }}>Medidas</h4>
                            </div>
                            <ul style={{ fontSize: '0.85rem', paddingLeft: '1.2rem', margin: 0 }}>
                                {(selectedItem.recomendaciones || []).map((it, i) => <li key={i}>{it}</li>)}
                                {(!selectedItem.recomendaciones || selectedItem.recomendaciones.length === 0) && <li>No hay medidas preventivas</li>}
                            </ul>
                        </div>
                        <div style={{ padding: '1rem', borderRadius: '12px', border: '1px solid var(--color-border)', borderLeft: '4px solid #8b5cf6' }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', color: '#8b5cf6', marginBottom: '0.8rem' }}>
                                <Gavel size={18} /> <h4 style={{ margin: 0 }}>Normativa</h4>
                            </div>
                            <ul style={{ fontSize: '0.85rem', paddingLeft: '1.2rem', margin: 0, listStyle: 'none' }}>
                                {(selectedItem.normativa || []).map((it, i) => <li key={i}>• {it}</li>)}
                                {(!selectedItem.normativa || selectedItem.normativa.length === 0) && <li>No hay normativa registrada</li>}
                            </ul>
                        </div>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="container" style={{ paddingBottom: '3rem' }}>
            <ShareModal
                open={!!shareItem}
                onClose={() => setShareItem(null)}
                title={`Análisis IA - ${shareItem?.task || ''}`}
                text={shareItem ? `✨ Análisis de Seguridad (IA)\n📋 Tarea: ${shareItem.task}\n🚨 Riesgos: ${(shareItem.riesgos || []).slice(0, 2).join(', ')}...\n🛡️ EPP: ${(shareItem.epp || []).slice(0, 2).join(', ')}...\n📚 Normativa: ${(shareItem.normativa || []).join(', ')}` : ''}
                elementIdToPrint="pdf-content"
            />

            <div style={{ position: 'absolute', left: '-9999px', top: '-9999px', pointerEvents: 'none' }}>
                {shareItem && <AiAdvisorPdfGenerator data={shareItem} />}
            </div>

            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: '1rem', marginBottom: '2rem', flexWrap: 'wrap' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.8rem', minWidth: '200px' }}>
                    <button onClick={() => navigate('/#activity')} style={{ background: 'none', border: 'none', padding: 0, color: 'var(--color-text)', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                        <ArrowLeft size={24} />
                    </button>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.8rem' }}>
                        <Sparkles size={24} color="var(--color-primary)" />
                        <div>
                            <h1 style={{ margin: 0, fontSize: 'clamp(1.1rem, 4vw, 1.4rem)', fontWeight: 800, lineHeight: 1.2 }}>Consultas IA</h1>
                            <p style={{ margin: 0, fontSize: '0.75rem', color: 'var(--color-text-muted)', fontWeight: 600 }}>Asesoría técnica</p>
                        </div>
                    </div>
                </div>
                <button
                    onClick={() => navigate('/ai-advisor')}
                    className="btn-primary"
                    style={{ padding: '0.6rem 1rem', display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.85rem', width: 'auto', margin: 0 }}
                >
                    <Sparkles size={18} /> <span className="hidden sm:inline">NUEVA CONSULTA</span>
                </button>
            </div>

            <div style={{ position: 'relative', marginBottom: '1.5rem' }}>
                <Search size={18} style={{ position: 'absolute', left: '1rem', top: '50%', transform: 'translateY(-50%)', color: 'var(--color-text-muted)' }} />
                <input
                    type="text"
                    placeholder="Buscar por tarea..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    style={{ paddingLeft: '2.8rem' }}
                />
            </div>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                {filteredHistory.length > 0 ? (
                    filteredHistory.map(item => (
                        <div
                            key={item.id}
                            className="card"
                            onClick={() => setSelectedItem(item)}
                            style={{ display: 'flex', alignItems: 'center', gap: '1rem', cursor: 'pointer', transition: 'transform 0.2s' }}
                        >
                            <div style={{ background: 'rgba(37, 99, 235, 0.1)', padding: '0.8rem', borderRadius: '12px', color: 'var(--color-primary)' }}>
                                <Sparkles size={24} />
                            </div>
                            <div style={{ flex: 1, minWidth: 0 }}>
                                <h4 style={{ margin: '0 0 0.3rem 0', fontWeight: 700, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{item.task}</h4>
                                <div style={{ display: 'flex', gap: '1rem', fontSize: '0.8rem', color: 'var(--color-text-muted)' }}>
                                    <span style={{ display: 'flex', alignItems: 'center', gap: '0.3rem' }}>
                                        <Calendar size={14} /> {new Date(item.date).toLocaleDateString()}
                                    </span>
                                </div>
                            </div>
                            <div style={{ display: 'flex', gap: '0.5rem', flexShrink: 0, flexWrap: 'wrap', justifyContent: 'flex-end' }}>
                                <button
                                    onClick={(e) => { e.stopPropagation(); setShareItem(item); }}
                                    style={{ background: '#dcfce7', border: '1px solid #86efac', borderRadius: '10px', color: '#16a34a', cursor: 'pointer', padding: '0.5rem 0.8rem', display: 'flex', alignItems: 'center', justifyContent: 'center', textDecoration: 'none', minWidth: '40px' }}
                                    title="Compartir"
                                >
                                    <Share2 size={18} /> <span className="hidden sm:inline" style={{ marginLeft: '0.3rem', fontWeight: 700, fontSize: '0.75rem' }}>Compartir</span>
                                </button>
                                <button
                                    onClick={(e) => handleDelete(item.id, e)}
                                    style={{ background: 'transparent', border: 'none', color: '#ef4444', cursor: 'pointer', padding: '0.5rem' }}
                                    title="Eliminar"
                                >
                                    <Trash2 size={20} />
                                </button>
                                <ChevronRight size={20} color="var(--color-text-muted)" style={{ alignSelf: 'center' }} />
                            </div>
                        </div>
                    ))
                ) : (
                    <div style={{ textAlign: 'center', padding: '3rem', color: 'var(--color-text-muted)' }}>
                        <Sparkles size={48} style={{ opacity: 0.1, marginBottom: '1rem' }} />
                        <p style={{ marginBottom: '1.5rem' }}>{searchTerm ? 'No se encontraron resultados' : 'Aún no tienes consultas guardadas'}</p>
                        <button onClick={() => navigate('/ai-advisor')} className="btn-primary" style={{ margin: '0 auto' }}>Hacer una consulta ahora</button>
                    </div>
                )}
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { ArrowLeft, Printer, Share2, Download, CheckCircle2, TriangleAlert, ShieldCheck, Info } from 'lucide-react';
import { useAuth } from '../contexts/AuthContext';
import ShareModal from '../components/ShareModal';
import { usePaywall } from '../hooks/usePaywall';
import CompanyLogo from '../components/CompanyLogo';
import { toast } from 'react-hot-toast';

export default function AIReport() {
    const navigate = useNavigate();
    const { currentUser } = useAuth();
    const { requirePro } = usePaywall();
    const [data, setData] = useState(null);
    const [profile, setProfile] = useState(null);
    const [signature, setSignature] = useState(null);
    const [company, setCompany] = useState('');
    const [location, setLocation] = useState('');
    const [showShare, setShowShare] = useState(false);
    const [showSignatures, setShowSignatures] = useState({
        operator: true,
        supervisor: true,
        professional: true
    });

    useEffect(() => {
        const current = localStorage.getItem('current_ai_inspection');
        const prof = localStorage.getItem('personalData');
        const sig = localStorage.getItem('signatureStampData');

        if (current) {
            const parsedData = JSON.parse(current);
            setData(parsedData);
            setCompany(parsedData.company || 'Empresa Local');
            setLocation(parsedData.location || 'Planta Principal');
        }
        if (prof) setProfile(JSON.parse(prof));
        if (sig) setSignature(JSON.parse(sig));
    }, []);

    if (!data) return <div className="container">Cargando...</div>;

    const handlePrint = () => requirePro(() => window.print());

    return (
        <div className="container" style={{ maxWidth: '1000px' }}>
            <ShareModal
                open={showShare}
                onClose={() => setShowShare(false)}
                title={`Informe IA – ${company}`}
                text={`🤖 INFORME DE INSPECCIÓN IA\n\n🏗️ Empresa: ${company}\n📍 Ubicación: ${location}\n📅 Fecha: ${data ? new Date(data.date).toLocaleString() : ''}\n⚠️ Estado: ${data?.analysis?.ppeComplete ? '✅ EPP Completo' : '⚠️ Falta EPP / Peligro'}\n\nGenerado con Asistente HYS`}
                elementIdToPrint="pdf-content"
            />
            <div className="no-print" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                <button onClick={() => navigate('/ai-camera')} style={{ background: 'transparent', border: 'none', display: 'flex', alignItems: 'center', gap: '0.5rem', cursor: 'pointer', color: 'var(--color-text)' }}>
                    <ArrowLeft size={20} /> Volver a Cámara
                </button>
            </div>

            <div id="pdf-content" className="card report-print print:p-0 print:m-0 print:border-none print:shadow-none print:min-h-0" style={{
                padding: '3rem',
                minHeight: '29.7cm',
                height: 'auto',
                background: '#ffffff',
                color: '#1e293b',
                boxShadow: '0 10px 25px -5px rgba(0,0,0,0.1)',
                position: 'relative'
            }}>
                {/* Header */}
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 2fr 1fr', alignItems: 'center', borderBottom: '4px solid var(--color-primary)', paddingBottom: '1.5rem', marginBottom: '2rem', width: '100%', gap: '1.5rem' }}>
                    <div style={{ textAlign: 'left' }}>
                        <p style={{ margin: 0, fontWeight: 700, fontSize: '0.65rem', textTransform: 'uppercase', color: '#64748b', letterSpacing: '0.05em' }}>Sistema de Gestión</p>
                        <p style={{ margin: 0, fontWeight: 900, fontSize: '0.75rem', textTransform: 'uppercase', color: '#1e293b' }}>Control H&S</p>
                    </div>

                    <div style={{ textAlign: 'center' }}>
                        <h2 style={{ margin: 0, fontSize: '1.2rem', fontWeight: 900, color: 'var(--color-primary)', textTransform: 'uppercase', letterSpacing: '1px', lineHeight: 1.2 }}>
                            Informe de Inspección IA
                        </h2>
                        <p style={{ margin: '4px 0 0 0', fontSize: '0.65rem', color: '#64748b', fontWeight: 600 }}>Detección de Riesgos y EPP</p>
                    </div>

                    <div style={{ display: 'flex', justifyContent: 'flex-end' }}>
                        <CompanyLogo style={{ height: '45px', width: 'auto', maxWidth: '140px', objectFit: 'contain' }} />
                    </div>
                </div>

                {profile && (
                    <div className="no-print" style={{ marginBottom: '1.5rem', textAlign: 'right', fontSize: '0.8rem', color: '#64748b' }}>
                        <p style={{ margin: 0, fontWeight: 700 }}>Profesional: {profile.name} | Mat: {profile.license}</p>
                    </div>
                )}

                {/* Info Block */}
                <div className="grid grid-cols-1 sm:grid-cols-3 print:grid-cols-3 gap-4 mb-10 bg-slate-50 p-5 rounded-lg border border-slate-200">
                    <div>
                        <p style={{ margin: 0, fontSize: '0.7rem', color: '#64748b' }}>Tipo de Inspección</p>
                        <p style={{ margin: 0, fontWeight: 800, fontSize: '0.9rem', color: 'var(--color-primary)' }}>
                            {data.type === 'general_risks' ? 'DETECTAR RIESGOS GENERALES' : 'VERIFICAR EPP'}
                        </p>
                    </div>
                    <div>
                        <p style={{ margin: 0, fontSize: '0.7rem', color: '#64748b' }}>Empresa / Planta</p>
                        <input
                            type="text"
                            value={company}
                            onChange={(e) => setCompany(e.target.value)}
                            className="no-print"
                            style={{ margin: 0, padding: '0.2rem 0', fontWeight: 600, fontSize: '0.9rem', border: 'none', borderBottom: '1px solid #e2e8f0', background: 'transparent', width: '100%' }}
                        />
                        <p className="print-only" style={{ margin: 0, fontWeight: 600, fontSize: '0.9rem' }}>{company}</p>
                    </div>
                    <div>
                        <p style={{ margin: 0, fontSize: '0.7rem', color: '#64748b' }}>Fecha del Escaneo</p>
                        <p style={{ margin: 0, fontWeight: 600, fontSize: '0.9rem' }}>{new Date(data.date).toLocaleString()}</p>
                    </div>
                </div>

                {/* Evidence Photo */}
                <div style={{ marginBottom: '3rem', textAlign: 'center' }}>
                    <div style={{ position: 'relative', display: 'inline-block', border: '4px solid #fff', boxShadow: '0 5px 15px rgba(0,0,0,0.1)', borderRadius: '12px', overflow: 'hidden' }}>
                        <img src={data.image} alt="Evidencia" style={{ maxWidth: '100%', maxHeight: '450px', display: 'block' }} />
                        {/* Simplified Overlay for Report */}
                        {data.type === 'general_risks' ? (
                            <div style={{ position: 'absolute', top: '10px', right: '10px', background: 'rgba(59, 130, 246, 0.9)', color: '#fff', fontSize: '0.8rem', fontWeight: 800, padding: '4px 10px', borderRadius: '20px', border: '2px solid #fff' }}>ANÁLISIS ENTORNO</div>
                        ) : data.analysis?.ppeComplete ? (
                            <div style={{ position: 'absolute', top: '10px', right: '10px', background: 'rgba(16, 185, 129, 0.9)', color: '#fff', fontSize: '0.8rem', fontWeight: 800, padding: '4px 10px', borderRadius: '20px', border: '2px solid #fff' }}>✓ EPP O.K.</div>
                        ) : (
                            <div style={{ position: 'absolute', top: '10px', right: '10px', background: 'rgba(239, 68, 68, 0.9)', color: '#fff', fontSize: '0.8rem', fontWeight: 800, padding: '4px 10px', borderRadius: '20px', border: '2px solid #fff' }}>⚠️ FALTA EPP</div>
                        )}
                    </div>
                    <p style={{ marginTop: '0.8rem', fontSize: '0.8rem', color: '#64748b', fontStyle: 'italic' }}>Captura fotográfica del sistema de inspección ocular</p>
                </div>

                {/* Analysis Results */}
                <div style={{ marginBottom: '2.5rem' }}>
                    <h3 style={{ borderBottom: '1px solid #e2e8f0', paddingBottom: '0.5rem', marginBottom: '1rem', color: '#1e293b' }}>
                        {data.type === 'general_risks' ? 'Resumen de Riesgos Detectados' : 'Evaluación de EPP Detectada'}
                    </h3>

                    {data.type !== 'general_risks' ? (
                        <>
                            <div className="grid grid-cols-1 sm:grid-cols-2 print:grid-cols-2 gap-4">
                                {[
                                    { label: 'Casco de Seguridad', pass: data.analysis?.helmetUsed },
                                    { label: 'Calzado de Seguridad', pass: data.analysis?.shoesUsed },
                                    { label: 'Guantes de Trabajo', pass: data.analysis?.glovesUsed },
                                    { label: 'Ropa / Chaleco Reflectivo', pass: data.analysis?.clothingUsed },
                                ].map((item, i) => (
                                    <div key={i} style={{ padding: '0.8rem', borderRadius: '8px', background: item.pass ? '#f0fdf4' : '#fef2f2', border: `1px solid ${item.pass ? '#bbf7d0' : '#fecaca'}`, display: 'flex', alignItems: 'center', gap: '0.8rem', color: item.pass ? '#15803d' : '#b91c1c' }}>
                                        {item.pass ? <ShieldCheck size={20} /> : <TriangleAlert size={20} />}
                                        <span style={{ fontWeight: 700, fontSize: '0.9rem' }}>{item.label}: {item.pass ? 'CUMPLE' : 'FALTA'}</span>
                                    </div>
                                ))}
                            </div>

                            <div style={{ marginTop: '1rem', padding: '1rem', borderRadius: '8px', background: data.analysis?.ppeComplete ? '#f0fdf4' : '#fff7ed', border: `1px solid ${data.analysis?.ppeComplete ? '#bbf7d0' : '#ffedd5'}`, display: 'flex', alignItems: 'center', gap: '0.8rem', color: data.analysis?.ppeComplete ? '#15803d' : '#c2410c' }}>
                                {data.analysis?.ppeComplete ? <ShieldCheck /> : <TriangleAlert />}
                                <span style={{ fontWeight: 800 }}>ESTADO GENERAL: {data.analysis?.ppeComplete ? 'ADECUADO' : 'REQUIERE ATENCIÓN INMEDIATA'}</span>
                            </div>
                        </>
                    ) : (
                        <div style={{ padding: '1.2rem', borderRadius: '12px', background: '#f8fafc', border: '1px solid #e2e8f0', color: '#334155' }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.8rem', marginBottom: '0.8rem', color: 'var(--color-primary)' }}>
                                <Info size={20} />
                                <span style={{ fontWeight: 800, fontSize: '1rem' }}>EVALUACIÓN GENERAL IA</span>
                            </div>
                            <p style={{ margin: 0, fontSize: '0.95rem', lineHeight: '1.6' }}>{data.analysis?.generalAssessment || 'Análisis ambiental completado.'}</p>
                        </div>
                    )}
                </div>

                {/* Findings Legend (Numbered) */}
                {data.analysis?.detections && data.analysis.detections.length > 0 && (
                    <div style={{ marginBottom: '2.5rem' }}>
                        <h4 style={{ borderBottom: '1px solid #e2e8f0', paddingBottom: '0.5rem', marginBottom: '1rem', color: '#1e293b' }}>Leyenda de Hallazgos</h4>
                        <div className="grid grid-cols-1 sm:grid-cols-2 print:grid-cols-2 gap-3">
                            {data.analysis.detections.map((det, i) => {
                                const isRisk = det.label.toLowerCase().includes('riesgo');
                                return (
                                    <div key={i} style={{ display: 'flex', alignItems: 'center', gap: '0.8rem', fontSize: '0.9rem' }}>
                                        <div style={{
                                            width: '24px', height: '24px', borderRadius: '50%',
                                            background: isRisk ? '#ef4444' : '#3b82f6', color: '#fff',
                                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                                            fontWeight: 800, fontSize: '0.75rem', flexShrink: 0
                                        }}>
                                            {i + 1}
                                        </div>
                                        <span style={{ color: '#475569' }}>{det.label}</span>
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                )}

                {/* Additional Findings */}
                {(data.analysis?.foundRisks?.length > 0 || data.analysis?.detections?.some(d => d.recommendation)) && (
                    <div style={{ marginBottom: '3rem' }}>
                        <h4 style={{ color: '#b91c1c', marginBottom: '0.8rem' }}>Riesgos y Observaciones Detalladas:</h4>
                        <ul style={{ margin: 0, paddingLeft: '1.5rem', color: '#1e293b' }}>
                            {data.analysis?.foundRisks?.map((risk, i) => (
                                <li key={i} style={{ marginBottom: '0.4rem' }}>{risk}</li>
                            ))}
                            {data.analysis?.detections?.filter(d => d.recommendation).map((det, i) => (
                                <li key={`rec-${i}`} style={{ marginBottom: '0.4rem' }}>
                                    <strong>{det.label.replace('Riesgo: ', '')}:</strong> {det.recommendation}
                                </li>
                            ))}
                        </ul>
                    </div>
                )}

                <div className="no-print mt-10 p-4 bg-slate-50 border border-slate-200 rounded-xl w-full flex flex-col md:flex-row gap-4 md:gap-8 justify-center items-center text-xs font-bold text-slate-700">
                    <div className="text-center">INCLUIR FIRMAS EN EL DOCUMENTO:</div>
                    <div className="flex gap-4 flex-wrap justify-center">
                        <label className="flex items-center gap-2 cursor-pointer">
                            <input type="checkbox" checked={showSignatures.operator} onChange={e => setShowSignatures(s => ({ ...s, operator: e.target.checked }))} className="w-4 h-4 accent-red-600" /> Operador
                        </label>
                        <label className="flex items-center gap-2 cursor-pointer">
                            <input type="checkbox" checked={showSignatures.supervisor} onChange={e => setShowSignatures(s => ({ ...s, supervisor: e.target.checked }))} className="w-4 h-4 accent-red-600" /> Supervisor
                        </label>
                        <label className="flex items-center gap-2 cursor-pointer">
                            <input type="checkbox" checked={showSignatures.professional} onChange={e => setShowSignatures(s => ({ ...s, professional: e.target.checked }))} className="w-4 h-4 accent-red-600" /> Profesional
                        </label>
                    </div>
                </div>

                <div className="signature-container-row mt-10">
                    {showSignatures.operator && (
                        <div className="signature-item-box">
                            <div className="signature-line"></div>
                            <p className="text-[0.65rem] font-black uppercase text-slate-400 tracking-widest leading-none mb-1">TRABAJADOR / OPERADOR</p>
                            <p className="text-[0.8rem] font-black uppercase text-black leading-none min-h-[0.8rem]">Aclaración y Firma</p>
                        </div>
                    )}

                    {showSignatures.supervisor && (
                        <div className="signature-item-box">
                            <div className="signature-line"></div>
                            <p className="text-[0.65rem] font-black uppercase text-slate-400 tracking-widest leading-none mb-1">SUPERVISOR / TESTIGO</p>
                            <p className="text-[0.8rem] font-black uppercase text-black leading-none min-h-[0.8rem]">Aclaración y Firma</p>
                        </div>
                    )}

                    {showSignatures.professional && (
                        <div className="signature-item-box">
                            {signature?.signature || signature?.stamp ? (
                                <div style={{ display: 'flex', gap: '10px', alignItems: 'center', justifyContent: 'center', marginBottom: '0.5rem', height: '60px' }}>
                                    {signature.signature && <img src={signature.signature} alt="Firma" style={{ maxWidth: '100px', maxHeight: '60px' }} />}
                                    {signature.stamp && <img src={signature.stamp} alt="Sello" style={{ maxWidth: '60px', maxHeight: '60px' }} />}
                                </div>
                            ) : (
                                <div style={{ height: '60px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.7rem', color: '#999', marginBottom: '0.5rem' }}>Sin Firma</div>
                            )}
                            <div className="signature-line"></div>
                            <p className="text-[0.65rem] font-black uppercase text-slate-400 tracking-widest leading-none mb-1">PROFESIONAL ACTUANTE</p>
                            <p style={{ margin: 0, fontWeight: 700, fontSize: '0.8rem' }}>{profile?.name}</p>
                            <p style={{ margin: 0, fontSize: '0.65rem', color: 'var(--color-text-muted)' }}>Mat: {profile?.license}</p>
                        </div>
                    )}
                </div>

                {/* Footer Content (Static in report) */}
                <div style={{ position: 'relative', marginTop: '30px', paddingBottom: '30px', width: '100%', textAlign: 'center', fontSize: '0.7rem', color: '#94a3b8' }}>
                    Documento de verificación instantánea generado por Asistente HYS.
                </div>
            </div>

            {/* Floating Action Buttons */}
            <div className="no-print floating-action-bar">
                <button onClick={() => toast.success('Los reportes de IA se guardan automáticamente en tu Historial.')} className="btn-floating-action" style={{ background: '#36B37E', color: 'white' }}>
                    <CheckCircle2 size={18} /> GUARDADO
                </button>
                <button onClick={() => requirePro(() => setShowShare(true))} className="btn-floating-action" style={{ background: '#0052CC', color: 'white' }}>
                    <Share2 size={18} /> COMPARTIR
                </button>
                <button onClick={handlePrint} className="btn-floating-action" style={{ background: '#FF8B00', color: 'white' }}>
                    <Printer size={18} /> IMPRIMIR PDF
                </button>
            </div>

            <style>
                {`
                .spin { animation: spin 1.5s linear infinite; }
                @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
                
                @media print {
                    .report-print {
                        min-height: 0 !important;
                        padding: 0 !important;
                        margin: 0 !important;
                        box-shadow: none !important;
                        border: none !important;
                    }
                }
                `}
            </style>
        </div>
    );
}

