                                        className="no-print"
                                        onClick={() => addQuestion(cat)}
                                        style={{ padding: '0.5rem 1rem', background: 'var(--color-primary)', color: '#ffffff', border: 'none', borderRadius: '8px', fontWeight: 800, fontSize: '0.7rem', cursor: 'pointer' }}
                                    >
                                        + AGREGAR PUNTO
                                    </button>
                                </div>

                                <div className="w-full flex-col">
                                    {formData.checklist.filter(i => i.categoria === cat).map((item) => (
                                        <div key={item.id} className="group border-b border-slate-200" style={{ padding: '0.75rem 1rem' }}>
                                            {/* Question text */}
                                            <div
                                                contentEditable
                                                suppressContentEditableWarning
                                                onBlur={(e) => updateChecklist(item.id, 'pregunta', e.target.innerText)}
                                                className="font-bold text-slate-800 text-[0.9rem] outline-none border-b border-dashed border-transparent focus:border-[var(--color-primary)] leading-tight"
                                                style={{ marginBottom: '0.5rem' }}
                                            >
                                                {item.pregunta}
                                            </div>

                                            {/* Observaciones */}
                                            <textarea
                                                rows={1}
                                                placeholder="Observaciones / Medidas tomadas..."
                                                value={item.observaciones}
                                                className="no-print block overflow-hidden"
                                                onInput={(e) => {
                                                    e.target.style.height = 'auto';
                                                    e.target.style.height = e.target.scrollHeight + 'px';
                                                }}
                                                onChange={(e) => updateChecklist(item.id, 'observaciones', e.target.value)}
                                                style={{ margin: '0 0 0.6rem 0', padding: '0.4rem', fontSize: '0.7rem', background: 'transparent', border: '1px solid #efefef', borderRadius: '4px', width: '100%', boxSizing: 'border-box', color: 'var(--color-text-muted)', resize: 'none', minHeight: '30px' }}
                                            />
                                            <div className="print-only text-[0.7rem] text-slate-500 whitespace-pre-wrap break-words mb-1">
                                                {item.observaciones || ''}
                                            </div>

                                            {/* Bottom row: status buttons + delete */}
                                            <div className="no-print" style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: '0.5rem', flexWrap: 'nowrap' }}>
                                                <div className="checklist-status-buttons" style={{ justifyContent: 'flex-start', flexShrink: 0 }}>
                                                    <StatusBtn active={item.estado === 'Cumple'} type="OK" onClick={() => updateChecklist(item.id, 'estado', 'Cumple')} label="SI" />
                                                    <StatusBtn active={item.estado === 'No Cumple'} type="FAIL" onClick={() => updateChecklist(item.id, 'estado', 'No Cumple')} label="NO" />
                                                    <StatusBtn active={item.estado === 'N/A'} type="NA" onClick={() => updateChecklist(item.id, 'estado', 'N/A')} label="NA" />
                                                </div>
                                                <button
                                                    onClick={() => {
                                                        const toastId = toast(
                                                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.8rem' }}>
                                                                <span style={{ fontSize: '0.9rem' }}>¿Eliminar este punto?</span>
                                                                <button
                                                                    onClick={() => { removeQuestion(item.id); toast.dismiss(toastId); }}
                                                                    style={{ background: '#ef4444', color: '#ffffff', border: 'none', borderRadius: '8px', padding: '0.3rem 0.7rem', cursor: 'pointer', fontWeight: 800, fontSize: '0.8rem' }}
                                                                >Sí</button>
                                                            </div>,
                                                            { duration: 4000, icon: '🗑️' }
                                                        );
                                                    }}
                                                    style={{ flexShrink: 0, background: 'rgba(239,68,68,0.08)', border: '1px solid rgba(239,68,68,0.2)', borderRadius: '8px', cursor: 'pointer', color: '#ef4444', padding: '0.3rem 0.5rem', display: 'flex', alignItems: 'center' }}
                                                    title="Eliminar"
                                                >
                                                    <Trash2 size={15} />
                                                </button>
                                            </div>
                                            {/* Vista de Impresión Reforzada */}
                                            <div className="checklist-print-box hidden print:flex gap-1" style={{ flexShrink: 0 }}>
                                                {['SI', 'NO', 'NA'].map((label) => {
                                                    const isSelected = (label === 'SI' && (item.estado === 'Cumple' || item.estado === 'SI')) ||
                                                                     (label === 'NO' && (item.estado === 'No Cumple' || item.estado === 'NO')) ||
                                                                     (label === 'NA' && (item.estado === 'N/A' || item.estado === 'NA'));

                                                    return (
                                                        <div key={label} style={{
                                                            width: '35px',
                                                            height: '24px',
                                                            border: isSelected ? '2.5px solid #000' : '1px solid #94a3b8',
                                                            borderRadius: '4px',
                                                            display: 'flex',
                                                            alignItems: 'center',
                                                            justifyContent: 'center',
                                                            fontSize: '0.65rem',
                                                            fontWeight: isSelected ? 900 : 400,
                                                            color: isSelected ? '#000' : '#94a3b8',
                                                            background: 'transparent',
                                                            WebkitPrintColorAdjust: 'exact'
                                                        }}>
                                                            {isSelected ? 'X' : ''}
                                                            <span style={{ fontSize: '0.5rem', marginLeft: '2px', opacity: isSelected ? 1 : 0.6 }}>{label}</span>
                                                        </div>
                                                    );
                                                })}
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        ))}
                    </div>

                    <div className="card" style={{ marginTop: '2.5rem' }}>
                        <h3 style={{ marginTop: 0, marginBottom: '2rem', display: 'flex', alignItems: 'center', gap: '0.7rem', color: 'var(--color-primary)', fontWeight: 900, fontSize: '1.2rem', textTransform: 'uppercase', letterSpacing: '1px' }}>
                            <Pencil size={24} /> Firmas y Autorizaciones
                        </h3>

                        <div className="no-print mb-8 p-6 bg-slate-50/5 border border-[var(--color-border)] rounded-xl w-full flex flex-col md:flex-row gap-4 md:gap-8 justify-center items-center text-sm font-bold text-slate-700">
                            <div className="text-center">INCLUIR FIRMAS EN EL DOCUMENTO:</div>
                            <div className="flex gap-4 flex-wrap justify-center">
                                <label className="flex items-center gap-2 cursor-pointer">
                                    <input type="checkbox" checked={showSignatures.operator} onChange={e => setShowSignatures(s => ({ ...s, operator: e.target.checked }))} className="w-5 h-5 accent-blue-600" /> Operador
                                </label>
                                <label className="flex items-center gap-2 cursor-pointer">
                                    <input type="checkbox" checked={showSignatures.supervisor} onChange={e => setShowSignatures(s => ({ ...s, supervisor: e.target.checked }))} className="w-5 h-5 accent-blue-600" /> Supervisor
                                </label>
                                <label className="flex items-center gap-2 cursor-pointer">
                                    <input type="checkbox" checked={showSignatures.professional} onChange={e => setShowSignatures(s => ({ ...s, professional: e.target.checked }))} className="w-5 h-5 accent-blue-600" /> Profesional
                                </label>
                            </div>
                        </div>

                        <div className="signature-container-row">
                            {showSignatures.operator && (
                                <div className="signature-item-box">
                                    <div className="signature-line"></div>
                                    <p className="text-[0.6rem] font-black uppercase text-slate-400 tracking-widest leading-none mb-1">OPERADOR / CAPATAZ</p>
                                    <p className="text-[0.8rem] font-black uppercase text-black leading-none break-words min-h-[0.8rem]">{formData.capatazNombre || ' '}</p>
                                    <p className="text-[0.5rem] font-bold text-blue-600 uppercase tracking-tighter mt-1" style={{ color: 'var(--color-primary)' }}>Firma / Aclaración</p>
                                </div>
                            )}

                            {showSignatures.supervisor && (
                                <div className="signature-item-box">
                                    <div className="no-print flex flex-col items-center w-full mb-4">
                                        <label className="text-xs font-semibold mb-1 text-slate-400">Firma Digital (Supervisor)</label>
                                        <canvas
                                            ref={capatazCanvasRef}
                                            width={400}
                                            height={120}
                                            className="w-full h-[100px] border border-dashed border-slate-200 rounded-lg bg-white touch-none"
                                            onMouseDown={startDrawing}
                                            onMouseMove={draw}
                                            onMouseUp={() => setIsDrawingCapataz(false)}
                                            onMouseLeave={() => setIsDrawingCapataz(false)}
                                        />
                                        <button type="button" onClick={clearCapatazSignature} className="mt-1 text-[0.6rem] text-red-500 underline hover:text-red-700 bg-transparent border-none cursor-pointer">Limpiar</button>
                                    </div>
                                    <div className="signature-line"></div>
                                    <p className="text-[0.6rem] font-black uppercase text-slate-400 tracking-widest leading-none mb-1">SUPERVISOR / JEFE OBRA</p>
                                    <p className="text-[0.8rem] font-black uppercase text-black leading-none min-h-[0.8rem]">Firma del Supervisor</p>
                                    <p className="text-[0.5rem] font-bold text-blue-600 uppercase tracking-tighter mt-1" style={{ color: 'var(--color-primary)' }}>Validación / Sello</p>
                                </div>
                            )}

                            {showSignatures.professional && (
                                <div className="signature-item-box">
                                    <div className="flex flex-col items-center justify-center gap-2 mb-4 w-full h-[100px]">
                                        {professional.signature ? (
                                            <img src={professional.signature} alt="Firma Professional" className="max-h-16 max-w-full object-contain" />
                                        ) : (
                                            <div className="text-[0.6rem] text-slate-300 italic">Sin firma digital</div>
                                        )}
                                    </div>
                                    <div className="signature-line"></div>
                                    <p className="text-[0.6rem] font-black uppercase text-slate-400 tracking-widest leading-none mb-1">PROFESIONAL ACTUANTE</p>
                                    <p className="text-[0.8rem] font-black uppercase text-black leading-none break-words">{professional.name}</p>
                                    <p className="text-[0.5rem] font-bold text-blue-600 uppercase tracking-tighter mt-1" style={{ color: 'var(--color-primary)' }}>Matrícula: {professional.license}</p>
                                </div>
                            )}
                        </div>
                    </div>
                    <PdfBrandingFooter />
                </div>
            </div>
            {/* ─── Modal IA Mágica ─── */}
            {
                showAIModal && (
                    <div
                        onClick={() => setShowAIModal(false)}
                        style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.7)', zIndex: 9000, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '1.5rem', backdropFilter: 'blur(6px)' }}
                    >
                        <div
                            onClick={e => e.stopPropagation()}
                            style={{ width: '100%', maxWidth: '440px', background: 'var(--color-surface)', borderRadius: '24px', padding: '2rem', border: '1px solid rgba(168,85,247,0.3)', boxShadow: '0 20px 60px rgba(168,85,247,0.2)' }}
                        >
                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '0.5rem' }}>
                                <div style={{ background: 'linear-gradient(135deg,#a855f7,#ec4899)', borderRadius: '12px', padding: '0.6rem', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 4px 15px rgba(168,85,247,0.4)' }}>
                                    <Sparkles size={20} color="white" />
                                </div>
                                <div>
                                    <h2 style={{ margin: 0, fontSize: '1.3rem', fontWeight: 900, background: 'linear-gradient(135deg,#a855f7,#ec4899)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>IA Mágica</h2>
                                    <p style={{ margin: 0, fontSize: '0.75rem', color: 'var(--color-text-muted)', fontWeight: 600 }}>Generador automático de ATS</p>
                                </div>
                            </div>
                            <p style={{ color: 'var(--color-text-muted)', fontSize: '0.85rem', marginBottom: '1.5rem', lineHeight: 1.5 }}>
                                Ingresá el nombre de la tarea y la IA generará automáticamente los pasos, riesgos y medidas de control.
                            </p>
                            <label style={{ fontSize: '0.8rem', fontWeight: 700, color: 'var(--color-text)', marginBottom: '0.5rem', display: 'block' }}>
                                ¿Para qué tarea?
                            </label>
                            <input
                                autoFocus
                                type="text"
                                value={aiTaskInput}
                                onChange={e => setAiTaskInput(e.target.value)}
                                onKeyDown={e => { if (e.key === 'Enter' && aiTaskInput.trim()) runAIGeneration(); }}
                                placeholder="Ej: Soldadura en altura, Excavación manual..."
                                style={{ width: '100%', padding: '0.9rem 1rem', borderRadius: '12px', border: '2px solid rgba(168,85,247,0.3)', background: 'var(--color-background)', color: 'var(--color-text)', fontSize: '0.95rem', fontWeight: 600, outline: 'none', boxSizing: 'border-box', marginBottom: '1.5rem', transition: 'border-color 0.2s' }}
                                onFocus={e => e.target.style.borderColor = '#a855f7'}
                                onBlur={e => e.target.style.borderColor = 'rgba(168,85,247,0.3)'}
                            />
                            <div style={{ display: 'flex', gap: '0.75rem' }}>
                                <button
                                    onClick={() => setShowAIModal(false)}
                                    style={{ flex: 1, padding: '0.8rem', borderRadius: '12px', border: '1px solid var(--color-border)', background: 'transparent', color: 'var(--color-text-muted)', fontWeight: 700, cursor: 'pointer', fontSize: '0.9rem' }}
                                >
                                    Cancelar
                                </button>
                                <button
                                    onClick={runAIGeneration}
                                    disabled={!aiTaskInput.trim()}
                                    style={{ flex: 2, padding: '0.8rem', borderRadius: '12px', border: 'none', background: aiTaskInput.trim() ? 'linear-gradient(135deg,#a855f7,#ec4899)' : 'var(--color-border)', color: '#ffffff', fontWeight: 800, cursor: aiTaskInput.trim() ? 'pointer' : 'not-allowed', fontSize: '0.9rem', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem', boxShadow: aiTaskInput.trim() ? '0 4px 15px rgba(168,85,247,0.4)' : 'none', transition: 'all 0.2s' }}
                                >
                                    <Sparkles size={16} /> GENERAR ATS
                                </button>
                            </div>
                        </div>
                    </div>
                )}
        </>
    );
}

// Internal Sub-components
function StatusBtn({ active, type, onClick, label }) {
    const classes = `status - btn ${active ? (type === 'OK' ? 'active-ok' : type === 'FAIL' ? 'active-fail' : 'active-na') : ''
        } `;
    return (
        <button className={classes} onClick={onClick}>
            {active && <CheckCircle2 size={10} style={{ marginRight: '2px' }} />}
            {label}
        </button>
    );
}

function DocBox({ label, value, onChange, type = "text", large = false, borderLeft = false }) {
    return (
        <div style={{
            padding: '0.8rem 1rem',
            display: 'flex',
            flexDirection: 'column',
            gap: '0.3rem',
            justifyContent: 'center',
            borderLeft: borderLeft ? '2px solid var(--color-border)' : 'none',
            borderTop: '0',
            background: 'transparent',
            minHeight: '60px',
        }}>
            <span style={{
                fontSize: '0.6rem',
                fontWeight: 900,
                color: 'var(--color-primary)',
                textTransform: 'uppercase',
                letterSpacing: '0.12em',
                opacity: 0.8,
            }}>{label}</span>
            <input
                type={type}
                value={value}
                onChange={e => onChange(e.target.value)}
                style={{
                    margin: 0,
                    padding: '0.15rem 0',
                    border: 'none',
                    borderBottom: '1.5px solid var(--color-border)',
                    background: 'transparent',
                    fontSize: large ? '1.05rem' : '0.9rem',
                    fontWeight: 700,
                    color: 'var(--color-text)',
                    outline: 'none',
                    width: '100%',
                    transition: 'border-color 0.2s',
                }}
                onFocus={e => e.target.style.borderBottomColor = 'var(--color-primary)'}
                onBlur={e => e.target.style.borderBottomColor = 'var(--color-border)'}
            />
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import {
    ArrowLeft, Save, FileText, UserPlus, FileSpreadsheet,
    MapPin, Clock, Search, ListPlus, Trash2, CheckCircle2, ChevronRight, ChevronLeft,
    Plus, Share2, Printer, Sparkles, Loader2
} from 'lucide-react';
import { usePaywall } from '../hooks/usePaywall';
import ShareModal from '../components/ShareModal';
import AccidentPdfGenerator from '../components/AccidentPdfGenerator';
import { useAuth } from '../contexts/AuthContext';
import { useSync } from '../contexts/SyncContext';
import { useDocumentTitle } from '../hooks/useDocumentTitle';
import toast from 'react-hot-toast';

const SECTIONS = ['Datos Generales', 'Accidentado', 'Descripción y Testigos', 'Análisis Causal', 'Medidas Preventivas'];

export default function AccidentInvestigation() {
    useDocumentTitle('Investigación de Accidentes');
    const navigate = useNavigate();
    const location = useLocation();
    const { currentUser } = useAuth();
    const { syncCollection } = useSync();
    const { requirePro } = usePaywall();

    const editData = location.state?.editData;

    const [currentStep, setCurrentStep] = useState(0);
    const [formData, setFormData] = useState(editData || {
        // Datos Generales
        fecha: new Date().toISOString().split('T')[0],
        hora: '',
        empresa: '',
        ubicacion: '',
        gravedad: 'Leve',
        // Accidentado
        victimaNombre: '',
        victimaDni: '',
        victimaPuesto: '',
        victimaAntiguedad: '',
        lesion: '',
        parteCuerpo: '',
        // Descripción y Testigos
        descripcionHecho: '',
        testigos: [{ nombre: '', declaracion: '' }],
        // Análisis Causal (5 Porqués)
        problemaCentral: '',
        porques: [''],
        // Medidas Preventivas
        medidas: [{ accion: '', responsable: '', fechaLimite: '' }]
    });

    const [showShare, setShowShare] = useState(false);
    const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);
    const [viewMode, setViewMode] = useState('edit'); // 'edit' or 'report'

    useEffect(() => {
        window.scrollTo(0, 0);
    }, [currentStep]);

    const handleInputChange = (field, value) => {
        setFormData(prev => ({ ...prev, [field]: value }));
    };

    const handleArrayChange = (arrayName, index, field, value) => {
        setFormData(prev => {
            const newArray = [...prev[arrayName]];
            // If it's an array of strings (like porques)
            if (typeof newArray[index] === 'string') {
                newArray[index] = value;
            } else {
                newArray[index] = { ...newArray[index], [field]: value };
            }
            return { ...prev, [arrayName]: newArray };
        });
    };

    const addArrayItem = (arrayName, defaultItem) => {
        setFormData(prev => ({ ...prev, [arrayName]: [...prev[arrayName], defaultItem] }));
    };

    const removeArrayItem = (arrayName, index) => {
        setFormData(prev => ({
            ...prev,
            [arrayName]: prev[arrayName].filter((_, i) => i !== index)
        }));
    };

    const handleNext = () => {
        if (currentStep < SECTIONS.length - 1) setCurrentStep(s => s + 1);
    };

    const handlePrev = () => {
        if (currentStep > 0) setCurrentStep(s => s - 1);
    };

    const handleSave = () => {
        if (!formData.empresa || !formData.victimaNombre) {
            toast.error('La empresa y el nombre del accidentado son obligatorios.');
            return;
        }

        const report = {
            id: editData?.id || Date.now(),
            date: editData?.date || new Date().toISOString(),
            ...formData
        };

        let history = JSON.parse(localStorage.getItem('accident_history') || '[]');

        if (editData) {
            history = history.map(item => item.id === editData.id ? report : item);
        } else {
            history.unshift(report);
        }

        localStorage.setItem('accident_history', JSON.stringify(history));
        syncCollection('accident_history', history);

        toast.success(editData ? 'Investigación actualizada correctamente.' : 'Investigación guardada correctamente.');
        navigate('/accident-history');
    };

    const handlePrint = () => {
        requirePro(() => {
            // Ensure ID exists for PDF ref (INV-XXXXXX)
            if (!formData.id) {
                setFormData(prev => ({ ...prev, id: Date.now() }));
            }
            window.print();
        });
    };



    return (
        <div className="container" style={{ paddingBottom: '6rem', minHeight: '100vh', display: 'flex', flexDirection: 'column' }}>
            <div className="no-print">
                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '1.5rem', zIndex: 10 }}>
                    <button onClick={() => navigate('/#tools')} style={{ padding: '0.5rem', background: 'var(--color-surface)', border: '1px solid var(--color-border)', cursor: 'pointer', borderRadius: '50%', color: 'var(--color-text)' }}>
                        <ArrowLeft size={20} />
                    </button>
                    <div>
                        <h1 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 800 }}>{editData ? 'Editar Investigación' : 'Investigación de Accidente'}</h1>
                        <p style={{ margin: 0, fontSize: '0.8rem', color: 'var(--color-text-muted)' }}>Metodología Árbol de Causas</p>
                    </div>
                </div>

                <ShareModal
                    open={showShare}
                    onClose={() => setShowShare(false)}
                    title={`Investigación de Accidente - ${formData.victimaNombre}`}
                    text={`⚠️ Informe de Investigación de Accidente\n👤 Accidentado: ${formData.victimaNombre}\n🏢 Empresa: ${formData.empresa}\n📅 Fecha: ${formData.fecha}\n⚠️ Gravedad: ${formData.gravedad}\n\nGenerado con Asistente HYS`}
                    elementIdToPrint="pdf-content"
                />

                {/* Floating Action Buttons */}
                <div className="floating-action-bar">
                    <button
                        onClick={handleSave}
                        className="btn-floating-action"
                        style={{ background: '#36B37E', color: '#ffffff' }}
                    >
                        <Save size={18} /> GUARDAR
                    </button>
                    <button
                        onClick={() => requirePro(() => setShowShare(true))}
                        className="btn-floating-action"
                        style={{ background: '#0052CC', color: '#ffffff' }}
                    >
                        <Share2 size={18} /> COMPARTIR
                    </button>
                    <button
                        onClick={handlePrint}
                        className="btn-floating-action"
                        style={{ background: '#FF8B00', color: '#ffffff' }}
                    >
                        <Printer size={18} /> IMPRIMIR PDF
                    </button>
                </div>

                {/* Stepper */}
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '2rem', position: 'relative' }}>
                    <div style={{ position: 'absolute', top: '50%', left: 0, right: 0, height: '2px', background: 'var(--color-border)', zIndex: 0, transform: 'translateY(-50%)' }} />
                    {SECTIONS.map((section, index) => (
                        <div key={index} style={{
                            display: 'flex', flexDirection: 'column', alignItems: 'center', zIndex: 1, gap: '0.5rem',
                            cursor: 'pointer'
                        }} onClick={() => setCurrentStep(index)}>
                            <div style={{
                                width: '32px', height: '32px', borderRadius: '50%',
                                background: currentStep >= index ? 'var(--color-primary)' : 'var(--color-surface)',
                                border: `2px solid ${currentStep >= index ? 'var(--color-primary)' : 'var(--color-border)'}`,
                                color: currentStep >= index ? '#fff' : 'var(--color-text-muted)',
                                display: 'flex', alignItems: 'center', justifyContent: 'center',
                                fontWeight: 700, fontSize: '0.9rem', transition: 'all 0.3s'
                            }}>
                                {currentStep > index ? <CheckCircle2 size={16} /> : index + 1}
                            </div>
                            <span style={{ fontSize: '0.75rem', fontWeight: currentStep === index ? 700 : 500, color: currentStep === index ? 'var(--color-text)' : 'var(--color-text-muted)', textAlign: 'center', maxWidth: '80px', display: 'none' }} className="sm:inline">{section}</span>
                        </div>
                    ))}
                </div>

                <div className="card" style={{ flex: 1, padding: '2rem' }}>
                    <h2 style={{ fontSize: '1.25rem', marginBottom: '1.5rem', borderBottom: '1px solid var(--color-border)', paddingBottom: '0.5rem', color: 'var(--color-primary)' }}>
                        {SECTIONS[currentStep]}
                    </h2>

                    {currentStep === 0 && (
                        <div className="grid-2-cols">
                            <div>
                                <label>Fecha del Suceso</label>
                                <input type="date" value={formData.fecha} onChange={e => handleInputChange('fecha', e.target.value)} />
                            </div>
                            <div>
                                <label>Hora Aprox.</label>
                                <input type="time" value={formData.hora} onChange={e => handleInputChange('hora', e.target.value)} />
                            </div>
                            <div style={{ gridColumn: '1 / -1' }}>
                                <label>Razón Social / Empresa</label>
                                <input type="text" placeholder="Ej. Constructora SRL" value={formData.empresa} onChange={e => handleInputChange('empresa', e.target.value)} />
                            </div>
                            <div style={{ gridColumn: '1 / -1' }}>
                                <label>Ubicación / Sector</label>
                                <input type="text" placeholder="Ej. Obra Centro, Sector Hormigonado" value={formData.ubicacion} onChange={e => handleInputChange('ubicacion', e.target.value)} />
                            </div>
                            <div style={{ gridColumn: '1 / -1' }}>
                                <label>Gravedad Estimada</label>
                                <select value={formData.gravedad} onChange={e => handleInputChange('gravedad', e.target.value)}>
                                    <option value="Leve">Leve (Sin baja)</option>
                                    <option value="Moderado">Moderado (Con baja médica corta)</option>
                                    <option value="Grave">Grave (Internación, amputaciones)</option>
                                    <option value="Mortal">Mortal</option>
                                </select>
                            </div>
                        </div>
                    )}

                    {currentStep === 1 && (
                        <div className="grid-2-cols">
                            <div style={{ gridColumn: '1 / -1' }}>
                                <label>Nombre del Accidentado</label>
                                <input type="text" placeholder="Nombre completo" value={formData.victimaNombre} onChange={e => handleInputChange('victimaNombre', e.target.value)} />
                            </div>
                            <div>
                                <label>DNI / CUIL</label>
                                <input type="text" placeholder="Sin guiones" value={formData.victimaDni} onChange={e => handleInputChange('victimaDni', e.target.value)} />
                            </div>
                            <div>
                                <label>Puesto / Tarea</label>
                                <input type="text" placeholder="Ej. Oficial Albañil" value={formData.victimaPuesto} onChange={e => handleInputChange('victimaPuesto', e.target.value)} />
                            </div>
                            <div>
                                <label>Antigüedad en el puesto</label>
                                <input type="text" placeholder="Ej. 2 años" value={formData.victimaAntiguedad} onChange={e => handleInputChange('victimaAntiguedad', e.target.value)} />
                            </div>
                            <div style={{ gridColumn: '1 / -1' }}>
                                <label>Tipo de Lesión</label>
                                <input type="text" placeholder="Ej. Corte profundo, contusión, fractura..." value={formData.lesion} onChange={e => handleInputChange('lesion', e.target.value)} />
                            </div>
                            <div style={{ gridColumn: '1 / -1' }}>
                                <label>Parte del Cuerpo Afectada</label>
                                <input type="text" placeholder="Ej. Mano derecha indíce" value={formData.parteCuerpo} onChange={e => handleInputChange('parteCuerpo', e.target.value)} />
                            </div>
                        </div>
                    )}

                    {currentStep === 2 && (
                        <div>
                            <div style={{ marginBottom: '1.5rem' }}>
                                <label>Descripción detallada del Hecho (¿Qué pasó?)</label>
                                <textarea
                                    rows={5}
                                    placeholder="Relato detallado de cómo ocurrió el accidente, basado en los testimonios y evidencias iniciales..."
                                    value={formData.descripcionHecho}
                                    onChange={e => handleInputChange('descripcionHecho', e.target.value)}
                                />
                            </div>

                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
                                <h3 style={{ fontSize: '1rem', margin: 0 }}>Testigos del Hecho</h3>
                                <button className="btn-outline" style={{ padding: '0.4rem 0.8rem', fontSize: '0.8rem' }} onClick={() => addArrayItem('testigos', { nombre: '', declaracion: '' })}>
                                    <UserPlus size={16} /> Añadir Testigo
                                </button>
                            </div>

                            {formData.testigos.map((t, i) => (
                                <div key={i} className="responsive-list-card">
                                    {formData.testigos.length > 1 && (
                                        <button
                                            onClick={() => removeArrayItem('testigos', i)}
                                            className="card-delete-btn"
                                            title="Eliminar Testigo"
                                        >
                                            <Trash2 size={16} />
                                        </button>
                                    )}
                                    <label>Nombre del Testigo {i + 1}</label>
                                    <input type="text" placeholder="Nombre completo o cargo" value={t.nombre} onChange={e => handleArrayChange('testigos', i, 'nombre', e.target.value)} />
                                    <label>Declaración Breve</label>
                                    <textarea rows={2} placeholder="Lo que presenció..." value={t.declaracion} onChange={e => handleArrayChange('testigos', i, 'declaracion', e.target.value)} />
                                </div>
                            ))}
                        </div>
                    )}

                    {currentStep === 3 && (
                        <div>
                            <div style={{ background: 'rgba(59, 130, 246, 0.1)', padding: '1rem', borderRadius: '12px', border: '1px solid rgba(59, 130, 246, 0.2)', marginBottom: '1.5rem', fontSize: '0.9rem', color: 'var(--color-text)' }}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', fontWeight: 700, marginBottom: '0.5rem', color: 'var(--color-primary)' }}>
                                    <Search size={18} /> Metodología de los "5 Porqués"
                                </div>
                                Técnica sistemática para iterar preguntando "¿Por qué ocurrió?" hasta llegar a la causa raíz sistémica o de gestión, evitando culpar únicamente al error humano.
                            </div>

                            <label>El Problema (Efecto Final)</label>
                            <input type="text" placeholder="Ej. El trabajador se cortó la mano con la amoladora" value={formData.problemaCentral} onChange={e => handleInputChange('problemaCentral', e.target.value)} style={{ fontWeight: 'bold' }} />

                            <div style={{ marginTop: '1.5rem', borderLeft: '3px solid var(--color-primary)', paddingLeft: '1rem' }}>
                                {formData.porques.map((pq, i) => (
                                    <div key={i} className="responsive-list-card" style={{ padding: '1rem' }}>
                                        <label style={{ color: 'var(--color-text)', margin: 0 }}>¿Por qué? (Nivel {i + 1})</label>
                                        <div style={{ display: 'flex', gap: '0.5rem' }}>
                                            <input type="text" placeholder="Respuesta al porqué anterior..." value={pq} onChange={e => handleArrayChange('porques', i, null, e.target.value)} style={{ marginBottom: 0, flex: 1 }} />
                                            {formData.porques.length > 1 && (
                                                <button
                                                    onClick={() => removeArrayItem('porques', i)}
                                                    className="card-delete-btn"
                                                    style={{ position: 'relative', top: 'auto', right: 'auto', borderRadius: '8px', zIndex: 1 }}
                                                    title="Eliminar Porqué"
                                                >
                                                    <Trash2 size={16} />
                                                </button>
                                            )}
                                        </div>
                                    </div>
                                ))}
                                {formData.porques.length < 5 && (
                                    <button className="btn-outline" style={{ padding: '0.4rem 0.8rem', fontSize: '0.8rem', marginTop: '0.5rem' }} onClick={() => addArrayItem('porques', '')}>
                                        <ListPlus size={16} /> Preguntar otro "¿Por qué?"
                                    </button>
                                )}
                            </div>
                        </div>
                    )}

                    {currentStep === 4 && (
                        <div>
                            <p style={{ margin: '0 0 1.5rem 0', color: 'var(--color-text-muted)', fontSize: '0.9rem' }}>
                                En base a la causa raíz detectada, defina el Plan de Acción Correctivo/Preventivo para asegurar que no vuelva a ocurrir.
                            </p>

                            {formData.medidas.map((m, i) => (
                                <div key={i} className="responsive-list-card">
                                    {formData.medidas.length > 1 && (
                                        <button
                                            onClick={() => removeArrayItem('medidas', i)}
                                            className="card-delete-btn"
                                            title="Eliminar Medida"
                                        >
                                            <Trash2 size={16} />
                                        </button>
                                    )}
                                    <label>Acción Correctiva / Preventiva</label>
                                    <input type="text" placeholder="Ej. Instalar guardas fijas, dar capacitación" value={m.accion} onChange={e => handleArrayChange('medidas', i, 'accion', e.target.value)} />

                                    <div className="grid-2-cols">
                                        <div>
                                            <label>Responsable</label>
                                            <input type="text" placeholder="Ej. Jefe de Mantenimiento" value={m.responsable} onChange={e => handleArrayChange('medidas', i, 'responsable', e.target.value)} />
                                        </div>
                                        <div>
                                            <label>Fecha Límite</label>
                                            <input type="date" value={m.fechaLimite} onChange={e => handleArrayChange('medidas', i, 'fechaLimite', e.target.value)} />
                                        </div>
                                    </div>
                                </div>
                            ))}

                            <button className="btn-outline" style={{ padding: '0.4rem 0.8rem', fontSize: '0.8rem', width: '100%', justifyContent: 'center', marginBottom: '1rem' }} onClick={() => addArrayItem('medidas', { accion: '', responsable: '', fechaLimite: '' })}>
                                <Plus size={16} /> Añadir otra Medida
                            </button>
                        </div>
                    )}
                </div>

                {/* Navegación Inferior Responsive */}
                <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: '1.5rem', gap: '1rem', flexWrap: 'wrap' }}>
                    <button
                        className="btn-outline"
                        onClick={handlePrev}
                        disabled={currentStep === 0}
                        style={{ opacity: currentStep === 0 ? 0.4 : 1, flex: 1, minWidth: '120px', background: 'var(--color-surface)', margin: 0 }}
                    >
                        <ChevronLeft size={20} /> Atrás
                    </button>

                    {currentStep < SECTIONS.length - 1 && (
                        <button className="btn-primary" onClick={handleNext} style={{ margin: 0, flex: 1, minWidth: '120px', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem' }}>
                            Siguiente <ChevronRight size={20} />
                        </button>
                    )}
                </div>
            </div>

            {/* Hidden report for direct printing */}
            <div className="print-only">
                <AccidentPdfGenerator report={{ ...formData, id: formData.id || Date.now() }} onBack={() => { }} />
            </div>

        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { XCircle, CheckCircle2 } from 'lucide-react';

// Tipos de auditoría según ISO 45001
const AUDIT_TYPES = [
    { id: 'internal', name: 'Auditoría Interna', icon: '📋', color: '#3b82f6' },
    { id: 'external', name: 'Auditoría Externa', icon: '🏢', color: '#8b5cf6' },
    { id: 'certification', name: 'Certificación', icon: '📜', color: '#10b981' },
    { id: 'surveillance', name: 'Seguimiento', icon: '👁️', color: '#f59e0b' },
    { id: 'compliance', name: 'Cumplimiento Legal', icon: '⚖️', color: '#dc2626' },
    { id: 'supplier', name: 'Proveedor', icon: '🤝', color: '#06b6d4' }
];

// Áreas de auditoría ISO 45001
const AUDIT_AREAS = [
    { id: 'context', name: 'Contexto de la Organización', clause: '4' },
    { id: 'leadership', name: 'Liderazgo y Participación', clause: '5' },
    { id: 'planning', name: 'Planificación', clause: '6' },
    { id: 'support', name: 'Apoyo', clause: '7' },
    { id: 'operation', name: 'Operación', clause: '8' },
    { id: 'performance', name: 'Evaluación del Desempeño', clause: '9' },
    { id: 'improvement', name: 'Mejora', clause: '10' }
];

const labelStyle = { display: 'block', fontSize: '0.8rem', fontWeight: 700, color: 'var(--color-text-muted)', textTransform: 'uppercase', marginBottom: '0.5rem' };
const inputStyle = { width: '100%', padding: '0.75rem 1rem', borderRadius: 'var(--radius-lg)', border: '1px solid var(--color-input-border)', background: 'var(--color-surface)', color: 'var(--color-text)', fontSize: '0.95rem', fontWeight: 500, outline: 'none', transition: 'all var(--transition-fast)', boxSizing: 'border-box' };

export default function AuditCreate() {
    const navigate = useNavigate();
    const location = useLocation();
    const [audit, setAudit] = useState({
        title: '',
        auditType: '',
        scope: '',
        leadAuditor: '',
        auditTeam: [],
        auditDate: '',
        duration: '',
        location: '',
        department: '',
        standard: 'ISO 45001:2018',
        areas: [],
        status: 'draft',
        scheduledDate: '',
        observations: '',
        conclusion: ''
    });

    const queryParams = new URLSearchParams(location.search);
    const auditsDb = localStorage.getItem('ehs_audits_db');
    const audits = auditsDb ? JSON.parse(auditsDb) : [];

    const handleCreateAudit = () => {
        if (!audit.title.trim()) return;

        const newAudit = {
            ...audit,
            id: `AUD-${Date.now()}`,
            createdAt: new Date().toISOString(),
            status: 'planned',
            checklist: buildChecklist(audit.areas)
        };

        const updated = [newAudit, ...audits];
        localStorage.setItem('ehs_audits_db', JSON.stringify(updated));

        // Redirect back to manager with success
        navigate('/audit?created=' + newAudit.id);
    };

    const buildChecklist = (selectedAreas) => {
        const checklist = [];
        selectedAreas.forEach(areaId => {
            const areaChecklist = ISO_CHECKLIST[areaId] || [];
            areaChecklist.forEach(item => {
                checklist.push({
                    ...item,
                    area: areaId,
                    status: null,
                    evidence: '',
                    auditor: ''
                });
            });
        });
        return checklist;
    };

    const toggleArea = (areaId) => {
        const current = audit.areas || [];
        const updated = current.includes(areaId) ? current.filter(a => a !== areaId) : [...current, areaId];
        setAudit({ ...audit, areas: updated });
    };

    const ISO_CHECKLIST = {
        context: [
            { id: '4.1', question: '¿Se determinaron las cuestiones internas y externas relevantes?', required: true },
            { id: '4.2', question: '¿Se identificaron las partes interesadas y sus necesidades?', required: true },
            { id: '4.3', question: '¿Está definido el alcance del SGSST?', required: true },
            { id: '4.4', question: '¿Está establecido el sistema de gestión SST?', required: true }
        ],
        leadership: [
            { id: '5.1', question: '¿La dirección demuestra liderazgo y compromiso?', required: true },
            { id: '5.2', question: '¿Existe una política de SST documentada?', required: true },
            { id: '5.3', question: '¿Están asignados roles y responsabilidades?', required: true },
            { id: '5.4', question: '¿Se consulta y participa a los trabajadores?', required: true }
        ],
        planning: [
            { id: '6.1', question: '¿Se identifican peligros y evalúan riesgos?', required: true },
            { id: '6.1.2', question: '¿Se determinan requisitos legales aplicables?', required: true },
            { id: '6.2', question: '¿Existen objetivos de SST medibles?', required: true },
            { id: '6.3', question: '¿Se planifica el cambio del sistema?', required: false }
        ],
        support: [
            { id: '7.1', question: '¿Se proporcionan recursos necesarios?', required: true },
            { id: '7.2', question: '¿El personal es competente para sus tareas?', required: true },
            { id: '7.3', question: '¿Se sensibiliza a los trabajadores sobre SST?', required: true },
            { id: '7.4', question: '¿Existen procesos de comunicación interna/externa?', required: true },
            { id: '7.5', question: '¿Se controla la información documentada?', required: true }
        ],
        operation: [
            { id: '8.1', question: '¿Se planifican y controlan los procesos operacionales?', required: true },
            { id: '8.1.1', question: '¿Existe jerarquía de controles de riesgo?', required: true },
            { id: '8.1.2', question: '¿Se gestiona el cambio operacional?', required: true },
            { id: '8.1.3', question: '¿Se gestionan compras y contratistas?', required: true },
            { id: '8.1.4', question: '¿Existe preparación y respuesta ante emergencias?', required: true }
        ],
        performance: [
            { id: '9.1', question: '¿Se realiza seguimiento y medición del desempeño?', required: true },
            { id: '9.1.2', question: '¿Se evalúa el cumplimiento legal?', required: true },
            { id: '9.2', question: '¿Se realiza auditoría interna periódica?', required: true },
            { id: '9.3', question: '¿La dirección revisa el sistema anualmente?', required: true }
        ],
        improvement: [
            { id: '10.1', question: '¿Se investigan incidentes y no conformidades?', required: true },
            { id: '10.2', question: '¿Se toman acciones correctivas?', required: true },
            { id: '10.3', question: '¿Existe mejora continua del sistema?', required: true }
        ]
    };

    return (
        <div className="container" style={{ paddingBottom: '6rem', maxWidth: '900px', paddingTop: '2rem' }}>
            {/* Header */}
            <div style={{
                marginBottom: '2.5rem',
                padding: '1.75rem',
                background: 'var(--gradient-card)',
                borderRadius: 'var(--radius-2xl)',
                border: '1px solid var(--glass-border)',
                boxShadow: 'var(--glass-shadow)',
                backdropFilter: 'blur(20px)',
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'center'
            }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                    <div style={{
                        width: '56px',
                        height: '56px',
                        background: 'linear-gradient(135deg, #8b5cf6, #7c3aed)',
                        borderRadius: 'var(--radius-lg)',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        boxShadow: '0 4px 20px rgba(139, 92, 246, 0.3)'
                    }}>
                        <XCircle size={32} color="#ffffff" strokeWidth={2} onClick={() => navigate('/audit')} style={{ cursor: 'pointer' }} />
                    </div>
                    <div>
                        <h1 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 900, lineHeight: 1.2 }}>Nueva Auditoría EHS</h1>
                        <p style={{ margin: '0.5rem 0 0 0', color: 'var(--color-text-muted)', fontSize: '0.85rem', lineHeight: 1.4 }}>Completá los datos para crear una auditoría</p>
                    </div>
                </div>
            </div>

            {/* Form */}
            <div className="card" style={{ padding: '2.5rem', paddingTop: '2rem' }}>
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem', marginBottom: '1.5rem' }}>
                    <div><label style={labelStyle}>Título *</label><input type="text" value={audit.title} onChange={(e) => setAudit({ ...audit, title: e.target.value })} style={inputStyle} placeholder="Ej: Auditoría Interna 2024" /></div>
                    <div><label style={labelStyle}>Tipo de Auditoría</label><select value={audit.auditType} onChange={(e) => setAudit({ ...audit, auditType: e.target.value })} style={inputStyle}>{AUDIT_TYPES.map(t => <option key={t.id} value={t.id}>{t.icon} {t.name}</option>)}</select></div>
                    <div><label style={labelStyle}>Auditor Líder</label><input type="text" value={audit.leadAuditor} onChange={(e) => setAudit({ ...audit, leadAuditor: e.target.value })} style={inputStyle} placeholder="Nombre del auditor" /></div>
                    <div><label style={labelStyle}>Ubicación</label><input type="text" value={audit.location} onChange={(e) => setAudit({ ...audit, location: e.target.value })} style={inputStyle} placeholder="Ej: Planta Principal" /></div>
                    <div><label style={labelStyle}>Fecha Programada</label><input type="date" value={audit.scheduledDate} onChange={(e) => setAudit({ ...audit, scheduledDate: e.target.value })} style={inputStyle} /></div>
                    <div><label style={labelStyle}>Duración (días)</label><input type="number" value={audit.duration} onChange={(e) => setAudit({ ...audit, duration: e.target.value })} style={inputStyle} placeholder="Ej: 2" /></div>
                </div>

                <div style={{ marginBottom: '2rem' }}>
                    <label style={labelStyle}>Áreas ISO 45001 a Auditar</label>
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '1rem' }}>
                        {AUDIT_AREAS.map(area => (
                            <label key={area.clause} style={{
                                padding: '1rem',
                                background: audit.areas?.includes(area.id) ? '#eff6ff' : 'var(--color-background)',
                                border: `2px solid ${audit.areas?.includes(area.id) ? '#3b82f6' : 'var(--color-border)'}`,
                                borderRadius: 'var(--radius-lg)',
                                cursor: 'pointer',
                                display: 'flex',
                                alignItems: 'center',
                                gap: '1rem',
                                transition: 'all var(--transition-fast)'
                            }}>
                                <input type="checkbox" checked={audit.areas?.includes(area.id)} onChange={() => toggleArea(area.id)} style={{ width: '20px', height: '20px' }} />
                                <div>
                                    <span style={{ fontSize: '0.7rem', fontWeight: 700, color: 'var(--color-text-muted)' }}>Cláusula {area.clause}</span>
                                    <div style={{ fontSize: '0.9rem', fontWeight: 600 }}>{area.name}</div>
                                </div>
                            </label>
                        ))}
                    </div>
                </div>

                <div style={{ display: 'flex', gap: '1rem', paddingTop: '1.5rem', borderTop: '1px solid var(--color-border)' }}>
                    <button onClick={() => navigate('/audit')} style={{ flex: 1, padding: '1rem', background: 'var(--color-background)', border: '1px solid var(--color-border)', borderRadius: 'var(--radius-lg)', fontWeight: 700, cursor: 'pointer', fontSize: '1rem' }}>Cancelar</button>
                    <button onClick={handleCreateAudit} className="btn-primary" style={{ flex: 1, fontSize: '1rem' }}>Crear Auditoría</button>
                </div>
            </div>
        </div>
    );
}

