            <div style={{ padding: isMobile ? '0 1rem' : '0 1.5rem', maxWidth: '1400px', margin: '0 auto', display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
                {filtered.length === 0 ? <EmptyState onAdd={() => navigate('/audit/new')} isMobile={isMobile} /> : filtered.map(a => (<AuditCard key={a.id} audit={a} statusConfig={STATUS[a.status] || STATUS.planned} onStart={() => updateStatus(a.id, 'in_progress')} onComplete={() => updateStatus(a.id, 'completed')} onView={() => setSelected(a)} onDelete={() => del(a.id)} isMobile={isMobile} />))}
            </div>
            </div>
            {selected && <DetailModal audit={selected} onClose={() => setSelected(null)} isMobile={isMobile} onPrint={() => setShowShareModal(true)} />}

