                fileName={`Auditoria_${selected?.title || 'Sin_Titulo'}.pdf`}
            />

            <div className="print-only" style={{ position: 'fixed', left: '-9999px', top: 0 }}>
                <AuditPdf data={selected} />
            </div>
        </div>
    );
}
