                    <span style={{ fontSize: '0.75rem', fontWeight: 800, color: 'var(--color-text-muted)', background: 'var(--color-background)', padding: '0.25rem 0.5rem', borderRadius: 'var(--radius-md)' }}>
                        {capa.id}
                    </span>
                    <h3 style={{ 
                        margin: 0, 
                        fontSize: '1.1rem', 
                        fontWeight: 800,
                        color: 'var(--color-text)',
                        whiteSpace: 'nowrap',
                        overflow: 'hidden',
                        textOverflow: 'ellipsis'
                    }}>
                        {capaType?.icon} {capa.title}
                    </h3>
                    <span style={{
                        padding: '0.35rem 0.75rem',
                        background: statusConfig.bg,
                        color: statusConfig.color,
                        borderRadius: 'var(--radius-full)',
                        fontSize: '0.7rem',
                        fontWeight: 800,
                        textTransform: 'uppercase'
                    }}>
                        {statusConfig.label}
                    </span>
                    {isOverdue && (
                        <span style={{
                            padding: '0.35rem 0.75rem',
                            background: '#fef2f2',
                            color: '#dc2626',
                            borderRadius: 'var(--radius-full)',
                            fontSize: '0.7rem',
                            fontWeight: 800,
                            display: 'flex',
                            alignItems: 'center',
                            gap: '0.25rem'
                        }}>
                            <AlertTriangle size={12} />
                            VENCIDA
                        </span>
                    )}
                </div>
                <div style={{ 
                    display: 'flex', 
                    flexWrap: 'wrap', 
                    gap: '1rem',
                    fontSize: '0.85rem',
                    color: 'var(--color-text-muted)',
                    fontWeight: 500
                }}>
                    <span style={{ display: 'flex', alignItems: 'center', gap: '0.35rem' }}>
                        <User size={14} />
                        {capa.responsible || 'Sin asignar'}
                    </span>
                    <span style={{ display: 'flex', alignItems: 'center', gap: '0.35rem' }}>
                        <Calendar size={14} />
                        {capa.dueDate ? new Date(capa.dueDate).toLocaleDateString() : 'Sin fecha'}
                    </span>
                    {daysUntilDue !== null && daysUntilDue >= 0 && (
                        <span style={{ 
                            color: daysUntilDue <= 3 ? '#dc2626' : daysUntilDue <= 7 ? '#f59e0b' : '#16a34a',
                            fontWeight: 700,
                            fontSize: '0.8rem'
                        }}>
                            {daysUntilDue === 0 ? 'Vence hoy' : daysUntilDue === 1 ? 'Vence mañana' : `Vence en ${daysUntilDue} días`}
