                            padding: '0.6rem 0.75rem',
                            background: '#3b82f6',
                            border: 'none',
                            borderRadius: 'var(--radius-md)',
                            cursor: 'pointer',
                            color: '#fff',
                            fontWeight: 700,
                            fontSize: '0.8rem'
                        }}
                        title="Iniciar"
                    >
                        <Clock size={18} />
                    </button>
                )}
                {capa.status === 'in_progress' && (
                    <button
                        onClick={onAddAction}
                        style={{
                            padding: '0.6rem 0.75rem',
                            background: '#10b981',
                            border: 'none',
                            borderRadius: 'var(--radius-md)',
                            cursor: 'pointer',
                            color: '#fff',
                            fontWeight: 700,
                            fontSize: '0.8rem'
                        }}
