import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import {
    ArrowLeft, Search, FlaskConical, AlertTriangle, CheckCircle2, Share2, Printer, Trash2
} from 'lucide-react';
import { useDocumentTitle } from '../hooks/useDocumentTitle';
import ShareModal from '../components/ShareModal';
import ChemicalSafetyPdf from '../components/ChemicalSafetyPdf';

const GHS_PICTOGRAMS = {
    explosive: { icon: '🧨', name: 'Explosivo', color: '#dc2626' },
    flammable: { icon: '🔥', name: 'Inflamable', color: '#dc2626' },
    oxidizing: { icon: '🔥', name: 'Comburente', color: '#dc2626' },
    corrosive: { icon: '🧪', name: 'Corrosivo', color: '#dc2626' },
    toxic: { icon: '💀', name: 'Tóxico', color: '#dc2626' },
    harmful: { icon: '⚠️', name: 'Nocivo', color: '#f59e0b' },
    irritant: { icon: '⚠️', name: 'Irritante', color: '#f59e0b' }
};

export default function ChemicalSafetyHistory() {
    useDocumentTitle('Productos Químicos');
    const navigate = useNavigate();

    const [chemicals, setChemicals] = useState([]);
    const [searchTerm, setSearchTerm] = useState('');
    const [filterCategory, setFilterCategory] = useState('all');
    const [shareItem, setShareItem] = useState(null);

    useEffect(() => {
        const stored = JSON.parse(localStorage.getItem('chemical_safety_db') || '[]');
        setChemicals(stored);
    }, []);

    const filteredChemicals = chemicals.filter(chem => {
        const matchesSearch = chem.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                            chem.casNumber?.includes(searchTerm) ||
                            chem.supplier?.toLowerCase().includes(searchTerm.toLowerCase());
        const matchesCategory = filterCategory === 'all' || chem.category === filterCategory;
        return matchesSearch && matchesCategory;
    });

    const stats = {
        total: chemicals.length,
        activos: chemicals.filter(c => c.status === 'active').length,
        criticos: chemicals.filter(c => c.pictograms?.some(p => ['toxic', 'corrosive', 'explosive'].includes(p))).length
    };

    const CATEGORIES = [
        { id: 'all', name: 'Todos', icon: '📦' },
        { id: 'fisico', name: 'Físico', icon: '🔥' },
        { id: 'salud', name: 'Salud', icon: '🏥' },
        { id: 'ambiental', name: 'Ambiental', icon: '🌍' }
    ];

    return (
        <div className="container" style={{ paddingBottom: '6rem' }}>
            <ShareModal
                open={!!shareItem}
                onClose={() => setShareItem(null)}
                title={`Ficha SGA - ${shareItem?.name || ''}`}
                text={shareItem ? `🧪 Ficha Técnica de Seguridad (SGA)\n🏷️ Producto: ${shareItem.name}\n🆔 CAS: ${shareItem.casNumber || '-'}\n📅 Fecha: ${new Date(shareItem.createdAt || Date.now()).toLocaleDateString()}` : ''}
                elementIdToPrint="pdf-content"
            />

            <div style={{ position: 'absolute', left: '-9999px', top: '-9999px', pointerEvents: 'none' }}>
                <ChemicalSafetyPdf data={shareItem} />
            </div>

            {/* Header */}
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '2rem' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                    <button onClick={() => navigate('/chemical-safety')} style={{ padding: '0.5rem', background: 'var(--color-surface)', border: '1px solid var(--color-border)', cursor: 'pointer', borderRadius: 'var(--radius-full)', color: 'var(--color-text)' }}>
                        <ArrowLeft size={20} />
                    </button>
                    <div>
                        <h1 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 800 }}>Productos Químicos</h1>
                        <p style={{ margin: '0.25rem 0 0 0', color: 'var(--color-text-muted)', fontSize: '0.85rem' }}>{stats.total} productos • {stats.criticos} críticos</p>
                    </div>
                </div>
                <button onClick={() => navigate('/chemical-safety/new')} className="btn-primary" style={{ margin: 0, padding: '0.75rem 1.25rem' }}>
                    Nuevo Producto
                </button>
            </div>

            {/* Stats Cards */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))', gap: '1rem', marginBottom: '2rem' }}>
                <StatCard label="Total" value={stats.total} color="#3B82F6" icon={<FlaskConical size={20} />} />
                <StatCard label="Activos" value={stats.activos} color="#16a34a" icon={<CheckCircle2 size={20} />} />
                <StatCard label="Críticos" value={stats.criticos} color="#dc2626" icon={<AlertTriangle size={20} />} />
            </div>

            {/* Filters */}
            <div style={{ display: 'flex', gap: '1rem', marginBottom: '1.5rem', flexWrap: 'wrap' }}>
                <div style={{ flex: 1, minWidth: '280px', position: 'relative' }}>
                    <Search size={20} style={{ position: 'absolute', left: '1rem', top: '50%', transform: 'translateY(-50%)', color: 'var(--color-text-muted)' }} />
                    <input
                        type="text"
                        placeholder="Buscar por nombre, CAS, proveedor..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        style={{ width: '100%', padding: '0.85rem 1rem 0.85rem 3rem', borderRadius: 'var(--radius-lg)', border: '1px solid var(--color-input-border)', background: 'var(--color-surface)', color: 'var(--color-text)', fontSize: '0.95rem', outline: 'none' }}
                    />
                </div>
                <select
                    value={filterCategory}
                    onChange={(e) => setFilterCategory(e.target.value)}
                    style={{ padding: '0.85rem 1.25rem', borderRadius: 'var(--radius-lg)', border: '1px solid var(--color-input-border)', background: 'var(--color-surface)', color: 'var(--color-text)', fontSize: '0.9rem', fontWeight: 600, cursor: 'pointer' }}
                >
                    {CATEGORIES.map(cat => (
                        <option key={cat.id} value={cat.id}>{cat.icon} {cat.name}</option>
                    ))}
                </select>
            </div>

            {/* Chemicals Grid */}
            {filteredChemicals.length === 0 ? (
                <div className="card" style={{ padding: '3rem', textAlign: 'center' }}>
                    <FlaskConical size={48} color="var(--color-text-muted)" style={{ opacity: 0.3, marginBottom: '1rem' }} />
                    <p style={{ color: 'var(--color-text-muted)', fontSize: '1rem' }}>No hay productos químicos registrados</p>
                    <button onClick={() => navigate('/chemical-safety')} className="btn-primary" style={{ marginTop: '1rem' }}>
                        Agregar Primer Producto
                    </button>
                </div>
            ) : (
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '1rem' }}>
                    {filteredChemicals.map(chem => (
                        <ChemicalCard 
                            key={chem.id} 
                            chemical={chem} 
                            onEdit={() => navigate(`/chemical-safety/new`, { state: { editData: chem } })}
                            onShare={() => setShareItem(chem)}
                        />
                    ))}
                </div>
            )}
        </div>
    );
}

function StatCard({ label, value, color, icon }) {
    return (
        <div className="card" style={{ padding: '1.25rem', background: 'var(--gradient-card)' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '0.5rem' }}>
                <span style={{ fontSize: '0.85rem', fontWeight: 600, color: 'var(--color-text-muted)' }}>{label}</span>
                <div style={{ color }}>{icon}</div>
            </div>
            <div style={{ fontSize: '2rem', fontWeight: 900, color }}>{value}</div>
        </div>
    );
}

function ChemicalCard({ chemical, onEdit, onShare }) {
    const primaryPicto = chemical.pictograms?.[0];
    const pictoConfig = primaryPicto ? GHS_PICTOGRAMS[primaryPicto] : null;
    const hazardLevel = chemical.pictograms?.some(p => ['toxic', 'corrosive', 'explosive'].includes(p)) 
        ? { color: '#dc2626', label: 'Crítico' }
        : chemical.pictograms?.some(p => ['flammable', 'harmful', 'irritant'].includes(p))
        ? { color: '#f59e0b', label: 'Precaución' }
        : { color: '#16a34a', label: 'Bajo' };

    return (
        <div className="card" style={{ padding: '1.25rem', transition: 'all var(--transition-fast)' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '1rem' }}>
                <div style={{ width: '56px', height: '56px', background: `${hazardLevel.color}20`, borderRadius: 'var(--radius-lg)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '2rem' }}>
                    {pictoConfig?.icon || '⚗️'}
                </div>
                <span style={{ padding: '0.35rem 0.75rem', background: `${hazardLevel.color}20`, color: hazardLevel.color, borderRadius: 'var(--radius-full)', fontSize: '0.7rem', fontWeight: 800 }}>
                    {hazardLevel.label}
                </span>
            </div>
            <h3 style={{ margin: '0 0 0.5rem 0', fontSize: '1rem', fontWeight: 700 }}>{chemical.name}</h3>
            <p style={{ margin: '0 0 0.25rem 0', fontSize: '0.85rem', color: 'var(--color-text-muted)' }}>
                CAS: {chemical.casNumber || 'N/A'}
            </p>
            <p style={{ margin: 0, fontSize: '0.85rem', color: 'var(--color-text-muted)' }}>
                {chemical.location || chemical.area || 'Sin ubicación'} • {chemical.quantity || '0'} {chemical.unit || ''}
            </p>

            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '1rem', borderTop: '1px solid var(--color-border)', paddingTop: '1rem' }}>
                <div style={{ display: 'flex', gap: '0.5rem' }}>
                    {chemical.pictograms?.slice(0, 3).map((p, i) => (
                        <span key={i} style={{ fontSize: '1.2rem' }}>{GHS_PICTOGRAMS[p]?.icon || '⚠️'}</span>
                    ))}
                </div>
                <div style={{ display: 'flex', gap: '0.5rem' }}>
                    <button onClick={onEdit} className="btn-secondary" style={{ padding: '0.5rem 0.75rem', fontSize: '0.8rem' }}>Editar</button>
                    <button onClick={onShare} style={{ padding: '0.5rem', background: '#dcfce7', border: '1px solid #86efac', borderRadius: '8px', color: '#16a34a', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                        <Share2 size={16} />
                    </button>
                </div>
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import {
    Tent, AlertTriangle, Plus, Search, 
    FileText, Eye, Edit3, Trash2, CheckCircle2, 
    XCircle, Clock, User, Users, Calendar,
    Shield, Wind, Droplets, Thermometer, Activity,
    BarChart3, AlertCircle, CheckSquare, XSquare
} from 'lucide-react';

// Límites atmosféricos según OSHA 1910.146
const ATMOSPHERIC_LIMITS = {
    oxygen: { min: 19.5, max: 23.5, unit: '%', name: 'Oxígeno' },
    lel: { min: 0, max: 10, unit: '%', name: 'LEL (Inflamables)' },
    h2s: { min: 0, max: 10, unit: 'ppm', name: 'H2S (Sulfuro)' },
    co: { min: 0, max: 35, unit: 'ppm', name: 'CO (Monóxido)' },
    co2: { min: 0, max: 5000, unit: 'ppm', name: 'CO2 (Dióxido)' }
};

// Tipos de espacios confinados
const CONFINED_SPACE_TYPES = [
    { id: 'tank', name: 'Tanque', icon: '🛢️' },
    { id: 'vessel', name: 'Recipiente', icon: '📦' },
    { id: 'silo', name: 'Silo', icon: '🏭' },
    { id: 'pit', name: 'Fosa', icon: '⬇️' },
    { id: 'tunnel', name: 'Túnel', icon: '🚇' },
    { id: 'sewer', name: 'Alcantarilla', icon: '🕳️' },
    { id: 'manhole', name: 'Boca de Visita', icon: '⭕' },
    { id: 'other', name: 'Otro', icon: '📍' }
];

// Roles en espacio confinado (OSHA)
const ROLES = [
    { id: 'entrant', name: 'Entrante', icon: '👤', color: '#3b82f6' },
    { id: 'attendant', name: 'Vigía', icon: '👁️', color: '#f59e0b' },
    { id: 'supervisor', name: 'Supervisor', icon: '👔', color: '#16a34a' },
    { id: 'rescue', name: 'Rescate', icon: '🚑', color: '#dc2626' }
];

// Equipamiento requerido
const EQUIPMENT_CHECKLIST = [
    { id: 'gas_detector', name: 'Detector de Gases', icon: '💨', required: true },
    { id: 'harness', name: 'Arnés de Seguridad', icon: '🦺', required: true },
    { id: 'tripod', name: 'Trípode con Malacate', icon: '🏗️', required: true },
    { id: 'ventilator', name: 'Ventilador', icon: '💨', required: false },
    { id: 'radio', name: 'Radio Comunicación', icon: '📻', required: true },
    { id: 'light', name: 'Iluminación', icon: '💡', required: true },
    { id: 'scba', name: 'ERA (SCBA)', icon: '😷', required: false },
    { id: 'first_aid', name: 'Botiquín Primeros Auxilios', icon: '🏥', required: true },
    { id: 'fire_extinguisher', name: 'Extintor', icon: '🧯', required: true },
    { id: 'barrier', name: 'Barreras/Señalización', icon: '🚧', required: true }
];

// Estados del permiso
const PERMIT_STATUS = {
    draft: { label: 'BORRADOR', color: '#6b7280', bg: '#f3f4f6' },
    pending: { label: 'PENDIENTE', color: '#f59e0b', bg: '#fffbeb' },
    active: { label: 'ACTIVO', color: '#16a34a', bg: '#f0fdf4' },
    suspended: { label: 'SUSPENDIDO', color: '#dc2626', bg: '#fef2f2' },
    completed: { label: 'COMPLETADO', color: '#3b82f6', bg: '#eff6ff' },
    expired: { label: 'EXPIRADO', color: '#9ca3af', bg: '#f9fafb' }
};

// Hazards potenciales
const POTENTIAL_HAZARDS = [
    { id: 'atmospheric', name: 'Atmosférico Peligroso', icon: '💨' },
    { id: 'engulfment', name: 'Atrapamiento', icon: '🌊' },
    { id: 'configuration', name: 'Configuración', icon: '📐' },
    { id: 'electrical', name: 'Eléctrico', icon: '⚡' },
    { id: 'mechanical', name: 'Mecánico', icon: '🔧' },
    { id: 'thermal', name: 'Térmico', icon: '🔥' },
    { id: 'noise', name: 'Ruido', icon: '🔊' },
    { id: 'fall', name: 'Caída', icon: '⬇️' },
    { id: 'chemical', name: 'Químico', icon: '🧪' },
    { id: 'biological', name: 'Biológico', icon: '🦠' }
];

export default function ConfinedSpace() {
    const navigate = useNavigate();
    const [permits, setPermits] = useState([]);
    const [activePermits, setActivePermits] = useState([]);
    const [searchTerm, setSearchTerm] = useState('');
    const [filterStatus, setFilterStatus] = useState('all');
    const [showAddModal, setShowAddModal] = useState(false);
    const [selectedPermit, setSelectedPermit] = useState(null);
    const [activeTab, setActiveTab] = useState('permits');
    const [showAtmosphericModal, setShowAtmosphericModal] = useState(false);
    const [currentPermitForReading, setCurrentPermitForReading] = useState(null);

    const [newPermit, setNewPermit] = useState({
        id: '',
        spaceName: '',
        spaceType: '',
        location: '',
        department: '',
        description: '',
        hazards: [],
        team: {
            entrants: [],
            attendant: '',
            supervisor: '',
            rescue: ''
        },
        equipment: EQUIPMENT_CHECKLIST.map(e => ({ ...e, checked: false })),
        atmosphericReadings: [],
        isolationPoints: [],
        rescueProcedure: '',
        communicationMethod: '',
        status: 'draft',
        validFrom: '',
        validUntil: '',
        createdAt: '',
        authorizedAt: '',
        completedAt: '',
        observations: ''
    });

    useEffect(() => {
        const loadData = () => {
            const savedPermits = localStorage.getItem('confined_space_permits_db');
            const savedActive = localStorage.getItem('confined_space_active_db');
            if (savedPermits) setPermits(JSON.parse(savedPermits));
            if (savedActive) setActivePermits(JSON.parse(savedActive));
        };

        loadData();

        const handleStorageChange = (e) => {
            if (e.key === 'confined_space_permits_db' || e.key === 'confined_space_active_db') {
                loadData();
            }
        };

        window.addEventListener('storage', handleStorageChange);

        const params = new URLSearchParams(window.location.search);
        if (params.get('created')) {
            loadData();
            window.history.replaceState({}, document.title, window.location.pathname);
        }

        return () => {
            window.removeEventListener('storage', handleStorageChange);
        };
    }, []);

    const savePermits = (data) => {
        localStorage.setItem('confined_space_permits_db', JSON.stringify(data));
        setPermits(data);
    };

    const saveActivePermits = (data) => {
        localStorage.setItem('confined_space_active_db', JSON.stringify(data));
        setActivePermits(data);
    };

    const handleCreatePermit = () => {
        if (!newPermit.spaceName.trim()) return;

        const permit = {
            ...newPermit,
            id: `CS-${Date.now()}`,
            createdAt: new Date().toISOString(),
            status: 'pending'
        };

        const updated = [permit, ...permits];
        savePermits(updated);
        setShowAddModal(false);
        resetForm();
    };

    const resetForm = () => {
        setNewPermit({
            id: '',
            spaceName: '',
            spaceType: '',
            location: '',
            department: '',
            description: '',
            hazards: [],
            team: {
                entrants: [],
                attendant: '',
                supervisor: '',
                rescue: ''
            },
            equipment: EQUIPMENT_CHECKLIST.map(e => ({ ...e, checked: false })),
            atmosphericReadings: [],
            isolationPoints: [],
            rescueProcedure: '',
            communicationMethod: '',
            status: 'draft',
            validFrom: '',
            validUntil: '',
            createdAt: '',
            authorizedAt: '',
            completedAt: '',
            observations: ''
        });
    };

    const authorizePermit = (permitId) => {
        const permit = permits.find(p => p.id === permitId);
        if (!permit) return;

        const now = new Date().toISOString();
        const validUntil = new Date(Date.now() + 8 * 60 * 60 * 1000).toISOString(); // 8 horas

        const authorizedPermit = {
            ...permit,
            status: 'active',
            authorizedAt: now,
            validFrom: now,
            validUntil
        };

        const updatedPermits = permits.map(p => 
            p.id === permitId ? authorizedPermit : p
        );
        savePermits(updatedPermits);

        const updatedActive = [authorizedPermit, ...activePermits];
        saveActivePermits(updatedActive);
    };

    const suspendPermit = (permitId) => {
        const updatedPermits = permits.map(p => 
            p.id === permitId ? { ...p, status: 'suspended' } : p
        );
        savePermits(updatedPermits);
        saveActivePermits(activePermits.filter(p => p.id !== permitId));
    };

    const completePermit = (permitId) => {
        const updatedPermits = permits.map(p => 
            p.id === permitId ? { 
                ...p, 
                status: 'completed',
                completedAt: new Date().toISOString()
            } : p
        );
        savePermits(updatedPermits);
        saveActivePermits(activePermits.filter(p => p.id !== permitId));
    };

    const deletePermit = (id) => {
        if (confirm('¿Eliminar este permiso de espacio confinado?')) {
            savePermits(permits.filter(p => p.id !== id));
            saveActivePermits(activePermits.filter(p => p.id !== id));
        }
    };

    const addAtmosphericReading = (reading) => {
        const updatedPermit = {
            ...currentPermitForReading,
            atmosphericReadings: [...currentPermitForReading.atmosphericReadings, {
                ...reading,
                timestamp: new Date().toISOString(),
                status: evaluateAtmosphere(reading)
            }]
        };

        // Update in permits
        const updatedPermits = permits.map(p => 
            p.id === updatedPermit.id ? updatedPermit : p
        );
        savePermits(updatedPermits);

        // Update in active
        const updatedActive = activePermits.map(p => 
            p.id === updatedPermit.id ? updatedPermit : p
        );
        saveActivePermits(updatedActive);

        setCurrentPermitForReading(updatedPermit);
    };

    const evaluateAtmosphere = (reading) => {
        const limits = ATMOSPHERIC_LIMITS;

        if (reading.oxygen < limits.oxygen.min || reading.oxygen > limits.oxygen.max) return 'danger';
        if (reading.lel > limits.lel.max) return 'danger';
        if (reading.h2s > limits.h2s.max) return 'danger';
        if (reading.co > limits.co.max) return 'danger';

        if (reading.oxygen < 20.9 || reading.lel > 0 || reading.h2s > 0 || reading.co > 0) return 'warning';

        return 'safe';
    };

    const filteredPermits = permits.filter(p => {
        const matchesSearch = p.spaceName.toLowerCase().includes(searchTerm.toLowerCase()) ||
                            p.location?.toLowerCase().includes(searchTerm.toLowerCase());
        const matchesStatus = filterStatus === 'all' || p.status === filterStatus;
        return matchesSearch && matchesStatus;
    });

    // Estadísticas
    const stats = {
        total: permits.length,
        active: activePermits.length,
        pending: permits.filter(p => p.status === 'pending').length,
        completed: permits.filter(p => p.status === 'completed').length,
        spaceTypes: permits.reduce((acc, p) => {
            if (p.spaceType) acc[p.spaceType] = (acc[p.spaceType] || 0) + 1;
            return acc;
        }, {})
    };

    return (
        <div className="container" style={{ paddingBottom: '6rem' }}>
            {/* Header Premium */}
            <div style={{
                marginBottom: '2rem',
                padding: '1.5rem',
                background: 'var(--gradient-card)',
                borderRadius: 'var(--radius-2xl)',
                border: '1px solid var(--glass-border)',
                boxShadow: 'var(--glass-shadow)',
                backdropFilter: 'blur(20px)',
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'center',
                flexWrap: 'wrap',
                gap: '1rem'
            }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                    <div style={{
                        width: '56px',
                        height: '56px',
                        background: 'linear-gradient(135deg, #f59e0b, #d97706)',
                        borderRadius: 'var(--radius-lg)',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        boxShadow: '0 4px 20px rgba(245, 158, 11, 0.3)'
                    }}>
                        <Tent size={32} color="#ffffff" strokeWidth={2} />
                    </div>
                    <div>
                        <h1 style={{ 
                            margin: 0, 
                            fontSize: '1.5rem', 
                            fontWeight: 900,
                            color: 'var(--color-text)',
                            letterSpacing: '-0.5px'
                        }}>
                            Espacios Confinados
                        </h1>
                        <p style={{ 
                            margin: '0.25rem 0 0 0', 
                            color: 'var(--color-text-muted)',
                            fontSize: '0.85rem',
                            fontWeight: 600
                        }}>
                            OSHA 1910.146 • {activePermits.length} activos
                        </p>
                    </div>
                </div>

                <div style={{ display: 'flex', gap: '0.75rem', flexWrap: 'wrap' }}>
                    <button
                        onClick={() => setShowAddModal(true)}
                        className="btn-primary"
                        style={{
                            width: 'auto',
                            margin: 0,
                            display: 'flex',
                            alignItems: 'center',
                            gap: '0.5rem',
                            padding: '0.75rem 1.25rem'
                        }}
                    >
                        <Plus size={20} strokeWidth={2.5} />
                        Nuevo Permiso
                    </button>
                    <button
                        onClick={() => navigate('/confined-space-history')}
                        className="btn-outline"
                        style={{
                            padding: '0.75rem 1rem'
                        }}
                    >
                        <FileText size={20} />
                    </button>
                </div>
            </div>

            {/* Stats Cards */}
            <div style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))',
                gap: '1rem',
                marginBottom: '2rem'
            }}>
                <StatCard 
                    icon={<FileText size={24} />}
                    label="Total Permisos"
                    value={stats.total}
                    color="#3B82F6"
                    gradient="linear-gradient(135deg, #3B82F6, #1D4ED8)"
                />
                <StatCard 
                    icon={<CheckCircle2 size={24} />}
                    label="Permisos Activos"
                    value={stats.active}
                    color="#16a34a"
                    gradient="linear-gradient(135deg, #16a34a, #059669)"
                />
                <StatCard 
                    icon={<Clock size={24} />}
                    label="Pendientes"
                    value={stats.pending}
                    color="#f59e0b"
                    gradient="linear-gradient(135deg, #f59e0b, #d97706)"
                />
                <StatCard 
                    icon={<CheckSquare size={24} />}
                    label="Completados"
                    value={stats.completed}
                    color="#8b5cf6"
                    gradient="linear-gradient(135deg, #8b5cf6, #7c3aed)"
                />
            </div>

            {/* Tabs */}
            <div style={{
                display: 'flex',
                gap: '0.5rem',
                marginBottom: '1.5rem',
                borderBottom: '2px solid var(--color-border)',
                paddingBottom: '0.5rem'
            }}>
                <TabButton 
                    active={activeTab === 'permits'}
                    onClick={() => setActiveTab('permits')}
                    icon={<FileText size={18} />}
                    label="Permisos"
                    count={permits.length}
                />
                <TabButton 
                    active={activeTab === 'active'}
                    onClick={() => setActiveTab('active')}
                    icon={<CheckCircle2 size={18} />}
                    label="Activos"
                    count={activePermits.length}
                    badge={activePermits.length}
                />
                <TabButton 
                    active={activeTab === 'limits'}
                    onClick={() => setActiveTab('limits')}
                    icon={<Activity size={18} />}
                    label="Límites"
                />
            </div>

            {/* Content by Tab */}
            {activeTab === 'permits' && (
                <>
                    {/* Search & Filters */}
                    <div style={{
                        display: 'flex',
                        gap: '1rem',
                        marginBottom: '1.5rem',
                        flexWrap: 'wrap'
                    }}>
                        <div style={{ flex: 1, minWidth: '280px', position: 'relative' }}>
                            <Search 
                                size={20} 
                                color="var(--color-text-muted)"
                                style={{
                                    position: 'absolute',
                                    left: '1rem',
                                    top: '50%',
                                    transform: 'translateY(-50%)',
                                    pointerEvents: 'none'
                                }}
                            />
                            <input
                                type="text"
                                placeholder="Buscar por espacio, ubicación..."
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                                style={{
                                    width: '100%',
                                    padding: '0.85rem 1rem 0.85rem 3rem',
                                    borderRadius: 'var(--radius-lg)',
                                    border: '1px solid var(--color-input-border)',
                                    background: 'var(--color-surface)',
                                    color: 'var(--color-text)',
                                    fontSize: '0.95rem',
                                    fontWeight: 500,
                                    outline: 'none'
                                }}
                            />
                        </div>

                        <select
                            value={filterStatus}
                            onChange={(e) => setFilterStatus(e.target.value)}
                            style={{
                                padding: '0.85rem 1.25rem',
                                borderRadius: 'var(--radius-lg)',
                                border: '1px solid var(--color-input-border)',
                                background: 'var(--color-surface)',
                                color: 'var(--color-text)',
                                fontSize: '0.9rem',
                                fontWeight: 600,
                                outline: 'none',
                                cursor: 'pointer'
                            }}
                        >
                            <option value="all">Todos los Estados</option>
                            {Object.entries(PERMIT_STATUS).map(([key, value]) => (
                                <option key={key} value={key}>{value.label}</option>
                            ))}
                        </select>
                    </div>

                    {/* Permits List */}
                    {filteredPermits.length === 0 ? (
                        <EmptyState onAdd={() => setShowAddModal(true)} />
                    ) : (
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
                            {filteredPermits.map(permit => (
                                <PermitCard 
                                    key={permit.id}
                                    permit={permit}
                                    statusConfig={PERMIT_STATUS[permit.status] || PERMIT_STATUS.draft}
                                    onAuthorize={() => authorizePermit(permit.id)}
                                    onSuspend={() => suspendPermit(permit.id)}
                                    onComplete={() => completePermit(permit.id)}
                                    onView={() => setSelectedPermit(permit)}
                                    onDelete={() => deletePermit(permit.id)}
                                />
                            ))}
                        </div>
                    )}
                </>
            )}

            {activeTab === 'active' && (
                <ActivePermitsList 
                    activePermits={activePermits}
                    onComplete={completePermit}
                    onSuspend={suspendPermit}
                    onView={setSelectedPermit}
                    onAddReading={(permit) => {
                        setCurrentPermitForReading(permit);
                        setShowAtmosphericModal(true);
                    }}
                />
            )}

            {activeTab === 'limits' && (
                <AtmosphericLimitsPanel limits={ATMOSPHERIC_LIMITS} />
            )}

            {/* Modal de Crear Permiso */}
            {showAddModal && (
                <CreatePermitModal 
                    permit={newPermit}
                    setPermit={setNewPermit}
                    onSave={handleCreatePermit}
                    onClose={() => {
                        setShowAddModal(false);
                        resetForm();
                    }}
                    CONFINED_SPACE_TYPES={CONFINED_SPACE_TYPES}
                    POTENTIAL_HAZARDS={POTENTIAL_HAZARDS}
                    EQUIPMENT_CHECKLIST={EQUIPMENT_CHECKLIST}
                    ROLES={ROLES}
                />
            )}

            {/* Modal de Detalle */}
            {selectedPermit && (
                <PermitDetailModal 
                    permit={selectedPermit}
                    statusConfig={PERMIT_STATUS[selectedPermit.status] || PERMIT_STATUS.draft}
                    onClose={() => setSelectedPermit(null)}
                    CONFINED_SPACE_TYPES={CONFINED_SPACE_TYPES}
                    POTENTIAL_HAZARDS={POTENTIAL_HAZARDS}
                    EQUIPMENT_CHECKLIST={EQUIPMENT_CHECKLIST}
                    ROLES={ROLES}
                />
            )}

            {/* Modal de Lectura Atmosférica */}
            {showAtmosphericModal && currentPermitForReading && (
                <AtmosphericReadingModal 
                    permit={currentPermitForReading}
                    onSave={addAtmosphericReading}
                    onClose={() => {
                        setShowAtmosphericModal(false);
                        setCurrentPermitForReading(null);
                    }}
                    limits={ATMOSPHERIC_LIMITS}
                />
            )}
        </div>
    );
}

// Componentes Auxiliares
function StatCard({ icon, label, value, color, gradient }) {
    return (
        <div className="card" style={{
            padding: '1.25rem',
            background: 'var(--gradient-card)',
            border: '1px solid var(--glass-border-subtle)',
            position: 'relative',
            overflow: 'hidden'
        }}>
            <div style={{
                position: 'absolute',
                top: '-20px',
                right: '-20px',
                width: '80px',
                height: '80px',
                background: gradient,
                borderRadius: '50%',
                opacity: 0.1
            }} />
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '0.75rem' }}>
                <div style={{
                    width: '48px',
                    height: '48px',
                    background: gradient,
                    borderRadius: 'var(--radius-lg)',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    boxShadow: `0 4px 15px ${color}40`
                }}>
                    {React.cloneElement(icon, { color: '#ffffff', size: 24 })}
                </div>
            </div>
            <div style={{ fontSize: '2rem', fontWeight: 900, color: 'var(--color-text)', lineHeight: 1 }}>
                {value}
            </div>
            <div style={{ fontSize: '0.85rem', fontWeight: 600, color: 'var(--color-text-muted)' }}>
                {label}
            </div>
        </div>
    );
}

function TabButton({ active, onClick, icon, label, count, badge }) {
    return (
        <button
            onClick={onClick}
            style={{
                display: 'flex',
                alignItems: 'center',
                gap: '0.5rem',
                padding: '0.75rem 1.25rem',
                background: active ? 'var(--color-primary)' : 'transparent',
                color: active ? '#fff' : 'var(--color-text-muted)',
                border: 'none',
                borderRadius: 'var(--radius-lg) var(--radius-lg) 0 0',
                cursor: 'pointer',
                fontWeight: 700,
                fontSize: '0.9rem',
                transition: 'all var(--transition-fast)',
                position: 'relative'
            }}
        >
            {icon}
            {label}
            {count !== undefined && (
                <span style={{
                    padding: '0.2rem 0.5rem',
                    background: active ? 'rgba(255,255,255,0.2)' : 'var(--color-background)',
                    borderRadius: 'var(--radius-full)',
                    fontSize: '0.75rem',
                    fontWeight: 800
                }}>
                    {count}
                </span>
            )}
            {badge > 0 && (
                <span style={{
                    position: 'absolute',
                    top: '-4px',
                    right: '-4px',
                    width: '20px',
                    height: '20px',
                    background: '#ef4444',
                    color: '#fff',
                    borderRadius: '50%',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontSize: '0.7rem',
                    fontWeight: 900
                }}>
                    {badge}
                </span>
            )}
        </button>
    );
}

function PermitCard({ permit, statusConfig, onAuthorize, onSuspend, onComplete, onView, onDelete }) {
    const spaceType = CONFINED_SPACE_TYPES.find(t => t.id === permit.spaceType);
    const isExpired = permit.validUntil && new Date(permit.validUntil) < new Date();

    return (
        <div className="card" style={{
            padding: '1.25rem',
            display: 'flex',
            alignItems: 'center',
            gap: '1rem',
            transition: 'all var(--transition-fast)',
            borderLeft: `4px solid ${isExpired ? '#9ca3af' : statusConfig.color}`
        }}>
            {/* Icono */}
            <div style={{
                width: '56px',
                height: '56px',
                background: `${isExpired ? '#9ca3af' : statusConfig.color}15`,
                borderRadius: 'var(--radius-xl)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                flexShrink: 0
            }}>
                <Tent size={28} color={isExpired ? '#9ca3af' : statusConfig.color} strokeWidth={2.5} />
            </div>

            {/* Información */}
            <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '0.5rem' }}>
                    <h3 style={{ 
                        margin: 0, 
                        fontSize: '1.1rem', 
                        fontWeight: 800,
                        color: 'var(--color-text)',
                        whiteSpace: 'nowrap',
                        overflow: 'hidden',
                        textOverflow: 'ellipsis'
                    }}>
                        {spaceType?.icon} {permit.spaceName}
                    </h3>
                    <span style={{
                        padding: '0.35rem 0.75rem',
                        background: statusConfig.bg,
                        color: statusConfig.color,
                        borderRadius: 'var(--radius-full)',
                        fontSize: '0.7rem',
                        fontWeight: 800,
                        textTransform: 'uppercase',
                        flexShrink: 0
                    }}>
                        {isExpired ? 'EXPIRADO' : statusConfig.label}
                    </span>
                </div>
                <div style={{ 
                    display: 'flex', 
                    flexWrap: 'wrap', 
                    gap: '1rem',
                    fontSize: '0.85rem',
                    color: 'var(--color-text-muted)',
                    fontWeight: 500
                }}>
                    <span style={{ display: 'flex', alignItems: 'center', gap: '0.35rem' }}>
                        <Tent size={14} />
                        {permit.location || 'Sin ubicación'}
                    </span>
                    <span style={{ display: 'flex', alignItems: 'center', gap: '0.35rem' }}>
                        <Users size={14} />
                        {permit.team?.entrants?.length || 0} entrantes
                    </span>
