                        <Calendar size={14} />
                        {permit.validUntil ? new Date(permit.validUntil).toLocaleDateString() : '-'}
                    </span>
                </div>
            </div>

            {/* Acciones */}
            <div style={{ display: 'flex', gap: '0.5rem' }}>
                {permit.status === 'pending' && (
                    <button
                        onClick={onAuthorize}
                        style={{
                            padding: '0.6rem 0.75rem',
                            background: '#16a34a',
                            border: 'none',
