                    >
                        <CheckCircle2 size={18} />
                    </button>
                )}
                {permit.status === 'active' && (
                    <>
                        <button
                            onClick={onSuspend}
                            style={{
                                padding: '0.6rem 0.75rem',
                                background: '#dc2626',
                                border: 'none',
                                borderRadius: 'var(--radius-md)',
                                cursor: 'pointer',
                                color: '#fff',
