                                    ? 'linear-gradient(135deg, #9ca3af, #6b7280)' 
                                    : 'linear-gradient(135deg, #16a34a, #059669)',
                                borderRadius: 'var(--radius-xl)',
                                display: 'flex',
                                flexDirection: 'column',
                                alignItems: 'center',
                                justifyContent: 'center',
