                                    {isExpired && (
                                        <span style={{
                                            padding: '0.35rem 0.75rem',
                                            background: '#9ca3af',
                                            color: '#fff',
                                            borderRadius: 'var(--radius-full)',
                                            fontSize: '0.7rem',
                                            fontWeight: 800,
                                            textTransform: 'uppercase'
                                        }}>
                                            EXPIRADO
                                        </span>
