                                    <span style={{
                                        padding: '0.35rem 0.65rem',
                                        background: '#f59e0b',
                                        color: '#fff',
                                        borderRadius: 'var(--radius-full)',
                                        fontSize: '0.75rem',
                                        fontWeight: 700
                                    }}>
                                        <Eye size={12} style={{ display: 'inline', marginRight: '4px' }} />
                                        {permit.atmosphericReadings?.length || 0} Mediciones
                                    </span>
                                    {!isExpired && (
                                        <span style={{
                                            padding: '0.35rem 0.65rem',
                                            background: '#16a34a',
                                            color: '#fff',
                                            borderRadius: 'var(--radius-full)',
                                            fontSize: '0.75rem',
                                            fontWeight: 700
                                        }}>
                                            <Clock size={12} style={{ display: 'inline', marginRight: '4px' }} />
