    // Estadísticas
    const stats = {
        total: measurements.length,
        normal: measurements.filter(m => m.status === 'normal').length,
        warning: measurements.filter(m => m.status === 'warning').length,
        critical: measurements.filter(m => m.status === 'critical').length,
