                <LimitsPanel parameters={PARAMETERS} />
            )}

            {/* Modal de Agregar Medición */}
            {showAddModal && (
                <AddMeasurementModal 
                    measurement={newMeasurement}
                    setMeasurement={setNewMeasurement}
                    onSave={handleAddMeasurement}
                    onClose={() => {
                        setShowAddModal(false);
                        resetForm();
                    }}
