                />
            )}

            {/* Modal de Detalle */}
            {selectedMeasurement && (
                <MeasurementDetailModal 
                    measurement={selectedMeasurement}
                    statusConfig={MEASUREMENT_STATUS[selectedMeasurement.status] || MEASUREMENT_STATUS.normal}
