                />
            )}

            <ShareModal 
                isOpen={showShareModal}
                onClose={() => setShowShareModal(false)}
                elementIdToPrint="pdf-content"
                title={selectedMeasurement ? "Protocolo de Monitoreo" : "Borrador de Monitoreo"}
