                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                )}

                {/* Condiciones Ambientales */}
                {(measurement.weather?.temperature || measurement.weather?.humidity || measurement.weather?.windSpeed) && (
                    <div style={{ marginBottom: '1.5rem' }}>
                        <h3 style={{ fontSize: '0.9rem', fontWeight: 800, marginBottom: '0.75rem', textTransform: 'uppercase' }}>
                            <Cloud size={16} style={{ display: 'inline', marginRight: '0.5rem' }} />
                            Condiciones Ambientales
                        </h3>
                        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '0.75rem' }}>
                            {measurement.weather.temperature && (
                                <div style={{ padding: '0.75rem', background: '#f8fafc', borderRadius: 'var(--radius-lg)', textAlign: 'center' }}>
                                    <Thermometer size={20} color="#f59e0b" style={{ margin: '0 auto 0.5rem' }} />
                                    <div style={{ fontSize: '0.75rem', color: 'var(--color-text-muted)' }}>Temperatura</div>
                                    <div style={{ fontSize: '1.25rem', fontWeight: 900 }}>{measurement.weather.temperature}°C</div>
                                </div>
                            )}
                            {measurement.weather.humidity && (
                                <div style={{ padding: '0.75rem', background: '#f8fafc', borderRadius: 'var(--radius-lg)', textAlign: 'center' }}>
                                    <Droplets size={20} color="#3b82f6" style={{ margin: '0 auto 0.5rem' }} />
                                    <div style={{ fontSize: '0.75rem', color: 'var(--color-text-muted)' }}>Humedad</div>
                                    <div style={{ fontSize: '1.25rem', fontWeight: 900 }}>{measurement.weather.humidity}%</div>
                                </div>
                            )}
                            {measurement.weather.windSpeed && (
                                <div style={{ padding: '0.75rem', background: '#f8fafc', borderRadius: 'var(--radius-lg)', textAlign: 'center' }}>
                                    <Wind size={20} color="#6b7280" style={{ margin: '0 auto 0.5rem' }} />
                                    <div style={{ fontSize: '0.75rem', color: 'var(--color-text-muted)' }}>Viento</div>
                                    <div style={{ fontSize: '1.25rem', fontWeight: 900 }}>{measurement.weather.windSpeed} km/h</div>
                                </div>
                            )}
                        </div>
                    </div>
                )}

                {/* Información Adicional */}
                <div style={{
                    display: 'grid',
                    gridTemplateColumns: '1fr 1fr',
                    gap: '1rem',
                    marginBottom: '1.5rem'
                }}>
                    <InfoDetail label="Fecha" value={measurement.measurementDate ? new Date(measurement.measurementDate).toLocaleDateString() : '-'} />
                    <InfoDetail label="Hora" value={measurement.measurementTime || '-'} />
                    <InfoDetail label="Técnico" value={measurement.technician || '-'} />
                    <InfoDetail label="Equipo" value={measurement.equipment || '-'} />
                </div>

                {/* Observaciones */}
                {measurement.observations && (
                    <div style={{
                        padding: '1rem',
                        background: 'var(--color-background)',
                        borderRadius: 'var(--radius-lg)',
                        marginBottom: '1.5rem'
                    }}>
                        <h4 style={{ margin: '0 0 0.5rem 0', fontSize: '0.85rem', fontWeight: 700 }}>
                            Observaciones
                        </h4>
                        <p style={{ margin: 0, fontSize: '0.9rem', color: 'var(--color-text)', lineHeight: 1.6 }}>
                            {measurement.observations}
                        </p>
                    </div>
                )}

                <div style={{ display: 'flex', gap: '1rem', marginTop: '1rem' }}>
                    <button
                        onClick={() => {
                            setShowShareModal(true);
                        }}
                        style={{
                            flex: 1,
                            padding: '1rem',
                            background: 'var(--color-surface)',
                            border: '1px solid var(--color-primary)',
                            borderRadius: 'var(--radius-lg)',
                            fontWeight: 700,
                            cursor: 'pointer',
                            color: 'var(--color-primary)',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            gap: '0.5rem'
                        }}
                    >
                        <Printer size={18} />
                        Imprimir / PDF
                    </button>
                    <button
                        onClick={onClose}
                        className="btn-primary"
                        style={{ flex: 1, margin: 0 }}
                    >
                        Cerrar
                    </button>
                </div>
            </div>
        </div>
    );
}

function InfoDetail({ label, value }) {
    return (
        <div>
            <div style={{ fontSize: '0.7rem', fontWeight: 700, color: 'var(--color-text-muted)', textTransform: 'uppercase', marginBottom: '0.25rem' }}>
                {label}
            </div>
            <div style={{ fontSize: '0.95rem', fontWeight: 600, color: 'var(--color-text)' }}>
                {value}
            </div>
        </div>
    );
}

const labelStyle = {
    display: 'block',
    fontSize: '0.8rem',
    fontWeight: 700,
    color: 'var(--color-text-muted)',
    textTransform: 'uppercase',
    marginBottom: '0.5rem'
};

const inputStyle = {
    width: '100%',
    padding: '0.75rem 1rem',
    borderRadius: 'var(--radius-lg)',
    border: '1px solid var(--color-input-border)',
    background: 'var(--color-surface)',
    color: 'var(--color-text)',
    fontSize: '0.95rem',
    fontWeight: 500,
    outline: 'none',
    transition: 'all var(--transition-fast)',
    boxSizing: 'border-box'
};

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { ArrowLeft, Plus, Search, CheckCircle2, XCircle, Clock, User, Calendar, AlertTriangle, Leaf, Eye, Trash2, Activity, Droplets, Wind } from 'lucide-react';

const MONITORING_TYPES = [{ id: 'air', name: 'Calidad de Aire', icon: '💨' }, { id: 'water', name: 'Calidad de Agua', icon: '💧' }, { id: 'noise', name: 'Ruido', icon: '🔊' }, { id: 'waste', name: 'Residuos', icon: '♻️' }, { id: 'emissions', name: 'Emisiones', icon: '🏭' }, { id: 'soil', name: 'Suelo', icon: '🌱' }];
const STATUS = { normal: { label: 'NORMAL', color: '#16a34a', bg: '#f0fdf4' }, warning: { label: 'PRECAUCIÓN', color: '#f59e0b', bg: '#fffbeb' }, critical: { label: 'CRÍTICO', color: '#dc2626', bg: '#fef2f2' } };

export default function EnvironmentalPage() {
    const navigate = useNavigate();
    const [measurements, setMeasurements] = useState([]);
    const [searchTerm, setSearchTerm] = useState('');
    const [selected, setSelected] = useState(null);
    const [isMobile, setIsMobile] = useState(false);

    useEffect(() => { const h = () => setIsMobile(window.innerWidth < 768); h(); window.addEventListener('resize', h); const s = localStorage.getItem('environmental_measurements_db'); if (s) setMeasurements(JSON.parse(s)); return () => window.removeEventListener('resize', h); }, []);
    const save = (d) => { localStorage.setItem('environmental_measurements_db', JSON.stringify(d)); setMeasurements(d); };
    const del = (id) => { if (confirm('¿Eliminar?')) save(measurements.filter(m => m.id !== id)); };
    const filtered = measurements.filter(m => m.stationName.toLowerCase().includes(searchTerm.toLowerCase()));
    const stats = { total: measurements.length, normal: measurements.filter(m => m.status === 'normal').length, warning: measurements.filter(m => m.status === 'warning').length, critical: measurements.filter(m => m.status === 'critical').length };

    return (
        <div style={{ minHeight: '100vh', background: 'var(--color-background)', paddingBottom: isMobile ? '80px' : '2rem' }}>
            <div style={{ background: 'var(--color-surface)', borderBottom: '1px solid var(--color-border)', padding: isMobile ? '1rem' : '1.5rem', position: 'sticky', top: 0, zIndex: 100, backdropFilter: 'blur(20px)' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', maxWidth: '1400px', margin: '0 auto' }}>
                    <button onClick={() => navigate(-1)} style={{ padding: '0.5rem', background: 'var(--color-background)', border: '1px solid var(--color-border)', borderRadius: 'var(--radius-lg)', cursor: 'pointer', color: 'var(--color-text)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><ArrowLeft size={20} /></button>
                    <div style={{ flex: 1 }}>
                        <h1 style={{ margin: 0, fontSize: isMobile ? '1.25rem' : '1.5rem', fontWeight: 900 }}><Leaf size={isMobile ? 20 : 24} style={{ display: 'inline', marginRight: '0.5rem', verticalAlign: 'middle' }} />Monitoreo Ambiental</h1>
                        <p style={{ margin: '0.25rem 0 0 0', fontSize: '0.85rem', color: 'var(--color-text-muted)' }}>ISO 14001 • {measurements.length} mediciones</p>
                    </div>
                    <button onClick={() => navigate('/environmental/new')} className="btn-primary" style={{ width: 'auto', margin: 0, padding: '0.75rem 1.25rem', display: 'flex', alignItems: 'center', gap: '0.5rem' }}><Plus size={20} strokeWidth={2.5} />{!isMobile && 'Nueva Medición'}</button>
                </div>
            </div>
            <div style={{ marginTop: isMobile ? '1rem' : '1.5rem' }}>
            <div style={{ display: 'grid', gridTemplateColumns: isMobile ? 'repeat(2, 1fr)' : 'repeat(4, 1fr)', gap: '1rem', padding: isMobile ? '1rem' : '1.5rem', maxWidth: '1400px', margin: '0 auto' }}>
                <StatCard label="Total" value={stats.total} color="#3B82F6" icon={<Activity size={20} />} />
                <StatCard label="Normales" value={stats.normal} color="#16a34a" icon={<CheckCircle2 size={20} />} />
                <StatCard label="Precaución" value={stats.warning} color="#f59e0b" icon={<AlertTriangle size={20} />} />
                <StatCard label="Críticas" value={stats.critical} color="#dc2626" icon={<AlertTriangle size={20} />} />
            </div>
            {isMobile && (<div style={{ padding: '0 1rem 1rem', display: 'flex', gap: '0.75rem' }}><div style={{ flex: 1, position: 'relative' }}><Search size={18} color="var(--color-text-muted)" style={{ position: 'absolute', left: '1rem', top: '50%', transform: 'translateY(-50%)' }} /><input type="text" placeholder="Buscar..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} style={{ width: '100%', padding: '0.75rem 1rem 0.75rem 2.5rem', borderRadius: 'var(--radius-lg)', border: '1px solid var(--color-border)', background: 'var(--color-surface)', fontSize: '0.95rem' }} /></div><button onClick={() => navigate('/environmental/new')} className="btn-primary" style={{ width: 'auto', margin: 0, padding: '0 1rem', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><Plus size={20} /></button></div>)}
            <div style={{ padding: isMobile ? '0 1rem' : '0 1.5rem', maxWidth: '1400px', margin: '0 auto', display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
                {filtered.length === 0 ? <EmptyState onAdd={() => navigate('/environmental/new')} isMobile={isMobile} /> : filtered.map(m => (<MeasurementCard key={m.id} measurement={m} statusConfig={STATUS[m.status] || STATUS.normal} onView={() => setSelected(m)} onDelete={() => del(m.id)} isMobile={isMobile} />))}
            </div>
            </div>
            {selected && <DetailModal measurement={selected} onClose={() => setSelected(null)} isMobile={isMobile} />}
        </div>
    );
}
function StatCard({ label, value, color, icon }) { return (<div className="card" style={{ padding: '1.25rem', background: 'var(--gradient-card)', border: '1px solid var(--glass-border-subtle)', display: 'flex', alignItems: 'center', gap: '1rem' }}><div style={{ width: '48px', height: '48px', background: `linear-gradient(135deg, ${color}, ${color}cc)`, borderRadius: 'var(--radius-lg)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#fff' }}>{icon}</div><div><div style={{ fontSize: '0.85rem', fontWeight: 600, color: 'var(--color-text-muted)' }}>{label}</div><div style={{ fontSize: '2rem', fontWeight: 900, color: 'var(--color-text)', lineHeight: 1 }}>{value}</div></div></div>); }
