                        ))}
                    </div>
                </div>

                {/* Pasos del Procedimiento */}
                <div style={{ marginTop: '1.5rem' }}>
                    <label style={labelStyle}>Pasos del Procedimiento (OSHA 1910.147)</label>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                        {LOTO_STEPS.map((step, idx) => (
                            <div key={step.id} style={{
                                padding: '0.75rem 1rem',
                                background: 'var(--color-background)',
                                border: '1px solid var(--color-border)',
                                borderRadius: 'var(--radius-lg)',
                                display: 'flex',
                                alignItems: 'center',
                                gap: '1rem'
                            }}>
                                <div style={{
                                    width: '32px',
                                    height: '32px',
                                    background: 'var(--color-primary)',
                                    color: '#fff',
                                    borderRadius: '50%',
                                    display: 'flex',
                                    alignItems: 'center',
                                    justifyContent: 'center',
                                    fontWeight: 900,
                                    fontSize: '0.9rem'
                                }}>
                                    {step.id}
                                </div>
                                <div style={{ flex: 1 }}>
                                    <div style={{ fontWeight: 800, fontSize: '0.95rem' }}>{step.name}</div>
                                    <div style={{ fontSize: '0.8rem', color: 'var(--color-text-muted)' }}>{step.description}</div>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Observaciones */}
                <div style={{ marginTop: '1.5rem' }}>
                    <label style={labelStyle}>Observaciones Adicionales</label>
                    <textarea
                        value={procedure.observations}
                        onChange={(e) => setProcedure({ ...procedure, observations: e.target.value })}
                        style={{ ...inputStyle, minHeight: '80px', resize: 'vertical' }}
                        placeholder="Información adicional sobre el procedimiento..."
                    />
                </div>

                <div style={{
                    display: 'flex',
                    gap: '1rem',
                    marginTop: '2rem',
                    paddingTop: '1.5rem',
                    borderTop: '1px solid var(--color-border)'
                }}>
                    <button
                        onClick={onClose}
                        style={{
                            flex: 1,
                            padding: '0.85rem',
                            background: 'var(--color-background)',
                            border: '1px solid var(--color-border)',
                            borderRadius: 'var(--radius-lg)',
                            fontWeight: 700,
                            cursor: 'pointer'
                        }}
                    >
                        Cancelar
                    </button>
                    <button
                        onClick={onSave}
                        className="btn-primary"
                        style={{ flex: 1 }}
                    >
                        Crear Procedimiento
                    </button>
                </div>
            </div>
        </div>
    );
}

