import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import {
    ArrowLeft, Save, Printer, Building2, User, Calendar,
    CheckCircle2, AlertCircle, Info, Pencil, TriangleAlert,
    ChevronRight, Share2, FileText, ShieldCheck, Camera,
    ShieldAlert
} from 'lucide-react';
import { useAuth } from '../contexts/AuthContext';
import ShareModal from '../components/ShareModal';
import { usePaywall } from '../hooks/usePaywall';
import toast from 'react-hot-toast';
import CompanyLogo from '../components/CompanyLogo';

export default function Report() {
    const navigate = useNavigate();
    const { currentUser } = useAuth();
    const { requirePro } = usePaywall();
    const [showShare, setShowShare] = useState(false);
    const [inspectionData, setInspectionData] = useState(null);
    const [riskAssessment, setRiskAssessment] = useState(null);
    const [professional, setProfessional] = useState(null);
    const [showSignatures, setShowSignatures] = useState({
        operator: true,
        supervisor: true,
        professional: true
    });

    useEffect(() => {
        // Load inspection data and update history if not already final
        const current = localStorage.getItem('current_inspection');
        if (current) {
            const inspection = JSON.parse(current);
            setInspectionData(inspection);

            // Update history with latest inspection data and mark as final
            const historyRaw = localStorage.getItem('inspections_history');
            const history = historyRaw ? JSON.parse(historyRaw) : [];

            const existingIndex = history.findIndex(item => item.id === inspection.id);
            if (existingIndex >= 0) {
                // Update with latest changes even if already final
                history[existingIndex] = { ...inspection, status: 'Finalizada' };
                localStorage.setItem('inspections_history', JSON.stringify(history));
            } else {
                const updatedHistory = [{ ...inspection, status: 'Finalizada' }, ...history];
                localStorage.setItem('inspections_history', JSON.stringify(updatedHistory));
            }
        }

        // Load Risk Assessment (IPER)
        const iper = localStorage.getItem('risk_assessment');
        if (iper) {
            setRiskAssessment(JSON.parse(iper));
        }

        // Load professional data
        const savedData = localStorage.getItem('personalData');
        const savedSigData = localStorage.getItem('signatureStampData');
        const legacySignature = localStorage.getItem('capturedSignature');

        let signature = legacySignature || null;
        if (savedSigData) {
            const parsed = JSON.parse(savedSigData);
            signature = parsed.signature || signature;
        }

        if (savedData) {
            const data = JSON.parse(savedData);
            setProfessional({
                name: data.name || 'Profesional',
                license: data.license || '',
                signature: signature
            });
        }
    }, []);

    const handlePrint = () => requirePro(() => window.print());

    if (!inspectionData) {
        return (
            <div className="container" style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '80vh', textAlign: 'center' }}>
                <AlertCircle size={48} color="#ef4444" style={{ marginBottom: '1.5rem' }} />
                <h1 style={{ fontSize: '1.5rem', fontWeight: 800, marginBottom: '0.5rem' }}>Datos no encontrados</h1>
                <p style={{ color: 'var(--color-text-muted)', marginBottom: '2rem', maxWidth: '400px' }}>
                    No se ha podido recuperar la información del relevamiento actual. 
                    Por favor, regrese a la lista de control e intente nuevamente.
                </p>
                <button 
                    onClick={() => navigate('/checklist')}
                    className="btn-primary"
                    style={{ padding: '0.8rem 2rem' }}
                >
                    Volver a la Lista
                </button>
            </div>
        );
    }

    const findings = inspectionData.observations || [];
    const findingCount = findings.length;

    return (
        <div className="container" style={{ paddingBottom: '5rem', maxWidth: '1000px' }}>
            {/* Action Bar (No Print) */}
            <div className="no-print" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                    <button onClick={() => navigate('/')} style={{ padding: '0.8rem', background: 'var(--color-surface)', border: '1px solid var(--color-border)', borderRadius: '12px', cursor: 'pointer', color: 'var(--color-text)', display: 'flex' }}>
                        <ArrowLeft size={20} />
                    </button>
                    <div>
                        <h1 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 800 }}>Informe de Inspección</h1>
                        <p style={{ margin: 0, fontSize: '0.85rem', color: 'var(--color-text-muted)' }}>ID #{inspectionData.id?.toString().slice(-6)}</p>
                    </div>
                </div>
                <div style={{ display: 'flex', gap: '0.8rem' }}>
                    <button onClick={() => requirePro(() => setShowShare(true))} className="btn-outline" style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', padding: '0.8rem 1.2rem', borderRadius: '12px' }}>
                        <Share2 size={18} /> <span>Compartir</span>
                    </button>
                    <button onClick={handlePrint} className="btn-primary" style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', padding: '0.8rem 1.5rem', borderRadius: '12px', width: 'auto' }}>
                        <Printer size={18} /> <span>PDF / Imprimir</span>
                    </button>
                </div>
            </div>

            <ShareModal
                open={showShare}
                onClose={() => setShowShare(false)}
                title="Informe de Inspección"
                text={`📋 Informe de Inspección\n🏗️ Obra: ${inspectionData.name}\n📅 Fecha: ${new Date(inspectionData.date).toLocaleDateString()}\n⚠️ Hallazgos: ${findingCount}\n\nGenerado con Asistente H&S`}
                elementIdToPrint="pdf-content"
            />

            {/* PRINTABLE AREA */}
            <div id="pdf-content" className="bg-white text-black p-4 md:p-12 shadow-sm border border-slate-200 rounded-2xl print-area print:mb-0 print:border-none print:shadow-none">
                {/* Header Section */}
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 2fr 1fr', alignItems: 'center', borderBottom: '4px solid var(--color-primary)', paddingBottom: '1.5rem', marginBottom: '2rem', width: '100%', gap: '1.5rem' }}>
                    <div style={{ textAlign: 'left' }}>
                        <p style={{ margin: 0, fontWeight: 700, fontSize: '0.65rem', textTransform: 'uppercase', color: '#64748b', letterSpacing: '0.05em' }}>Sistema de Gestión</p>
                        <p style={{ margin: 0, fontWeight: 900, fontSize: '0.75rem', textTransform: 'uppercase', color: '#1e293b' }}>Control H&S</p>
                    </div>

                    <div style={{ textAlign: 'center' }}>
                        <h2 style={{ margin: 0, fontSize: '1.2rem', fontWeight: 900, color: 'var(--color-primary)', textTransform: 'uppercase', letterSpacing: '1px', lineHeight: 1.2 }}>
                            Informe Técnico de Inspección
                        </h2>
                        <p style={{ margin: '4px 0 0 0', fontSize: '0.65rem', color: '#64748b', fontWeight: 600 }}>Protocolo de Relevamiento General de Riesgos</p>
                    </div>

                    <div style={{ display: 'flex', justifyContent: 'flex-end' }}>
                        <CompanyLogo style={{ height: '45px', width: 'auto', maxWidth: '140px', objectFit: 'contain' }} />
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8 bg-slate-50 p-5 rounded-xl border border-slate-200">
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                        <div><span style={{ fontSize: '0.7rem', color: '#64748b', fontWeight: 700, textTransform: 'uppercase' }}>FECHA:</span> <span style={{ fontWeight: 800, fontSize: '0.9rem' }}>{new Date(inspectionData.date).toLocaleDateString('es-AR')}</span></div>
                        <div><span style={{ fontSize: '0.7rem', color: '#64748b', fontWeight: 700, textTransform: 'uppercase' }}>REFERENCIA:</span> <span style={{ fontWeight: 800, fontSize: '0.9rem' }}>{inspectionData.name}</span></div>
                    </div>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                         <div><span style={{ fontSize: '0.7rem', color: '#64748b', fontWeight: 700, textTransform: 'uppercase' }}>UBICACIÓN:</span> <span style={{ fontWeight: 800, fontSize: '0.9rem' }}>{inspectionData.location || '-'}</span></div>
                         <div><span style={{ fontSize: '0.7rem', color: '#64748b', fontWeight: 700, textTransform: 'uppercase' }}>ESTADO:</span> <span style={{ fontWeight: 800, fontSize: '0.9rem', color: 'var(--color-primary)' }}>FINALIZADO</span></div>
                    </div>
                </div>

                {/* Summary Cards */}
                <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-10">
                    <div className="card" style={{ padding: '1.2rem', textAlign: 'center', background: '#f8fafc', border: '1px solid #e2e8f0' }}>
                        <div style={{ fontSize: '1.5rem', fontWeight: 900, color: '#172B4D' }}>{findingCount}</div>
                        <div style={{ fontSize: '0.75rem', fontWeight: 800, color: '#6B778C', textTransform: 'uppercase', letterSpacing: '0.5px' }}>Hallazgos</div>
                    </div>
                    <div className="card" style={{ padding: '1.2rem', textAlign: 'center', background: '#f8fafc', border: '1px solid #e2e8f0' }}>
                        <div style={{ fontSize: '1.5rem', fontWeight: 900, color: '#172B4D' }}>
                            {(() => {
                                const categories = [
                                    { items: ['e1', 'e2'] },
                                    { items: ['L1', 'L2'] },
                                    { items: ['p1', 'p2'] },
                                    { items: ['o1', 'o2'] },
                                    { items: ['s1', 's2'] }
                                ];
                                const allItems = categories.flatMap(c => c.items);
                                const total = allItems.length;
                                const okCount = allItems.filter(id => inspectionData.responses?.[id] === 'ok').length;
                                return Math.round((okCount / total) * 100) || 0;
                            })()}%
                        </div>
                        <div style={{ fontSize: '0.75rem', fontWeight: 800, color: '#6B778C', textTransform: 'uppercase', letterSpacing: '0.5px' }}>Cumplimiento</div>
                    </div>
                    <div className="card md:col-span-2" style={{ padding: '1.2rem', background: '#f8fafc', border: '1px solid #e2e8f0' }}>
                        <div style={{ fontSize: '0.85rem', fontWeight: 800, color: '#6B778C', marginBottom: '0.3rem' }}>PROFESIONAL ACTUANTE</div>
                        <div style={{ fontSize: '1.1rem', color: 'var(--color-primary)', fontWeight: 900 }}>{professional?.name || 'No especificado'}</div>
                        {professional?.license && <div style={{ fontSize: '0.7rem', fontWeight: 600, color: '#6B778C' }}>MATRÍCULA: {professional.license}</div>}
                    </div>
                </div>

                {/* Checklist Summary Section */}
                <h3 style={{ fontSize: '1.2rem', fontWeight: 900, marginBottom: '1.2rem', display: 'flex', alignItems: 'center', gap: '0.6rem', color: '#172B4D' }}>
                    <ShieldCheck size={24} color="#00875A" /> Resumen de Inspección por Áreas
                </h3>
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))', gap: '1rem', marginBottom: '3rem' }}>
                    {[
                        { name: 'Extintores y Protección', id: 'extintores', items: ['e1', 'e2'] },
                        { name: 'Riesgo Eléctrico', id: 'electrico', items: ['L1', 'L2'] },
                        { name: 'EPP', id: 'epp', items: ['p1', 'p2'] },
                        { name: 'Orden y Limpieza', id: 'orden', items: ['o1', 'o2'] },
                        { name: 'Señalización y Evacuación', id: 'senyalizacion', items: ['s1', 's2'] }
                    ].map(cat => {
                        const total = cat.items.length;
                        const ok = cat.items.filter(id => inspectionData.responses?.[id] === 'ok').length;
                        // For fail, we check responses OR if there's an observation for this item
                        const fail = cat.items.filter(id => {
                            const isResponseFail = inspectionData.responses?.[id] === 'fail';
                            const hasObservation = inspectionData.observations?.some(o => o.itemId === id);
                            return isResponseFail || hasObservation;
                        }).length;
                        
                        const percent = Math.round((ok / total) * 100) || 0;

                        return (
                            <div key={cat.id} style={{ padding: '1.2rem', background: '#f8fafc', borderRadius: '16px', border: '1px solid #e2e8f0', pageBreakInside: 'avoid' }}>
                                <div style={{ fontSize: '0.85rem', fontWeight: 900, color: '#172B4D', marginBottom: '0.8rem' }}>{cat.name}</div>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '0.8rem', marginBottom: '0.5rem', pageBreakInside: 'avoid' }}>
                                    <div style={{ flex: 1, height: '8px', background: '#e2e8f0', borderRadius: '4px', overflow: 'hidden' }}>
                                        <div style={{ width: `${percent}%`, height: '100%', background: percent === 100 ? '#00875A' : '#3b82f6', transition: 'width 0.5s ease' }}></div>
                                    </div>
                                    <span style={{ fontSize: '0.8rem', fontWeight: 900, color: '#172B4D' }}>{percent}%</span>
                                </div>
                                <div style={{ fontSize: '0.75rem', color: '#6B778C', fontWeight: 800, display: 'flex', justifyContent: 'space-between' }}>
                                    <span style={{ color: '#00875A' }}>✓ {ok} OK</span>
                                    <span style={{ color: fail > 0 ? '#ef4444' : '#6B778C', fontWeight: fail > 0 ? 900 : 800 }}>
                                        {fail > 0 ? '✕' : ''} {fail} Fallos
                                    </span>
                                </div>
                            </div>
                        );
                    })}
                </div>

                {/* Risk Assessment Integrated Section */}
                {riskAssessment && riskAssessment.length > 0 && (
                    <div style={{ pageBreakInside: 'avoid', marginBottom: '3rem' }}>
                        <h3 style={{ fontSize: '1.2rem', fontWeight: 900, marginBottom: '1.2rem', display: 'flex', alignItems: 'center', gap: '0.6rem', color: '#172B4D' }}>
                            <ShieldAlert size={24} color="#FF991F" /> Evaluación de Riesgos Previa (IPER)
                        </h3>
                        <div style={{ overflowX: 'auto' }}>
                            <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.85rem' }}>
                                <thead>
                                    <tr style={{ background: '#f8fafc', borderBottom: '2px solid #e2e8f0' }}>
                                        <th style={{ padding: '1rem', textAlign: 'left', fontWeight: 900 }}>Peligro Identificado</th>
                                        <th style={{ padding: '1rem', textAlign: 'left', fontWeight: 900 }}>Riesgo Asociado</th>
                                        <th style={{ padding: '1rem', textAlign: 'center', fontWeight: 900 }}>Probabilidad / Severidad</th>
                                        <th style={{ padding: '1rem', textAlign: 'center', fontWeight: 900 }}>Nivel</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {riskAssessment.map((risk, idx) => (
                                        <tr key={idx} style={{ borderBottom: '1px solid #f1f5f9', pageBreakInside: 'avoid' }}>
                                            <td style={{ padding: '1rem', fontWeight: 600 }}>{risk.danger}</td>
                                            <td style={{ padding: '1rem' }}>{risk.risk}</td>
                                            <td style={{ padding: '1rem', textAlign: 'center' }}>{risk.probability} x {risk.severity}</td>
                                            <td style={{ padding: '1rem', textAlign: 'center' }}>
                                                <span style={{
                                                    fontSize: '0.7rem',
                                                    fontWeight: 900,
                                                    padding: '0.3rem 0.6rem',
                                                    borderRadius: '8px',
                                                    background: risk.score > 15 ? '#fee2e2' : risk.score > 8 ? '#ffedd5' : '#dcfce7',
                                                    color: risk.score > 15 ? '#b91c1c' : risk.score > 8 ? '#9a3412' : '#15803d',
                                                }}>
                                                    {risk.level || (risk.score > 15 ? 'ALTO' : risk.score > 8 ? 'MEDIO' : 'BAJO')}
                                                </span>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}

                {/* Findings Table */}
                <h3 style={{ fontSize: '1.2rem', fontWeight: 900, marginBottom: '1.2rem', display: 'flex', alignItems: 'center', gap: '0.6rem', color: '#172B4D' }}>
                    <TriangleAlert size={24} color="#DC2626" /> Detalle de Hallazgos y Desvíos
                </h3>

                {findings.length > 0 ? (
                    <div style={{ overflowX: 'auto', marginBottom: '3rem' }}>
                        <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.9rem' }}>
                            <thead>
                                <tr style={{ background: '#f8fafc', borderBottom: '2px solid #e2e8f0' }}>
                                    <th style={{ padding: '1rem', textAlign: 'left', fontWeight: 900, width: '40px' }}>#</th>
                                    <th style={{ padding: '1rem', textAlign: 'left', fontWeight: 900 }}>Descripción de la Anomalía</th>
                                    <th style={{ padding: '1rem', textAlign: 'center', fontWeight: 900 }}>Riesgo</th>
                                    <th style={{ padding: '1rem', textAlign: 'left', fontWeight: 900 }}>Acción Correctiva / Responsable</th>
                                    <th style={{ padding: '1rem', textAlign: 'center', fontWeight: 900 }}>Evidencia</th>
                                </tr>
                            </thead>
                            <tbody>
                                {findings.map((obs, i) => (
                                    <tr key={i} style={{ borderBottom: '1px solid #f1f5f9', pageBreakInside: 'avoid' }}>
                                        <td style={{ padding: '1rem', fontWeight: 800, color: '#6B778C' }}>{i + 1}</td>
                                        <td style={{ padding: '1rem' }}>
                                            <div style={{ fontWeight: 800, color: '#172B4D', marginBottom: '0.2rem' }}>{obs.category}</div>
                                            <div style={{ fontSize: '0.85rem', color: '#444' }}>{obs.description}</div>
                                        </td>
                                        <td style={{ padding: '1rem', textAlign: 'center' }}>
                                            <span style={{
                                                fontSize: '0.7rem',
                                                fontWeight: 900,
                                                padding: '0.3rem 0.6rem',
                                                borderRadius: '8px',
                                                background: obs.severity === 'Crítica' ? '#fee2e2' : obs.severity === 'Moderada' ? '#ffedd5' : '#dcfce7',
                                                color: obs.severity === 'Crítica' ? '#dc2626' : obs.severity === 'Moderada' ? '#9a3412' : '#15803d',
                                                border: '1px solid currentColor'
                                            }}>
                                                {obs.severity?.toUpperCase()}
                                            </span>
                                        </td>
                                        <td style={{ padding: '1rem' }}>
                                            <div style={{ fontSize: '0.85rem' }}>
                                                <strong>Plazo:</strong> {obs.deadline}<br/>
                                                <strong>Responsable:</strong> {obs.assignee || 'A designar'}
                                            </div>
                                        </td>
                                        <td style={{ padding: '1rem', textAlign: 'center' }}>
                                            <div style={{ display: 'flex', gap: '4px', flexWrap: 'wrap', justifyContent: 'center' }}>
                                                {(obs.photos || (obs.photo ? [obs.photo] : [])).map((img, idx) => (
                                                    <img 
                                                        key={idx} 
                                                        src={img} 
                                                        alt="Hallazgo" 
                                                        style={{ width: '45px', height: '45px', objectFit: 'cover', borderRadius: '6px', border: '1px solid #e2e8f0', cursor: 'pointer' }} 
                                                        onClick={() => window.open(img, '_blank')}
                                                    />
                                                ))}
                                                {!(obs.photos?.length || obs.photo) && <span style={{ color: '#cbd5e1', fontSize: '0.7rem' }}>Sin fotos</span>}
                                            </div>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                ) : (
                    <div className="card" style={{ padding: '2.5rem', textAlign: 'center', background: '#f0fdf4', border: '1px solid #bbf7d0', color: '#166534', marginBottom: '3rem' }}>
                        <CheckCircle2 size={40} style={{ marginBottom: '0.8rem', opacity: 0.8 }} />
                        <p style={{ margin: 0, fontSize: '1.2rem', fontWeight: 900 }}>Relevamiento sin desvíos críticos</p>
                        <p style={{ margin: '0.5rem 0 0 0', fontSize: '0.95rem', fontWeight: 600 }}>Las condiciones observadas se ajustan a las normativas de seguridad vigentes.</p>
                    </div>
                )}

                {/* Photo Gallery (General Evidence) */}
                {inspectionData.photos && inspectionData.photos.length > 0 && (
                    <div style={{ marginTop: '4rem', pageBreakBefore: 'auto' }}>
                        <h3 style={{ fontSize: '1.2rem', fontWeight: 900, marginBottom: '1.5rem', display: 'flex', alignItems: 'center', gap: '0.6rem', color: '#172B4D', borderBottom: '2px solid #f1f5f9', paddingBottom: '0.8rem' }}>
                            <Camera size={24} color="var(--color-primary)" /> Registro Fotográfico General de la Visita
                        </h3>
                        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '2rem' }}>
                            {inspectionData.photos.map((photo, index) => (
                                <div key={index} style={{ border: '1px solid #e2e8f0', borderRadius: '20px', overflow: 'hidden', padding: '0.8rem', background: '#f8fafc', pageBreakInside: 'avoid', boxShadow: '0 4px 12px rgba(0,0,0,0.05)' }}>
                                    <img src={photo} alt={`Evidencia ${index + 1}`} style={{ width: '100%', height: '260px', objectFit: 'cover', borderRadius: '12px', marginBottom: '0.8rem' }} />
                                    <p style={{ margin: 0, fontSize: '0.8rem', fontWeight: 800, textAlign: 'center', color: '#6B778C', textTransform: 'uppercase', letterSpacing: '1px' }}>Evidencia Fotográfica #{index + 1}</p>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                {/* Signatures Section */}
                <div style={{ marginTop: '5rem' }}>
                    <div className="no-print mb-10 p-6 bg-blue-50/50 border border-blue-100 rounded-2xl w-full flex flex-col md:flex-row gap-6 justify-center items-center text-sm font-bold text-blue-900 shadow-sm">
                        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}><Info size={20}/> CONFIGURAR FIRMAS PARA EL PDF:</div>
                        <div className="flex gap-6 flex-wrap justify-center">
                            <label className="flex items-center gap-3 cursor-pointer p-2 hover:bg-white rounded-lg transition-colors">
                                <input type="checkbox" checked={showSignatures.operator} onChange={e => setShowSignatures(s => ({ ...s, operator: e.target.checked }))} className="w-5 h-5 accent-blue-600" /> Operador
                            </label>
                            <label className="flex items-center gap-3 cursor-pointer p-2 hover:bg-white rounded-lg transition-colors">
                                <input type="checkbox" checked={showSignatures.supervisor} onChange={e => setShowSignatures(s => ({ ...s, supervisor: e.target.checked }))} className="w-5 h-5 accent-blue-600" /> Supervisor
                            </label>
                            <label className="flex items-center gap-3 cursor-pointer p-2 hover:bg-white rounded-lg transition-colors">
                                <input type="checkbox" checked={showSignatures.professional} onChange={e => setShowSignatures(s => ({ ...s, professional: e.target.checked }))} className="w-5 h-5 accent-blue-600" /> Profesional
                            </label>
                        </div>
                    </div>

                    <div className="signature-container-row mt-12" style={{ pageBreakInside: 'avoid', gap: '40px' }}>
                        {showSignatures.operator && (
                            <div className="signature-item-box" style={{ flex: 1, textAlign: 'center' }}>
                                <div style={{ height: '80px' }}></div>
                                <div className="signature-line" style={{ borderTop: '2px solid #172B4D', width: '200px', margin: '0 auto 12px auto' }}></div>
                                <p style={{ fontSize: '0.75rem', fontWeight: 900, color: '#6B778C', textTransform: 'uppercase', marginBottom: '4px' }}>OPERADOR / RESPONSABLE</p>
                                <p style={{ fontSize: '0.9rem', fontWeight: 800, color: '#172B4D' }}>Firma y Aclaración</p>
                            </div>
                        )}

                        {showSignatures.supervisor && (
                            <div className="signature-item-box" style={{ flex: 1, textAlign: 'center' }}>
                                <div style={{ height: '80px' }}></div>
                                <div className="signature-line" style={{ borderTop: '2px solid #172B4D', width: '200px', margin: '0 auto 12px auto' }}></div>
                                <p style={{ fontSize: '0.75rem', fontWeight: 900, color: '#6B778C', textTransform: 'uppercase', marginBottom: '4px' }}>SUPERVISOR / JEFE DE OBRA</p>
                                <p style={{ fontSize: '0.9rem', fontWeight: 800, color: '#172B4D' }}>Validación de Auditoría</p>
                            </div>
                        )}

                        {showSignatures.professional && (
                            <div className="signature-item-box" style={{ flex: 1, textAlign: 'center' }}>
                                <div style={{ height: '80px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                    {professional?.signature && (
                                        <img src={professional.signature} alt="Firma Profesional" style={{ maxHeight: '70px', maxWidth: '160px', mixBlendMode: 'multiply' }} />
                                    )}
                                </div>
                                <div className="signature-line" style={{ borderTop: '2px solid #172B4D', width: '200px', margin: '0 auto 12px auto' }}></div>
                                <p style={{ fontSize: '0.75rem', fontWeight: 900, color: '#6B778C', textTransform: 'uppercase', marginBottom: '4px' }}>PROFESIONAL ACTUANTE H&S</p>
                                <p style={{ fontSize: '1rem', fontWeight: 900, color: '#172B4D' }}>{professional?.name}</p>
                                {professional?.license && <p style={{ fontSize: '0.75rem', fontWeight: 700, color: '#6B778C' }}>MP: {professional.license}</p>}
                            </div>
                        )}
                    </div>
                </div>

                {/* Footer Print Info */}
                <div className="print-only" style={{ marginTop: '5rem', borderTop: '0.5px solid #cbd5e1', paddingTop: '1.5rem', textAlign: 'center', fontSize: '0.7rem', color: '#64748b', fontStyle: 'italic' }}>
                    Este documento es un registro oficial de inspección generado autónomamente por el sistema Asistente H&S para {professional?.name || 'el profesional actuante'}.
                </div>
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { ArrowLeft, Save, FileText, AlertCircle, GraduationCap, ClipboardCheck, Package, Plus, Trash2, History, Share2, Printer, Clock, Edit2 } from 'lucide-react';
import { useSync } from '../contexts/SyncContext';
import toast from 'react-hot-toast';
import PhotoAttachments from '../components/PhotoAttachments';
import CompanyLogo from '../components/CompanyLogo';

export default function Reports() {
    const navigate = useNavigate();
    const location = useLocation();
    const { syncCollection } = useSync();
    const [template, setTemplate] = useState('general'); // general, accident, training, rgrl, epp
    const [projectData, setProjectData] = useState({
        title: '',
        company: '',
        location: '',
        date: new Date().toISOString().split('T')[0],
        responsable: ''
    });

    const [content, setContent] = useState('');
    const [recentReports, setRecentReports] = useState([]);
    const [photos, setPhotos] = useState([]);

    // Template specific fields
    const [extraFields, setExtraFields] = useState({});
    const [personnel, setPersonnel] = useState(() => [{ id: Date.now(), name: '', dni: '' }]);

    useEffect(() => {
        if (location.state?.editData) {
            const data = location.state.editData;
            setTemplate(data.template || 'general');
            setProjectData({
                id: data.id,
                title: data.title || '',
                company: data.company || '',
                location: data.location || '',
                date: data.date || new Date().toISOString().split('T')[0],
                responsable: data.responsable || ''
            });
            setContent(data.content || '');
            setExtraFields(data.extraFields || {});
            setPhotos(data.photos || []);
            if (data.personnel && data.personnel.length > 0) {
                setPersonnel(data.personnel);
            }
        } else {
            const savedProfile = localStorage.getItem('personalData');
            if (savedProfile) {
                const parsed = JSON.parse(savedProfile);
                setProjectData(prev => ({ ...prev, responsable: parsed.name || '' }));
            }
        }
        // Load recent reports
        const hist = JSON.parse(localStorage.getItem('reports_history') || '[]');
        setRecentReports(hist.slice(0, 3));
    }, [location.state]);

    const handleAddPerson = () => {
        setPersonnel([...personnel, { id: Date.now(), name: '', dni: '' }]);
    };

    const handleRemovePerson = (id) => {
        if (personnel.length > 1) {
            setPersonnel(personnel.filter(p => p.id !== id));
        }
    };

    const handlePersonChange = (id, field, value) => {
        setPersonnel(personnel.map(p => p.id === id ? { ...p, [field]: value } : p));
    };

    const handleSave = async () => {
        if (!projectData.title || !projectData.company) {
            toast.error('Por favor, complete al menos el título y la empresa.');
            return;
        }

        const entryId = projectData.id || Date.now();
        const newReport = {
            id: entryId,
            template,
            ...projectData,
            content,
            extraFields,
            photos,
            personnel: (template === 'training' || template === 'epp') ? personnel : [],
            createdAt: new Date().toISOString()
        };

        const history = JSON.parse(localStorage.getItem('reports_history') || '[]');
        let updated;
        if (projectData.id) {
            updated = history.map(h => h.id === entryId ? newReport : h);
        } else {
            updated = [newReport, ...history];
        }

        await syncCollection('reports_history', updated);
        localStorage.setItem('current_report', JSON.stringify(newReport));
        navigate('/reports-report');
    };

    const templates = [
        { id: 'general', label: 'Informe Técnico', icon: <FileText /> },
        { id: 'accident', label: 'Accidente', icon: <AlertCircle /> },
        { id: 'training', label: 'Capacitación', icon: <GraduationCap /> },
        { id: 'rgrl', label: 'RGRL', icon: <ClipboardCheck /> },
        { id: 'epp', label: 'Entrega EPP', icon: <Package /> }
    ];

    return (
        <div className="container" style={{ maxWidth: '800px', paddingBottom: '4rem' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '2rem' }}>
                <button onClick={() => navigate('/#tools')} style={{ padding: '0.5rem', background: 'transparent', border: 'none', cursor: 'pointer' }}>
                    <ArrowLeft />
                </button>
                <div style={{ flex: 1 }}>
                    <h1 style={{ margin: 0, fontSize: '1.5rem' }}>Generar Informe</h1>
                </div>
                <CompanyLogo style={{ height: '32px', width: 'auto', maxWidth: '80px', objectFit: 'contain' }} />
                <button
                    onClick={() => navigate('/history')}
                    className="btn-outline"
                    style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', padding: '0.5rem 1rem' }}
                >
                    <History size={18} /> Historial
                </button>
            </div>

            {/* Template Selector */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(140px, 1fr))', gap: '0.8rem', marginBottom: '2rem' }}>
                {templates.map(t => (
                    <div
                        key={t.id}
                        onClick={() => {
                            setTemplate(t.id);
                            if ((t.id === 'training' || t.id === 'epp') && personnel.length === 0) {
                                setPersonnel([{ id: Date.now(), name: '', dni: '' }]);
                            }
                        }}
                        className="card"
                        style={{
                            textAlign: 'center',
                            padding: '1rem',
                            cursor: 'pointer',
                            border: template === t.id ? '2px solid var(--color-primary)' : '1px solid var(--color-border)',
                            background: template === t.id ? 'rgba(59, 130, 246, 0.05)' : 'var(--color-surface)',
                            transition: 'all 0.2s'
                        }}
                    >
                        <div style={{ color: template === t.id ? 'var(--color-primary)' : 'var(--color-text-muted)', marginBottom: '0.5rem' }}>
                            {React.cloneElement(t.icon, { size: 28 })}
                        </div>
                        <div style={{ fontSize: '0.85rem', fontWeight: 600 }}>{t.label}</div>
                    </div>
                ))}
            </div>

            {/* General Info */}
            <div className="card" style={{ marginBottom: '1.5rem', display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
                <div style={{ gridColumn: 'span 2' }}>
                    <label style={{ fontSize: '0.8rem', color: 'var(--color-text-muted)' }}>Título del Informe</label>
                    <input
                        type="text"
                        value={projectData.title}
                        onChange={(e) => setProjectData({ ...projectData, title: e.target.value })}
                        placeholder="Ej: Relevamiento de Condiciones de Seguridad"
                    />
                </div>
                <div>
                    <label style={{ fontSize: '0.8rem', color: 'var(--color-text-muted)' }}>Empresa / Cliente</label>
                    <input
                        type="text"
                        value={projectData.company}
                        onChange={(e) => setProjectData({ ...projectData, company: e.target.value })}
                        placeholder="Nombre de la empresa"
                    />
                </div>
                <div>
                    <label style={{ fontSize: '0.8rem', color: 'var(--color-text-muted)' }}>Ubicación / Planta</label>
                    <input
                        type="text"
                        value={projectData.location}
                        onChange={(e) => setProjectData({ ...projectData, location: e.target.value })}
                        placeholder="Ej: Sede Central"
                    />
                </div>
                <div>
                    <label style={{ fontSize: '0.8rem', color: 'var(--color-text-muted)' }}>Fecha</label>
                    <input
                        type="date"
                        value={projectData.date}
                        onChange={(e) => setProjectData({ ...projectData, date: e.target.value })}
                    />
                </div>
                <div>
                    <label style={{ fontSize: '0.8rem', color: 'var(--color-text-muted)' }}>Responsable</label>
                    <input
                        type="text"
                        value={projectData.responsable}
                        onChange={(e) => setProjectData({ ...projectData, responsable: e.target.value })}
                    />
                </div>
            </div>

            {/* Template Content */}
            <div className="card" style={{ marginBottom: '2rem' }}>
                <h3 style={{ margin: '0 0 1rem 0', fontSize: '1rem' }}>Desarrollo del Informe</h3>

                {template === 'training' && (
                    <div style={{ marginBottom: '1.5rem', padding: '1rem', background: 'var(--color-surface)', borderRadius: '8px', border: '1px solid var(--color-border)' }}>
                        <div style={{ marginBottom: '1rem' }}>
                            <label style={{ fontSize: '0.8rem', display: 'block', marginBottom: '0.3rem' }}>Tema de la Capacitación</label>
                            <input
                                type="text"
                                placeholder="Ej: Uso de Extintores, RCP, etc."
                                value={extraFields.topic || ''}
                                onChange={(e) => setExtraFields({ ...extraFields, topic: e.target.value })}
                            />
                        </div>
                        <div style={{ marginBottom: '1rem' }}>
                            <label style={{ fontSize: '0.8rem', display: 'block', marginBottom: '0.3rem' }}>Duración (minutos)</label>
                            <input
                                type="number"
                                value={extraFields.duration || ''}
                                onChange={(e) => setExtraFields({ ...extraFields, duration: e.target.value })}
                            />
                        </div>
                    </div>
                )}

                {template === 'accident' && (
                    <div style={{ marginBottom: '1.5rem', padding: '1rem', background: 'var(--color-surface)', borderRadius: '8px', border: '1px solid var(--color-border)' }}>
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
                            <div>
                                <label style={{ fontSize: '0.8rem', display: 'block', marginBottom: '0.3rem' }}>Hora del Evento</label>
                                <input
                                    type="time"
                                    value={extraFields.eventTime || ''}
                                    onChange={(e) => setExtraFields({ ...extraFields, eventTime: e.target.value })}
                                />
                            </div>
                            <div>
                                <label style={{ fontSize: '0.8rem', display: 'block', marginBottom: '0.3rem' }}>Persona Afectada</label>
                                <input
                                    type="text"
                                    value={extraFields.affectedPerson || ''}
                                    onChange={(e) => setExtraFields({ ...extraFields, affectedPerson: e.target.value })}
                                />
                            </div>
                        </div>
                    </div>
                )}

                {(template === 'training' || template === 'epp') && (
                    <div style={{ marginBottom: '1.5rem', padding: '1rem', background: 'var(--color-surface)', borderRadius: '8px', border: '1px solid var(--color-border)' }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
                            <label style={{ fontSize: '0.8rem', fontWeight: 700 }}>Personal Interviniente / Receptores</label>
                            <button
                                onClick={handleAddPerson}
                                className="btn-outline"
                                style={{ padding: '0.4rem 0.8rem', fontSize: '0.75rem', display: 'flex', alignItems: 'center', gap: '0.4rem' }}
                            >
                                <Plus size={14} /> Añadir Persona
                            </button>
                        </div>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '0.8rem' }}>
                            {personnel.map((p, index) => (
                                <div key={p.id} style={{ display: 'flex', gap: '0.5rem', alignItems: 'center' }}>
                                    <div style={{ flex: 2 }}>
                                        <input
                                            type="text"
                                            placeholder="Nombre completo"
                                            style={{ fontSize: '0.85rem', padding: '0.5rem' }}
                                            value={p.name}
                                            onChange={(e) => handlePersonChange(p.id, 'name', e.target.value)}
                                        />
                                    </div>
                                    <div style={{ flex: 1 }}>
                                        <input
                                            type="text"
                                            placeholder="DNI/CUIL"
                                            style={{ fontSize: '0.85rem', padding: '0.5rem' }}
                                            value={p.dni}
                                            onChange={(e) => handlePersonChange(p.id, 'dni', e.target.value)}
                                        />
                                    </div>
                                    <button
                                        onClick={() => handleRemovePerson(p.id)}
                                        style={{ background: 'transparent', border: 'none', color: '#ef4444', cursor: 'pointer', padding: '0.5rem' }}
                                        disabled={personnel.length === 1}
                                    >
                                        <Trash2 size={18} />
                                    </button>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                <label style={{ fontSize: '0.8rem', color: 'var(--color-text-muted)' }}>Contenido Principal / Observaciones</label>
                <textarea
                    style={{ minHeight: '300px', padding: '1rem' }}
                    value={content}
                    onChange={(e) => setContent(e.target.value)}
                    placeholder="Describa los hallazgos, recomendaciones o el cuerpo del informe..."
                />

                <PhotoAttachments
                    photos={photos}
                    onChange={setPhotos}
                    maxPhotos={8}
                    label="Fotos de Evidencia"
                />
            </div>

            {/* Recent Reports Mini-Panel */}
            {recentReports.length > 0 && (
                <div style={{ marginBottom: '2rem' }}>
                    <h3 style={{ fontSize: '0.95rem', fontWeight: 800, marginBottom: '0.8rem', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                        <Clock size={16} color="var(--color-primary)" /> Informes Recientes
                    </h3>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '0.6rem' }}>
                        {recentReports.map((r) => (
                            <div key={r.id} style={{
                                display: 'flex', alignItems: 'center', gap: '1rem',
                                background: 'var(--color-surface)', border: '1px solid var(--color-border)',
                                borderRadius: '12px', padding: '0.8rem 1rem', transition: 'border-color 0.2s'
                            }}
                                onMouseOver={e => e.currentTarget.style.borderColor = 'var(--color-primary)'}
                                onMouseOut={e => e.currentTarget.style.borderColor = 'var(--color-border)'}
                            >
                                <div style={{ flex: 1, minWidth: 0 }}>
                                    <div style={{ fontWeight: 700, fontSize: '0.88rem', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{r.title || 'Sin título'}</div>
                                    <div style={{ fontSize: '0.72rem', color: 'var(--color-text-muted)', display: 'flex', gap: '0.6rem', marginTop: '0.15rem', alignItems: 'center', flexWrap: 'wrap' }}>
                                        <span style={{ background: 'rgba(59,130,246,0.08)', color: 'var(--color-primary)', padding: '0.1rem 0.5rem', borderRadius: '20px', fontWeight: 700, fontSize: '0.65rem' }}>{r.template?.toUpperCase() || 'GENERAL'}</span>
                                        {r.company} · {new Date(r.createdAt).toLocaleDateString('es-AR')}
                                    </div>
                                </div>
                                <button
                                    onClick={() => navigate('/reports', { state: { editData: r } })}
                                    style={{
                                        display: 'flex', alignItems: 'center', gap: '0.4rem',
                                        background: 'rgba(59,130,246,0.08)', border: '1px solid rgba(59,130,246,0.2)',
                                        borderRadius: '8px', padding: '0.4rem 0.8rem',
                                        color: 'var(--color-primary)', cursor: 'pointer',
                                        fontSize: '0.78rem', fontWeight: 700, whiteSpace: 'nowrap', flexShrink: 0
                                    }}
                                >
                                    <Edit2 size={13} /> Editar
                                </button>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* Floating Action Buttons */}
            <div className="no-print floating-action-bar">
                <button
                    onClick={handleSave}
                    className="btn-floating-action"
                    style={{ background: '#36B37E', color: 'white' }}
                >
                    <Save size={18} /> GENERAR INFORME
                </button>
                <button
                    onClick={() => toast.error('Selecciona "Generar Informe" primero para poder compartirlo.')}
                    className="btn-floating-action"
                    style={{ background: '#0052CC', color: 'white' }}
                >
                    <Share2 size={18} /> COMPARTIR
                </button>
                <button
                    onClick={() => toast.error('Selecciona "Generar Informe" primero para poder imprimirlo.')}
                    className="btn-floating-action"
                    style={{ background: '#FF8B00', color: 'white' }}
                >
                    <Printer size={18} /> IMPRIMIR PDF
                </button>
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { ArrowLeft, Printer, Share2, Download, CheckCircle2, Info, Building2, User, HelpCircle, MapPin, Calendar } from 'lucide-react';
import { useAuth } from '../contexts/AuthContext';
import ShareModal from '../components/ShareModal';
import CompanyLogo from '../components/CompanyLogo';
import { usePaywall } from '../hooks/usePaywall';
import { toast } from 'react-hot-toast';
import PdfBrandingFooter from '../components/PdfBrandingFooter';
import { getCountryNormativa } from '../data/legislationData';

export default function ReportsReport() {
    const navigate = useNavigate();
    const { currentUser } = useAuth();
    const { requirePro } = usePaywall();
    const [report, setReport] = useState(null);
    const [profile, setProfile] = useState(null);
    const [signature, setSignature] = useState(null);
    const [showShare, setShowShare] = useState(false);
    const [showSignatures, setShowSignatures] = useState({
        operator: true,
        supervisor: true,
        professional: true
    });

    const savedData = localStorage.getItem('personalData');
    const userCountry = savedData ? JSON.parse(savedData).country || 'argentina' : 'argentina';
    const countryNorms = getCountryNormativa(userCountry);

    useEffect(() => {
        const current = localStorage.getItem('current_report');
        const prof = localStorage.getItem('personalData');
        const sig = localStorage.getItem('signatureStampData');

        if (current) setReport(JSON.parse(current));
        if (prof) setProfile(JSON.parse(prof));
        if (sig) setSignature(JSON.parse(sig));
    }, []);

    if (!report) return <div className="container">Cargando...</div>;

    const handlePrint = () => requirePro(() => window.print());

    return (
        <div className="container" style={{ maxWidth: '1000px' }}>
            <ShareModal
                open={showShare}
                onClose={() => setShowShare(false)}
                title={`Checklist – ${report.company || ''}`}
                text={`📋 Checklist de Inspección\n🏗️ Empresa: ${report.company}\n📍 Ubicación: ${report.location || '-'}\n📅 Fecha: ${new Date(report.date).toLocaleDateString()}\n\nGenerado con Asistente H&S`}
                elementIdToPrint="pdf-content"
            />
            {/* Control Panel - Absolute Print Hide */}
            <div className="no-print" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                <button onClick={() => navigate('/reports')} style={{ background: 'transparent', border: 'none', display: 'flex', alignItems: 'center', gap: '0.5rem', cursor: 'pointer', color: 'var(--color-text)' }}>
                    <ArrowLeft size={20} /> Volver a Formulario
                </button>
            </div>

            <div id="pdf-content" className="card report-print" style={{
                padding: '3rem',
                minHeight: '29.7cm',
                height: 'auto',
                paddingBottom: '5rem',
                background: '#ffffff',
                color: '#1e293b',
                boxShadow: '0 10px 25px -5px rgba(0,0,0,0.1)',
                position: 'relative'
            }}>
                {/* Header with Professional Info */}
                <div style={{ display: 'flex', justifyContent: 'space-between', borderBottom: '2px solid var(--color-primary)', paddingBottom: '2rem', marginBottom: '2.5rem', gap: '1.5rem' }} className="flex-col sm:flex-row">
                    <div style={{ flex: 1, display: 'flex', gap: '1.5rem', alignItems: 'flex-start' }}>
                        <CompanyLogo style={{ height: '60px', width: 'auto', objectFit: 'contain' }} />
                        <div>
                            <h1 style={{ margin: '0 0 0.5rem 0', color: 'var(--color-primary)', fontSize: '2.5rem', fontWeight: 900, tracking: '-1px' }}>INFORME</h1>
                            <p style={{ margin: 0, fontSize: '0.9rem', color: '#475569', textTransform: 'uppercase', letterSpacing: '1px' }}>
                                {report.template === 'general' ? 'Informe Técnico' :
                                    report.template === 'accident' ? 'Registro de Accidente' :
                                        report.template === 'training' ? 'Capacitación de Personal' :
                                            report.template === 'rgrl' ? 'RGRL' : 'EPP'}
                            </p>
                        </div>
                    </div>
                    {profile && (
                        <div style={{ textAlign: 'right', borderLeft: '1px solid #e2e8f0', paddingLeft: '2rem' }} className="md:text-right md:border-t-0 md:border-l border-[#e2e8f0] pt-4 md:pt-0">
                            <p style={{ margin: 0, fontWeight: 700, fontSize: '1.2rem', color: '#1e293b' }}>{profile.name}</p>
                            <p style={{ margin: '0.2rem 0', fontSize: '0.9rem', color: '#475569' }}>{profile.profession}</p>
                            {profile.license && <p style={{ margin: 0, fontSize: '0.85rem', color: '#64748b' }}>Mat: {profile.license}</p>}
                        </div>
                    )}
                </div>

                {/* Metadata Grid */}
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '1.5rem', marginBottom: '3rem', background: '#f8fafc', padding: '1.5rem', borderRadius: '8px', border: '1px solid #e2e8f0', color: '#1e293b' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.8rem' }}>
                        <Building2 size={20} color="var(--color-primary)" />
                        <div>
                            <p style={{ margin: 0, fontSize: '0.75rem', color: '#64748b' }}>Empresa</p>
                            <p style={{ margin: 0, fontWeight: 600 }}>{report.company}</p>
                        </div>
                    </div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.8rem' }}>
                        <MapPin size={20} color="var(--color-primary)" />
                        <div>
                            <p style={{ margin: 0, fontSize: '0.75rem', color: '#64748b' }}>Ubicación</p>
                            <p style={{ margin: 0, fontWeight: 600 }}>{report.location || 'N/A'}</p>
                        </div>
                    </div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.8rem' }}>
                        <Calendar size={20} color="var(--color-primary)" />
                        <div>
                            <p style={{ margin: 0, fontSize: '0.75rem', color: '#64748b' }}>Fecha</p>
                            <p style={{ margin: 0, fontWeight: 600 }}>{new Date(report.date).toLocaleDateString()}</p>
                        </div>
                    </div>
                </div>

                {/* Main Content Area / Observations */}
                <div style={{ marginBottom: '1rem', color: 'var(--color-primary)', fontWeight: 800, fontSize: '0.8rem', letterSpacing: '2px', textTransform: 'uppercase' }}>OBSERVACIONES</div>
                <div style={{ marginBottom: '4rem', whiteSpace: 'pre-wrap', wordBreak: 'break-word', overflowWrap: 'anywhere', lineHeight: '1.6', fontSize: '1.05rem', color: '#1e293b', borderTop: '2px solid #f1f5f9', paddingTop: '1rem' }}>
                    {report.content || 'Sin observaciones registradas.'}
                </div>

                {/* Personnel List Table if applicable */}
                {(report.template === 'training' || report.template === 'epp') && report.personnel && report.personnel.length > 0 && (
                    <div style={{ marginBottom: '4rem' }}>
                        <h4 style={{ margin: '0 0 1rem 0', color: 'var(--color-primary)', borderBottom: '1px solid #e2e8f0', paddingBottom: '0.5rem' }}>
                            Personal Interviniente / Firmas
                        </h4>
                        <div className="overflow-x-auto w-full">
                            <table style={{ width: '100%', minWidth: '600px', borderCollapse: 'collapse', fontSize: '0.85rem' }}>
                                <thead>
                                    <tr style={{ background: '#f1f5f9' }}>
                                        <th style={{ border: '1px solid #e2e8f0', padding: '0.8rem', textAlign: 'left', color: '#475569' }}>Nombre y Apellido</th>
                                        <th style={{ border: '1px solid #e2e8f0', padding: '0.8rem', textAlign: 'left', color: '#475569' }}>DNI / CUIL</th>
                                        <th style={{ border: '1px solid #e2e8f0', padding: '0.8rem', textAlign: 'left', width: '250px', color: '#475569' }}>Firma</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {report.personnel.map(p => (
                                        <tr key={p.id}>
                                            <td style={{ border: '1px solid #e2e8f0', padding: '0.8rem', color: '#1e293b' }}>{p.name}</td>
                                            <td style={{ border: '1px solid #e2e8f0', padding: '0.8rem', color: '#1e293b' }}>{p.dni}</td>
                                            <td style={{ border: '1px solid #e2e8f0', padding: '0.8rem', height: '65px', verticalAlign: 'bottom', textAlign: 'center' }}>
                                                <div style={{ borderTop: '1px dotted #000', width: '80%', margin: '0 auto', fontSize: '0.7rem', color: '#64748b' }}>
                                                    Firma del Trabajador
                                                </div>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>
                )}

                {/* THREE-COLUMN SIGNATURE GRID / CONTROLS */}
                <div className="no-print mt-10 mb-8 p-4 bg-slate-50 border border-slate-200 rounded-xl w-full flex flex-col md:flex-row gap-4 md:gap-8 justify-center items-center text-xs font-bold text-slate-700">
                    <div className="text-center">INCLUIR FIRMAS EN EL DOCUMENTO:</div>
                    <div className="flex gap-4 flex-wrap justify-center">
                        <label className="flex items-center gap-2 cursor-pointer">
                            <input type="checkbox" checked={showSignatures.operator} onChange={e => setShowSignatures(s => ({ ...s, operator: e.target.checked }))} className="w-4 h-4 accent-emerald-600" /> Operador
                        </label>
                        <label className="flex items-center gap-2 cursor-pointer">
                            <input type="checkbox" checked={showSignatures.supervisor} onChange={e => setShowSignatures(s => ({ ...s, supervisor: e.target.checked }))} className="w-4 h-4 accent-emerald-600" /> Supervisor
                        </label>
                        <label className="flex items-center gap-2 cursor-pointer">
                            <input type="checkbox" checked={showSignatures.professional} onChange={e => setShowSignatures(s => ({ ...s, professional: e.target.checked }))} className="w-4 h-4 accent-emerald-600" /> Profesional
                        </label>
                    </div>
                </div>

                <div className="signature-container-row mt-12 pt-8 border-t-2 border-dashed border-[#e2e8f0]">
                    {showSignatures.operator && (
                        <div className="signature-item-box">
                            <div className="signature-line"></div>
                            <p className="text-[0.65rem] font-black uppercase text-slate-400 tracking-widest leading-none mb-1">OPERADOR</p>
                            <p className="text-[0.8rem] font-black uppercase text-black leading-none min-h-[0.8rem]">Firma y DNI</p>
                        </div>
                    )}

                    {showSignatures.supervisor && (
                        <div className="signature-item-box">
                            <div className="signature-line"></div>
                            <p className="text-[0.65rem] font-black uppercase text-slate-400 tracking-widest leading-none mb-1">SUPERVISOR / RESPONSABLE</p>
                            <p className="text-[0.8rem] font-black uppercase text-black leading-none min-h-[0.8rem]">Firma y DNI</p>
                        </div>
                    )}

                    {showSignatures.professional && (
                        <div className="signature-item-box">
                            {signature?.signature || signature?.stamp ? (
                                <div style={{ display: 'flex', gap: '10px', alignItems: 'center', justifyContent: 'center', marginBottom: '0.5rem', height: '60px' }}>
                                    {signature.signature && <img src={signature.signature} alt="Firma" style={{ maxWidth: '100px', maxHeight: '60px' }} />}
                                    {signature.stamp && <img src={signature.stamp} alt="Sello" style={{ maxWidth: '60px', maxHeight: '60px' }} />}
                                </div>
                            ) : (
                                <div style={{ height: '60px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.7rem', color: '#999', marginBottom: '0.5rem' }}>Sin Firma</div>
                            )}
                            <div className="signature-line"></div>
                            <p className="text-[0.65rem] font-black uppercase text-slate-400 tracking-widest leading-none mb-1">{profile?.name || report.responsable}</p>
                            <p style={{ margin: 0, fontWeight: 700, fontSize: '0.8rem' }}>PROFESIONAL ACTUANTE</p>
                            {profile?.license && <p style={{ margin: 0, fontSize: '0.65rem', color: 'var(--color-primary)', fontWeight: 700 }}>Mat: {profile.license}</p>}
                        </div>
                    )}
                </div>

                {/* Footer Legal */}
                <div style={{ width: '100%', textAlign: 'center', fontSize: '0.7rem', color: '#94a3b8', marginTop: '3rem', fontStyle: 'italic' }}>
                    Documento generado por Asistente de Higiene y Seguridad - Conforme a {countryNorms.general}
                </div>
                <PdfBrandingFooter />
            </div>

            {/* Floating Action Buttons */}
            <div className="no-print floating-action-bar">
                <button onClick={() => toast.success('Este reporte ya se encuentra guardado en tu historial.')} className="btn-floating-action" style={{ background: '#36B37E', color: 'white' }}>
                    <CheckCircle2 size={18} /> GUARDADO
                </button>
                <button onClick={() => requirePro(() => setShowShare(true))} className="btn-floating-action" style={{ background: '#0052CC', color: 'white' }}>
                    <Share2 size={18} /> COMPARTIR
                </button>
                <button onClick={handlePrint} className="btn-floating-action" style={{ background: '#FF8B00', color: 'white' }}>
                    <Printer size={18} /> IMPRIMIR PDF
                </button>
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { Lock, Eye, EyeOff, CheckCircle2, AlertCircle, ArrowLeft } from 'lucide-react';
import { API_BASE_URL } from '../config';
import { auth } from '../firebase';
import { confirmPasswordReset, verifyPasswordResetCode } from 'firebase/auth';
import toast from 'react-hot-toast';

export default function ResetPassword() {
    const navigate = useNavigate();
    const [searchParams] = useSearchParams();
    const oobCode = searchParams.get('oobCode') || searchParams.get('token');

    const [passwords, setPasswords] = useState({
        new: '',
        confirm: ''
    });
    const [showPass, setShowPass] = useState({ new: false, confirm: false });
    const [status, setStatus] = useState({ type: '', message: '' });

    useEffect(() => {
        if (!oobCode) {
            setStatus({ type: 'error', message: 'Enlace de restablecimiento no válido o ausente.' });
        }
    }, [oobCode]);

    const handleReset = async (e) => {
        e.preventDefault();
        if (passwords.new !== passwords.confirm) {
            setStatus({ type: 'error', message: 'Las contraseñas no coinciden.' });
            return;
        }

        // Enhanced password validation
        if (passwords.new.length < 8) {
            setStatus({ type: 'error', message: 'La contraseña debe tener al menos 8 caracteres.' });
            return;
        }
        if (!/[A-Z]/.test(passwords.new)) {
            setStatus({ type: 'error', message: 'La contraseña debe incluir al menos una letra mayúscula.' });
            return;
        }
        if (!/[a-z]/.test(passwords.new)) {
            setStatus({ type: 'error', message: 'La contraseña debe incluir al menos una letra minúscula.' });
            return;
        }
        if (!/[0-9]/.test(passwords.new)) {
            setStatus({ type: 'error', message: 'La contraseña debe incluir al menos un número.' });
            return;
        }
        if (!/[!@#$%^&*(),.?":{}|<>_\-+=\[\]\\;'`~]/.test(passwords.new)) {
            setStatus({ type: 'error', message: 'La contraseña debe incluir al menos un carácter especial (!@#$%^&*...).' });
            return;
        }

        setStatus({ type: 'loading', message: 'Actualizando contraseña...' });

        try {
            // First verify code to get email for the notification
            const email = await verifyPasswordResetCode(auth, oobCode);

            // Apply new password to Firebase Auth
            await confirmPasswordReset(auth, oobCode, passwords.new);

            // Notify user of successful change asynchronously
            fetch(`${API_BASE_URL}/api/send-password-changed-email`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ email })
            }).catch(e => console.error("Notification failed", e));

            setStatus({ type: 'success', message: '¡Contraseña actualizada con éxito!' });
            toast.success("Tu contraseña ha sido cambiada");
            setTimeout(() => navigate('/login'), 2000);

        } catch (error) {
            console.error("Firebase Reset Error:", error);
            let errorMessage = 'El enlace ha expirado o ya fue utilizado.';
            if (error.code === 'auth/weak-password') {
                errorMessage = 'La contraseña es muy débil. Debe tener 8+ caracteres, mayúscula, minúscula, número y carácter especial.';
            } else if (error.code === 'auth/invalid-action-code') {
                errorMessage = 'El enlace de recuperación es inválido o ya ha caducado.';
            }
            setStatus({ type: 'error', message: errorMessage });
        }
    };
    return (
        <div className="container" style={{ display: 'flex', flexDirection: 'column', justifyContent: 'center', minHeight: '100vh', maxWidth: '450px' }}>
            <div className="card shadow-lg" style={{ padding: '2.5rem' }}>
                <div style={{ textAlign: 'center', marginBottom: '2rem' }}>
                    <div style={{
                        width: '80px',
                        height: '80px',
                        margin: '0 auto 1rem auto'
                    }}>
                        <img
                            src="/logo.png"
                            alt="Asistente H&S Logo"
                            style={{ width: '100%', height: '100%', objectFit: 'contain' }}
                        />
                    </div>
                    <h1 style={{ fontSize: '1.6rem', marginBottom: '0.5rem' }}>Nueva Contraseña</h1>
                    <p style={{ color: 'var(--color-text-muted)', fontSize: '0.9rem' }}>Introduce tu nueva clave de acceso</p>
                </div>

                {!oobCode ? (
                    <div style={{
                        padding: '1rem',
                        borderRadius: '12px',
                        background: 'rgba(239, 68, 68, 0.1)',
                        color: '#ef4444',
                        textAlign: 'center',
                        display: 'flex',
                        flexDirection: 'column',
                        gap: '1rem'
                    }}>
                        <AlertCircle size={32} style={{ margin: '0 auto' }} />
                        <p style={{ margin: 0, fontWeight: 500 }}>{status.message}</p>
                        <button onClick={() => navigate('/login')} className="btn-secondary" style={{ width: '100%' }}>
                            Volver al Login
                        </button>
                    </div>
                ) : (
                    <form onSubmit={handleReset} style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                        <div>
                            <label style={{ display: 'block', fontSize: '0.85rem', marginBottom: '0.5rem', fontWeight: 600 }}>Nueva Contraseña</label>
                            <div style={{ position: 'relative' }}>
                                <input
                                    type={showPass.new ? 'text' : 'password'}
                                    value={passwords.new}
                                    onChange={e => setPasswords({ ...passwords, new: e.target.value })}
                                    required
                                    placeholder="••••••••"
                                    style={{ width: '100%', padding: '0.8rem', paddingRight: '2.5rem', borderRadius: '8px', border: '1px solid var(--color-border)', background: 'var(--color-surface)', color: 'var(--color-text)' }}
                                />
                                <button type="button" onClick={() => setShowPass({ ...showPass, new: !showPass.new })} style={{ position: 'absolute', right: '0.8rem', top: '50%', transform: 'translateY(-50%)', background: 'none', border: 'none', color: 'var(--color-text-muted)', cursor: 'pointer' }}>
                                    {showPass.new ? <EyeOff size={18} /> : <Eye size={18} />}
                                </button>
                            </div>
                        </div>

                        <div>
                            <label style={{ display: 'block', fontSize: '0.85rem', marginBottom: '0.5rem', fontWeight: 600 }}>Confirmar Contraseña</label>
                            <div style={{ position: 'relative' }}>
                                <input
                                    type={showPass.confirm ? 'text' : 'password'}
                                    value={passwords.confirm}
                                    onChange={e => setPasswords({ ...passwords, confirm: e.target.value })}
                                    required
                                    placeholder="••••••••"
                                    style={{ width: '100%', padding: '0.8rem', paddingRight: '2.5rem', borderRadius: '8px', border: '1px solid var(--color-border)', background: 'var(--color-surface)', color: 'var(--color-text)' }}
                                />
                                <button type="button" onClick={() => setShowPass({ ...showPass, confirm: !showPass.confirm })} style={{ position: 'absolute', right: '0.8rem', top: '50%', transform: 'translateY(-50%)', background: 'none', border: 'none', color: 'var(--color-text-muted)', cursor: 'pointer' }}>
                                    {showPass.confirm ? <EyeOff size={18} /> : <Eye size={18} />}
                                </button>
                            </div>
                        </div>

                        {status.message && (
                            <div style={{
                                padding: '0.8rem',
                                borderRadius: '8px',
                                fontSize: '0.85rem',
                                background: status.type === 'error' ? 'rgba(239, 68, 68, 0.1)' : status.type === 'success' ? 'rgba(16, 185, 129, 0.1)' : 'rgba(59, 130, 246, 0.1)',
                                color: status.type === 'error' ? '#ef4444' : status.type === 'success' ? '#10b981' : 'var(--color-primary)',
                                display: 'flex',
                                alignItems: 'center',
                                gap: '0.5rem'
                            }}>
                                {status.type === 'success' ? <CheckCircle2 size={16} /> : <AlertCircle size={16} />}
                                {status.message}
                            </div>
                        )}

                        <button
                            type="submit"
                            disabled={status.type === 'loading' || status.type === 'success'}
                            className="btn-primary"
                            style={{ margin: 0 }}
                        >
                            {status.type === 'loading' ? 'Procesando...' : 'Restablecer Contraseña'}
                        </button>
                    </form>
                )}

                <p style={{ textAlign: 'center', marginTop: '1.5rem', fontSize: '0.85rem' }}>
                    <a href="/login" onClick={(e) => { e.preventDefault(); navigate('/login'); }} style={{ color: 'var(--color-text-muted)', textDecoration: 'none', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem' }}>
                        <ArrowLeft size={14} /> Volver al inicio de sesión
                    </a>
                </p>
            </div>
        </div>
    );
}

