                            <div style={{ display: 'flex', gap: '1rem', marginTop: '1rem' }}>
                                <button onClick={() => setIsAddingEvent(false)} className="btn-secondary" style={{ flex: 1, padding: '1rem', borderRadius: '14px', fontWeight: 700 }}>CANCELAR</button>
                                <button onClick={handleAddEvent} className="bg-emerald-600 hover:bg-emerald-700 text-white border-0 shadow-sm transition-all" style={{ flex: 1, padding: '1rem', borderRadius: '14px', fontWeight: 700, marginTop: 0 }}>GUARDAR AGENDA</button>
                            </div>
