                `}
            </style>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { useSync } from '../contexts/SyncContext';
import { useDocumentTitle } from '../hooks/useDocumentTitle';
import { ArrowLeft, Save, AlertTriangle, MapPin, Camera, User } from 'lucide-react';

export default function StopCards() {
    useDocumentTitle('Nueva Tarjeta STOP');
    const navigate = useNavigate();
    const { currentUser } = useAuth();
    const { syncCollection } = useSync();

    const [formData, setFormData] = useState({
        id: Date.now().toString(),
        date: new Date().toISOString().split('T')[0],
        time: new Date().toTimeString().split(' ')[0].substring(0, 5),
        type: 'Condición Insegura',
        location: '',
        description: '',
        actionTaken: '',
        observer: currentUser?.displayName || currentUser?.email || 'Usuario',
        photoBase64: null
    });

    const handleChange = (e) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handlePhotoUpload = (e) => {
        const file = e.target.files[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = () => {
                setFormData(prev => ({ ...prev, photoBase64: reader.result }));
            };
            reader.readAsDataURL(file);
        }
    };

    const handleSave = () => {
        if (!formData.location || !formData.description) {
            alert("Por favor completá ubicación y descripción.");
            return;
        }

        const history = JSON.parse(localStorage.getItem('stop_cards_history') || '[]');
        const updated = [formData, ...history];
        localStorage.setItem('stop_cards_history', JSON.stringify(updated));
        syncCollection('stop_cards_history', updated);

        navigate('/stop-cards-history');
    };

    return (
        <div className="container page-transition" style={{ paddingBottom: '4rem', maxWidth: '600px', margin: '0 auto' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '2rem' }}>
                <button onClick={() => navigate('/#tools')} style={{ padding: '0.5rem', background: 'transparent', border: 'none', cursor: 'pointer' }}>
                    <ArrowLeft size={24} />
                </button>
                <h1 style={{ margin: 0, fontSize: '1.4rem', fontWeight: 800 }}>Tarjeta STOP</h1>
            </div>

            <div className="card" style={{ padding: '1.5rem' }}>
                <div style={{ display: 'flex', gap: '1rem', marginBottom: '1rem' }}>
                    <div className="form-group" style={{ flex: 1 }}>
                        <label>Fecha</label>
                        <input type="date" name="date" value={formData.date} onChange={handleChange} className="form-control" />
                    </div>
                    <div className="form-group" style={{ flex: 1 }}>
                        <label>Hora</label>
                        <input type="time" name="time" value={formData.time} onChange={handleChange} className="form-control" />
                    </div>
                </div>

                <div className="form-group" style={{ marginBottom: '1rem' }}>
                    <label>Tipo de Observación</label>
                    <select name="type" value={formData.type} onChange={handleChange} className="form-control">
                        <option value="Condición Insegura">Condición Insegura</option>
                        <option value="Acto Inseguro">Acto Inseguro</option>
                        <option value="Casi Accidente">Casi Accidente</option>
                        <option value="Acto Seguro">Acto Seguro (Positivo)</option>
                    </select>
                </div>

                <div className="form-group" style={{ marginBottom: '1rem' }}>
                    <label style={{ display: 'flex', alignItems: 'center', gap: '0.4rem' }}><MapPin size={16} /> Ubicación / Sector</label>
                    <input type="text" name="location" value={formData.location} onChange={handleChange} className="form-control" placeholder="Ej. Taller principal, Línea 2..." />
                </div>

                <div className="form-group" style={{ marginBottom: '1rem' }}>
                    <label style={{ display: 'flex', alignItems: 'center', gap: '0.4rem' }}><AlertTriangle size={16} /> Descripción del Hallazgo</label>
                    <textarea name="description" value={formData.description} onChange={handleChange} className="form-control" rows="3" placeholder="Describí exactamente qué viste..."></textarea>
                </div>

                <div className="form-group" style={{ marginBottom: '1rem' }}>
                    <label>Acción Inmediata Tomada (opcional)</label>
                    <textarea name="actionTaken" value={formData.actionTaken} onChange={handleChange} className="form-control" rows="2" placeholder="Ej. Se detuvo la tarea, se limpió el área..."></textarea>
                </div>

                <div className="form-group" style={{ marginBottom: '1.5rem' }}>
                    <label style={{ display: 'flex', alignItems: 'center', gap: '0.4rem' }}><User size={16} /> Reportado por</label>
                    <input type="text" name="observer" value={formData.observer} onChange={handleChange} className="form-control" />
                </div>

                <div className="form-group" style={{ marginBottom: '2rem' }}>
                    <label style={{ display: 'flex', alignItems: 'center', gap: '0.4rem' }}><Camera size={16} /> Evidencia Fotográfica (Opcional)</label>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginTop: '0.5rem' }}>
                        <label style={{
                            padding: '0.8rem 1.2rem', background: 'var(--color-surface)', border: '1px dashed var(--color-border)',
                            borderRadius: '12px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '0.5rem',
                            fontWeight: 600, color: 'var(--color-text-muted)'
                        }}>
                            <Camera size={20} /> Capturar o Subir
                            <input type="file" accept="image/*" capture="environment" onChange={handlePhotoUpload} style={{ display: 'none' }} />
                        </label>
                        {formData.photoBase64 && (
                            <img src={formData.photoBase64} alt="Evidencia" style={{ width: '60px', height: '60px', objectFit: 'cover', borderRadius: '8px', border: '2px solid var(--color-primary)' }} />
                        )}
                    </div>
                </div>

                <button onClick={handleSave} className="btn-primary" style={{ width: '100%', padding: '1rem', fontSize: '1.1rem', display: 'flex', justifyContent: 'center', gap: '0.5rem' }}>
                    <Save size={20} /> Guardar Tarjeta STOP
                </button>
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import {
    Calculator, Info, RefreshCw, Printer, Search, Settings2, CheckCircle2, TriangleAlert, Share2, Save, ArrowLeft, ThermometerSun
} from 'lucide-react';
import ShareModal from '../components/ShareModal';
import ThermalStressPdfGenerator from '../components/ThermalStressPdfGenerator';
import { useAuth } from '../contexts/AuthContext';
import { useSync } from '../contexts/SyncContext';
import { useDocumentTitle } from '../hooks/useDocumentTitle';
import toast from 'react-hot-toast';
import { usePaywall } from '../hooks/usePaywall';
import AdBanner from '../components/AdBanner';
import { getCountryNormativa } from '../data/legislationData';

// SRT 295/03 Permissible Limits Table (Values in Celsius)
const LIMITS_295 = {
    'continuo': { 'liviano': 30.0, 'moderado': 26.7, 'pesado': 25.0 },
    '75_25': { 'liviano': 30.6, 'moderado': 28.0, 'pesado': 25.9 },
    '50_50': { 'liviano': 31.4, 'moderado': 29.4, 'pesado': 27.9 },
    '25_75': { 'liviano': 32.2, 'moderado': 31.1, 'pesado': 30.0 }
};

export default function ThermalStress() {
    useDocumentTitle('Cálculo Estrés Térmico');
    const navigate = useNavigate();
    const location = useLocation();
    const { currentUser } = useAuth();
    const { requirePro } = usePaywall();
    const { syncCollection } = useSync();

    const editData = location.state?.editData;

    const [formData, setFormData] = useState(editData || {
        puesto: '',
        sector: '',
        tarea: '',
        fecha: new Date().toISOString().split('T')[0],

        // Entorno
        cargaSolar: false,
        tbh: '', // Temperatura Bulbo Húmedo
        tg: '',  // Temperatura de Globo
        tbs: '', // Temperatura Bulbo Seco (Solo para carga solar)

        // Trabajo
        ritmo: 'moderado', // liviano, moderado, pesado
        ciclo: 'continuo', // continuo, 75_25, 50_50, 25_75
    });

    const [resultados, setResultados] = useState({
        tgbh: null,
        limite: null,
        admisible: null
    });

    const [showShareModal, setShowShareModal] = useState(false);
    const [viewMode, setViewMode] = useState('edit'); // 'edit' or 'report'



    const savedData = localStorage.getItem('personalData');
    const userCountry = savedData ? JSON.parse(savedData).country || 'argentina' : 'argentina';
    const countryNorms = getCountryNormativa(userCountry);

    const handleInput = (field, value) => {
        setFormData(p => ({ ...p, [field]: value }));
    };

    // Auto-calculate when vars change
    useEffect(() => {
        const tbh = parseFloat(formData.tbh);
        const tg = parseFloat(formData.tg);
        const tbs = formData.cargaSolar ? parseFloat(formData.tbs) : 0;

        if (!isNaN(tbh) && !isNaN(tg)) {
            let tgbhCalc = 0;
            if (formData.cargaSolar && !isNaN(tbs)) {
                // Al aire libre con carga solar
                tgbhCalc = (0.7 * tbh) + (0.2 * tg) + (0.1 * tbs);
            } else {
                // Interiores o aire libre sin carga solar
                tgbhCalc = (0.7 * tbh) + (0.3 * tg);
            }

            const limiteCalc = LIMITS_295[formData.ciclo][formData.ritmo];

            setResultados({
                tgbh: parseFloat(tgbhCalc.toFixed(1)),
                limite: limiteCalc,
                admisible: tgbhCalc <= limiteCalc
            });
        } else {
            setResultados({ tgbh: null, limite: null, admisible: null });
        }
    }, [formData.tbh, formData.tg, formData.tbs, formData.cargaSolar, formData.ritmo, formData.ciclo]);

    const doSave = () => {
        if (!formData.puesto) {
            toast.error('Debe indicar el nombre del puesto/estudio.');
            return;
        }

        if (resultados.tgbh === null) {
            toast.error('Faltan datos ambientales para calcular el TGBH.');
            return;
        }

        const report = {
            id: editData?.id || Date.now(),
            date: editData?.date || new Date().toISOString(),
            evaluador: editData?.evaluador || currentUser?.displayName || 'Profesional HSE',
            ...formData,
            resultados
        };

        let history = JSON.parse(localStorage.getItem('thermal_history') || '[]');

        if (editData) {
            history = history.map(item => item.id === editData.id ? report : item);
        } else {
            history.unshift(report);
        }

        localStorage.setItem('thermal_history', JSON.stringify(history));
        syncCollection('thermal_history', history);

        toast.success(editData ? 'Evaluación térmica actualizada.' : 'Medición guardada en el historial.');
        navigate('/thermal-stress-history');
    };

    const handleSave = () => requirePro(doSave);
    const handlePrint = () => requirePro(() => window.print());

    return (
        <div className="container" style={{ paddingBottom: '6rem', minHeight: '100vh', display: 'flex', flexDirection: 'column' }}>
            <ShareModal
                open={showShareModal}
                onClose={() => setShowShareModal(false)}
                title="Compartir Informe de Estrés Térmico"
                text={`🌡️ Evaluación de Estrés Térmico (TGBH)\n📍 Puesto: ${formData.puesto}\n📊 Índice: ${resultados.tgbh}°C (Límite: ${resultados.limite}°C)\n✅ Dictamen: ${resultados.admisible ? 'ADMISIBLE' : 'RIESGO'}\n\nEnviado desde Asistente HYS`}
                elementIdToPrint="pdf-content"
            />

            {/* Floating Action Bar Premium */}
            <div className="no-print floating-action-bar">
                <button
                    onClick={handleSave}
                    className="btn-floating-action"
                    style={{ background: '#36B37E', color: '#ffffff' }}
                >
                    <Save size={18} /> GUARDAR
                </button>
                <button
                    onClick={() => requirePro(() => setShowShareModal(true))}
                    className="btn-floating-action"
                    style={{ background: '#0052CC', color: '#ffffff' }}
                >
                    <Share2 size={18} /> COMPARTIR
                </button>
                <button
                    onClick={handlePrint}
                    className="btn-floating-action"
                    style={{ background: '#FF8B00', color: '#ffffff' }}
                >
                    <Printer size={18} /> IMPRIMIR PDF
                </button>
            </div>
            <div className="no-print">
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '1.5rem', zIndex: 10, flexWrap: 'wrap', gap: '1rem' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                        <button onClick={() => navigate('/#tools')} style={{ padding: '0.5rem', background: 'var(--color-surface)', border: '1px solid var(--color-border)', cursor: 'pointer', borderRadius: '50%', color: 'var(--color-text)' }}>
                            <ArrowLeft size={20} />
                        </button>
                        <h1 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 800 }}>Estrés Térmico Calculadora</h1>
                    </div>
                    <button onClick={() => navigate('/thermal-stress-history')} className="btn-outline" style={{ margin: 0, display: 'flex', alignItems: 'center', gap: '0.5rem', padding: '0.5rem 1.2rem' }}>
                        <Search size={18} /> Historial
                    </button>
                </div>

                <div className="grid-2-cols" style={{ gap: '1.5rem' }}>

                    {/* Columna Izquierda: Formulario de Configuración */}
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                        <div className="card" style={{ padding: '1.5rem' }}>
                            <h2 style={{ fontSize: '1.1rem', margin: '0 0 1rem', display: 'flex', alignItems: 'center', gap: '0.5rem', color: 'var(--color-primary)' }}>
                                <Settings2 size={20} /> Metadatos del Puesto
                            </h2>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                                <div>
                                    <label>Puesto de Trabajo a Evaluar</label>
                                    <input type="text" value={formData.puesto} onChange={e => handleInput('puesto', e.target.value)} placeholder="Ej. Operador de Horno 3" style={{ fontWeight: 'bold' }} />
                                </div>
                                <div className="grid-2-cols" style={{ gap: '1rem' }}>
                                    <div>
                                        <label>Sector / Área</label>
                                        <input type="text" value={formData.sector} onChange={e => handleInput('sector', e.target.value)} placeholder="Ej. Fundición" />
                                    </div>
                                    <div>
                                        <label>Fecha de Medición</label>
                                        <input type="date" value={formData.fecha} onChange={e => handleInput('fecha', e.target.value)} />
                                    </div>
                                </div>
                                <div>
                                    <label>Tarea Principal que Realiza</label>
                                    <input type="text" value={formData.tarea} onChange={e => handleInput('tarea', e.target.value)} placeholder="Ej. Carga manual de lingotes y control visual" />
                                </div>
                            </div>
                        </div>

                        <div className="card" style={{ padding: '1.5rem' }}>
                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem', flexWrap: 'wrap', gap: '1rem' }}>
                                <h2 style={{ fontSize: '1.1rem', margin: 0, display: 'flex', alignItems: 'center', gap: '0.5rem', color: '#f97316' }}>
                                    <ThermometerSun size={20} /> Mediciones Ambientales
                                </h2>
                                <label style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.85rem', cursor: 'pointer', background: 'rgba(249,115,22,0.1)', padding: '0.3rem 0.8rem', borderRadius: '12px', color: '#c2410c', fontWeight: 700 }}>
                                    <input type="checkbox" checked={formData.cargaSolar} onChange={e => handleInput('cargaSolar', e.target.checked)} style={{ margin: 0 }} /> Al sol / Carga Solar
                                </label>
                            </div>

                            <div className="grid-2-cols" style={{ gap: '1rem' }}>
                                <div>
                                    <label>Temp. Bulbo Húmedo natural (Tbh) °C</label>
                                    <input type="number" step="0.1" value={formData.tbh} onChange={e => handleInput('tbh', e.target.value)} placeholder="Ej: 22.5" />
                                </div>
                                <div>
                                    <label>Temp. Globo (Tg) °C</label>
                                    <input type="number" step="0.1" value={formData.tg} onChange={e => handleInput('tg', e.target.value)} placeholder="Ej: 28.1" />
                                </div>
                                {formData.cargaSolar && (
                                    <div style={{ gridColumn: '1 / -1' }}>
                                        <label>Temp. Bulbo Seco (Tbs) °C</label>
                                        <input type="number" step="0.1" value={formData.tbs} onChange={e => handleInput('tbs', e.target.value)} placeholder="Temp. Aire" style={{ borderColor: '#f97316' }} />
                                        <span style={{ fontSize: '0.75rem', color: 'var(--color-text-muted)' }}>* Requerido al activar carga solar por ecuación de ponderación.</span>
                                    </div>
                                )}
                            </div>
                        </div>

                        <div className="card" style={{ padding: '1.5rem' }}>
                            <h2 style={{ fontSize: '1.1rem', margin: '0 0 1rem', display: 'flex', alignItems: 'center', gap: '0.5rem', color: '#8b5cf6' }}>
                                <RefreshCw size={20} /> Exigencia Física y Régimen
                            </h2>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                                <div>
                                    <label>Metabolismo / Carga de Trabajo</label>
                                    <select value={formData.ritmo} onChange={e => handleInput('ritmo', e.target.value)} style={{ padding: '0.8rem', width: '100%', borderRadius: '12px', border: '1px solid var(--color-border)', background: 'var(--color-surface)', color: 'var(--color-text)' }}>
                                        <option value="liviano">Liviana (Ej. Trabajo en banco, sentados 200W)</option>
                                        <option value="moderado">Moderada (Ej. Caminar con arrastre, empuje sostenido 300W)</option>
                                        <option value="pesado">Pesada (Ej. Trabajo intenso con pico/pala, cargas pesadas 400W)</option>
                                    </select>
                                </div>
                                <div>
                                    <label>Ciclo Trabajo / Descanso (Turno)</label>
                                    <select value={formData.ciclo} onChange={e => handleInput('ciclo', e.target.value)} style={{ padding: '0.8rem', width: '100%', borderRadius: '12px', border: '1px solid var(--color-border)', background: 'var(--color-surface)', color: 'var(--color-text)' }}>
                                        <option value="continuo">Trabajo Continuo (o &lt; 25% descanso/hr)</option>
                                        <option value="75_25">75% Trabajo, 25% Descanso c/hora</option>
                                        <option value="50_50">50% Trabajo, 50% Descanso c/hora</option>
                                        <option value="25_75">25% Trabajo, 75% Descanso c/hora</option>
                                    </select>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Columna Derecha: Panel de Resultados en Vivo */}
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                        <div className="card shadow-xl" style={{ border: '2px solid var(--color-primary)', background: 'var(--color-surface)', overflow: 'hidden' }}>
                            <div style={{ background: 'var(--color-primary)', color: 'white', padding: '1rem', display: 'flex', alignItems: 'center', gap: '0.5rem', fontWeight: 800 }}>
                                <Calculator size={20} /> Dictamen {countryNorms.thermal.split(' (')[0]}
                            </div>

                            <div style={{ padding: '2rem', textAlign: 'center' }}>
                                <div style={{ fontSize: '0.9rem', color: 'var(--color-text-muted)', fontWeight: 700, textTransform: 'uppercase', marginBottom: '0.5rem' }}>
                                    Índice TGBH Calculado
                                </div>
                                <div style={{ fontSize: '3.5rem', fontWeight: 900, lineHeight: 1, color: 'var(--color-text)', marginBottom: '1.5rem' }}>
                                    {resultados.tgbh !== null ? `${resultados.tgbh}°C` : '--'}
                                </div>

                                <div style={{ display: 'grid', gridTemplateColumns: '1fr', gap: '0.5rem', marginBottom: '2rem' }}>
                                    <div style={{ display: 'flex', justifyContent: 'space-between', padding: '0.8rem 1.5rem', background: 'var(--color-background)', borderRadius: '12px', border: '1px solid var(--color-border)' }}>
                                        <span style={{ color: 'var(--color-text-muted)', fontWeight: 600 }}>Carga Solar Activa:</span>
                                        <span style={{ fontWeight: 800, color: formData.cargaSolar ? '#f97316' : 'var(--color-text)' }}>{formData.cargaSolar ? 'SÍ' : 'NO'}</span>
                                    </div>
                                    <div style={{ display: 'flex', justifyContent: 'space-between', padding: '0.8rem 1.5rem', background: 'var(--color-background)', borderRadius: '12px', border: '1px solid var(--color-border)' }}>
                                        <span style={{ color: 'var(--color-text-muted)', fontWeight: 600 }}>Límite Máximo Permitido:</span>
                                        <span style={{ fontWeight: 800 }}>{resultados.limite !== null ? `${resultados.limite}°C` : '--'}</span>
                                    </div>
                                </div>

                                {/* Alerta de Dictamen */}
                                {resultados.admisible !== null ? (
                                    <div style={{
                                        padding: '1.5rem', borderRadius: '16px', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.8rem',
                                        background: resultados.admisible ? 'rgba(16,185,129,0.1)' : 'rgba(239,68,68,0.1)',
                                        color: resultados.admisible ? '#059669' : '#dc2626',
                                        border: `2px solid ${resultados.admisible ? '#10b981' : '#ef4444'}`
                                    }}>
                                        {resultados.admisible ? <CheckCircle2 size={32} /> : <TriangleAlert size={32} />}
                                        <div style={{ textAlign: 'left' }}>
                                            <div style={{ fontSize: '1.2rem', fontWeight: 900, textTransform: 'uppercase' }}>
                                                {resultados.admisible ? 'Admisible' : 'Riesgo Térmico'}
                                            </div>
                                            <div style={{ fontSize: '0.85rem', fontWeight: 600, opacity: 0.9 }}>
                                                {resultados.admisible ? 'El puesto no requiere rotación extra.' : 'El TGBH supera el valor tabla. Urgente rotación o mitigación.'}
                                            </div>
                                        </div>
                                    </div>
                                ) : (
                                    <div style={{ padding: '1.5rem', borderRadius: '16px', background: 'var(--color-background)', color: 'var(--color-text-muted)', border: '1px dashed var(--color-border)' }}>
                                        <Info size={24} style={{ margin: '0 auto 0.5rem', opacity: 0.5 }} />
                                        Ingrese las temperaturas de globo y bulbo húmedo para ver el resultado oficial.
                                    </div>
                                )}

                            </div>


                        </div>

                        {/* Formula reference card */}
                        <div className="card" style={{ padding: '1.5rem', background: '#f8fafc', border: '1px solid #cbd5e1' }}>
                            <h3 style={{ fontSize: '0.9rem', color: '#475569', margin: '0 0 0.8rem 0', display: 'flex', alignItems: 'center', gap: '0.4rem' }}>
                                <Info size={16} /> Fundamento Legal
                            </h3>
                            <p style={{ fontSize: '0.8rem', color: '#64748b', margin: '0 0 0.5rem 0', lineHeight: 1.5 }}>
                                <strong>{countryNorms.thermal} ({countryNorms.general}).</strong> El valor adoptado es TGBH (Índice T° Globo Bulbo Húmedo).
                            </p>
                            <code style={{ fontSize: '0.75rem', background: '#e2e8f0', padding: '0.4rem', borderRadius: '4px', display: 'block', color: '#0f172a' }}>
                                Int: TGBH = 0.7(Tbh) + 0.3(Tg)<br />
                                Ext Sol: TGBH = 0.7(Tbh) + 0.2(Tg) + 0.1(Tbs)
                            </code>
                        </div>
                    </div>
                </div>
            </div>

            {/* PRO upgrade banner for free users */}
            <AdBanner />

            {/* Hidden report for direct printing */}
            <div className="print-only">
                <ThermalStressPdfGenerator
                    report={{
                        id: Date.now(),
                        date: new Date().toISOString(),
                        evaluador: currentUser?.displayName || 'Profesional HSE',
                        ...formData,
                        resultados
                    }}
                    onBack={() => { }}
                />
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import {
    ArrowLeft, Save, Users, Calendar, Clock, BookOpen,
    UserPlus, Trash2, CheckCircle2, FileText, Briefcase,
    Plus, Share2, Printer, ChevronLeft, ChevronRight
} from 'lucide-react';
import ShareModal from '../components/ShareModal';
import TrainingPdfGenerator from '../components/TrainingPdfGenerator';
import { useAuth } from '../contexts/AuthContext';
import { useSync } from '../contexts/SyncContext';
import { useDocumentTitle } from '../hooks/useDocumentTitle';
import toast from 'react-hot-toast';
import { usePaywall } from '../hooks/usePaywall';
import AdBanner from '../components/AdBanner';

export default function TrainingManagement() {
    useDocumentTitle('Gestión de Capacitaciones');
    const navigate = useNavigate();
    const location = useLocation();
    const { currentUser } = useAuth();
    const { syncCollection } = useSync();
    const { requirePro } = usePaywall();

    const editData = location.state?.editData;

    const [formData, setFormData] = useState(editData || {
        tema: '',
        expositor: currentUser?.displayName || '',
        fecha: new Date().toISOString().split('T')[0],
        duracion: '1',
        empresa: '',
        ubicacion: '',
        observaciones: '',
        asistentes: [
            { nombre: '', dni: '', puesto: '' }
        ]
    });

    const [viewMode, setViewMode] = useState('edit'); // 'edit' or 'report'
    const [showShareModal, setShowShareModal] = useState(false);

    const handlePrint = () => requirePro(() => window.print());

    const handleInputChange = (field, value) => {
        setFormData(prev => ({ ...prev, [field]: value }));
    };

    const handleArrayChange = (index, field, value) => {
        setFormData(prev => {
            const newAsistentes = [...prev.asistentes];
            newAsistentes[index] = { ...newAsistentes[index], [field]: value };
            return { ...prev, asistentes: newAsistentes };
        });
    };

    const addAsistente = () => {
        setFormData(prev => ({
            ...prev,
            asistentes: [...prev.asistentes, { nombre: '', dni: '', puesto: '' }]
        }));
    };

    const removeAsistente = (index) => {
        setFormData(prev => ({
            ...prev,
            asistentes: prev.asistentes.filter((_, i) => i !== index)
        }));
    };

    const doSave = () => {
        if (!formData.tema || !formData.fecha) {
            toast.error('El tema y la fecha son obligatorios.');
            return;
        }

        // Filter out completely empty rows before saving
        const asistentesValidos = formData.asistentes.filter(a => a.nombre.trim() !== '' || a.dni.trim() !== '');

        if (asistentesValidos.length === 0) {
            toast.error('Debe ingresar al menos 1 asistente a la capacitación.');
            return;
        }

        const report = {
            id: editData?.id || Date.now(),
            date: editData?.date || new Date().toISOString(),
            ...formData,
            asistentes: asistentesValidos
        };

        let history = [];
        try {
            const raw = localStorage.getItem('training_history');
            if (raw && raw !== 'undefined') {
                const parsed = JSON.parse(raw);
                history = Array.isArray(parsed) ? parsed : [];
            }
        } catch (e) {
            console.error('[TrainingManagement] Error parsing history:', e);
            history = [];
        }

        if (editData) {
            // Update existing
            history = history.map(item => item.id === editData.id ? report : item);
        } else {
            // Add new
            history.unshift(report);
        }

        localStorage.setItem('training_history', JSON.stringify(history));
        syncCollection('training_history', history);

        toast.success(editData ? 'Capacitación actualizada correctamente.' : 'Capacitación registrada correctamente.');
        navigate('/training-history');
    };

    const handleSave = () => requirePro(doSave);

    const handleBack = () => {
        navigate('/training-history');
    };

    return (
        <div className="container" style={{ paddingBottom: '6rem', minHeight: '100vh', display: 'flex', flexDirection: 'column' }}>
            <div className="no-print">
                <ShareModal
                    open={showShareModal}
                    onClose={() => setShowShareModal(false)}
                    title="Compartir Capacitación"
                    text={`📊 Registro de Capacitación: ${formData.tema}\n📅 Fecha: ${formData.fecha}\n👥 Asistentes: ${formData.asistentes.length}\n\nEnviado desde Asistente HYS`}
                    elementIdToPrint="pdf-content"
                />

                {/* Floating Action Bar Premium */}
                <div className="floating-action-bar">
                    <button
                        onClick={handleSave}
                        className="btn-floating-action"
                        style={{ background: '#36B37E', color: '#ffffff' }}
                    >
                        <Save size={18} /> GUARDAR
                    </button>
                    <button
                        onClick={() => requirePro(() => setShowShareModal(true))}
                        className="btn-floating-action"
                        style={{ background: '#0052CC', color: '#ffffff' }}
                    >
                        <Share2 size={18} /> COMPARTIR
                    </button>
                    <button
                        onClick={handlePrint}
                        className="btn-floating-action"
                        style={{ background: '#FF8B00', color: '#ffffff' }}
                    >
                        <Printer size={18} /> IMPRIMIR PDF
                    </button>
                </div>

                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '1.5rem', zIndex: 10 }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                        <button onClick={() => navigate('/')} style={{ padding: '0.5rem', background: 'var(--color-surface)', border: '1px solid var(--color-border)', cursor: 'pointer', borderRadius: '50%', color: 'var(--color-text)' }}>
                            <ArrowLeft size={20} />
                        </button>
                        <h1 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 800 }}>{editData ? 'Editar Capacitación' : 'Nueva Capacitación'}</h1>
                    </div>
                </div>

                <div className="card" style={{ padding: '2rem', marginBottom: '1.5rem' }}>
                    <h2 style={{ fontSize: '1.1rem', marginBottom: '1.5rem', display: 'flex', alignItems: 'center', gap: '0.5rem', color: 'var(--color-primary)' }}>
                        <BookOpen size={20} /> Metadatos de la Charla
                    </h2>

                    <div className="grid-2-cols">
                        <div style={{ gridColumn: '1 / -1' }}>
                            <label>Tema / Título de la Capacitación</label>
                            <input
                                type="text"
                                placeholder="Ej. Inducción de Seguridad, Uso de EPP, Primeros Auxilios..."
                                value={formData.tema}
                                onChange={e => handleInputChange('tema', e.target.value)}
                                style={{ fontWeight: 'bold' }}
                            />
                        </div>
                        <div>
                            <label>Expositor / Instructor</label>
                            <input
                                type="text"
                                value={formData.expositor}
                                onChange={e => handleInputChange('expositor', e.target.value)}
                            />
                        </div>
                        <div>
                            <label>Sector / Lugar de Dictado</label>
                            <input
                                type="text"
                                placeholder="Ej. Sala de Reuniones 1"
                                value={formData.ubicacion}
                                onChange={e => handleInputChange('ubicacion', e.target.value)}
                            />
                        </div>
                        <div>
                            <label>Fecha</label>
                            <input
                                type="date"
                                value={formData.fecha}
                                onChange={e => handleInputChange('fecha', e.target.value)}
                            />
                        </div>
                        <div>
                            <label>Duración (Horas)</label>
                            <input
                                type="number"
                                min="0.5"
                                step="0.5"
                                value={formData.duracion}
                                onChange={e => handleInputChange('duracion', e.target.value)}
                            />
                        </div>
                        <div style={{ gridColumn: '1 / -1' }}>
                            <label>Empresa / Contratista (Opcional)</label>
                            <input
                                type="text"
                                placeholder="Si aplica a una subcontratista específica"
                                value={formData.empresa}
                                onChange={e => handleInputChange('empresa', e.target.value)}
                            />
                        </div>
                    </div>
                </div>

                <div className="card" style={{ flex: 1, padding: '2rem' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                        <h2 style={{ fontSize: '1.1rem', margin: 0, display: 'flex', alignItems: 'center', gap: '0.5rem', color: 'var(--color-primary)' }}>
                            <Users size={20} /> Planilla de Asistentes
                        </h2>
                        <span style={{ fontSize: '0.85rem', fontWeight: 600, background: 'var(--color-surface)', border: '1px solid var(--color-border)', padding: '0.3rem 0.8rem', borderRadius: '20px' }}>
                            {formData.asistentes.length} cargados
                        </span>
                    </div>

                    <div className="hidden sm:grid" style={{ gridTemplateColumns: '2fr 1fr 1.5fr 40px', gap: '1rem', marginBottom: '0.5rem', padding: '0 0.5rem', fontSize: '0.85rem', fontWeight: 700, color: 'var(--color-text-muted)' }}>
                        <div>Apellido y Nombre</div>
                        <div>DNI / CUIL</div>
                        <div>Puesto / Sector</div>
                        <div></div>
                    </div>

                    {formData.asistentes.map((asistente, i) => (
                        <div key={i} className="responsive-list-card">

                            <div className="responsive-card-row">
                                <div style={{ display: 'flex', flexDirection: 'column', gap: '0.4rem', flex: 2 }}>
                                    <label className="sm:hidden" style={{ fontSize: '0.75rem', fontWeight: 700, margin: 0 }}>Apellido y Nombre</label>
                                    <input
                                        type="text"
                                        placeholder="Nombre completo"
                                        value={asistente.nombre}
                                        onChange={e => handleArrayChange(i, 'nombre', e.target.value)}
                                        style={{ margin: 0, height: '44px' }}
                                    />
                                </div>
                                <div style={{ display: 'flex', flexDirection: 'column', gap: '0.4rem', flex: 1 }}>
                                    <label className="sm:hidden" style={{ fontSize: '0.75rem', fontWeight: 700, margin: 0 }}>DNI / CUIL</label>
                                    <input
                                        type="text"
                                        placeholder="DNI..."
                                        value={asistente.dni}
                                        onChange={e => handleArrayChange(i, 'dni', e.target.value)}
                                        style={{ margin: 0, height: '44px' }}
                                    />
                                </div>
                                <div style={{ display: 'flex', flexDirection: 'column', gap: '0.4rem', flex: 1.5 }}>
                                    <label className="sm:hidden" style={{ fontSize: '0.75rem', fontWeight: 700, margin: 0 }}>Puesto / Sector</label>
                                    <input
                                        type="text"
                                        placeholder="Ej. Soldador"
                                        value={asistente.puesto}
                                        onChange={e => handleArrayChange(i, 'puesto', e.target.value)}
                                        style={{ margin: 0, height: '44px' }}
                                    />
                                </div>

                                {/* Acción de Borrar (Móvil full, PC cuadrado 44px) */}
                                {formData.asistentes.length > 1 ? (
                                    <div style={{ display: 'flex' }} className="mt-2 sm:mt-0 sm:ml-2 sm:w-[44px] flex-none">
                                        <style>{`
                                            @media (min-width: 640px) {
                                                .btn-del-${i} { width: 44px !important; flex: none !important; margin-top: 0 !important; }
                                            }
                                        `}</style>
                                        <button
                                            onClick={() => removeAsistente(i)}
                                            className={`delete-asistente-btn btn-del-${i}`}
                                            title="Eliminar Asistente"
                                            style={{
                                                width: '100%', height: '44px', borderRadius: '8px',
                                                marginTop: '0.5rem', padding: 0, display: 'flex',
                                                alignItems: 'center', justifyContent: 'center'
                                            }}
                                        >
                                            <Trash2 size={20} />
                                        </button>
                                    </div>
                                ) : (
                                    <div className="hidden sm:block" style={{ width: '44px', flex: 'none' }}></div>
                                )}
                            </div>
                        </div>
                    ))}

                    <button
                        className="btn-outline"
                        onClick={addAsistente}
                        style={{
                            width: '100%', padding: '1rem', borderStyle: 'dashed',
                            borderWidth: '2px', display: 'flex', alignItems: 'center',
                            justifyContent: 'center', gap: '0.5rem', marginTop: '1rem'
                        }}
                    >
                        <UserPlus size={18} /> Añadir Fila de Asistente
                    </button>
                </div>
            </div>

            {/* PRO upgrade banner for free users */}
            <AdBanner />

            {/* Hidden report for direct printing */}
            <div className="print-only">
                <TrainingPdfGenerator training={formData} onBack={() => { }} />
            </div>

        </div>
    );
}

import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import {
    ArrowLeft, Save, Plus, Trash2, Printer,
    ShieldCheck, Building2, User, Calendar,
    CheckCircle2, AlertCircle, HelpCircle, Pencil, Info, Share2,
    Users, Clock, Zap, Flame, HardHat, Construction
} from 'lucide-react';
import { useAuth } from '../contexts/AuthContext';
import { useSync } from '../contexts/SyncContext';
import ShareModal from '../components/ShareModal';
import { usePaywall } from '../hooks/usePaywall';
import { permitTypes } from '../data/workPermits';
import toast from 'react-hot-toast';
import { useDocumentTitle } from '../hooks/useDocumentTitle';
import CompanyLogo from '../components/CompanyLogo';

export default function WorkPermit() {
    const navigate = useNavigate();
    const location = useLocation();
    const { currentUser } = useAuth();
    const { syncCollection } = useSync();
    const { requirePro } = usePaywall();
    useDocumentTitle('Permiso de Trabajo');

    // Default state
    const [formData, setFormData] = useState(() => ({
        id: null,
        numeroPermiso: '',
        empresa: '',
        obra: '',
        fecha: new Date().toISOString().split('T')[0],
        tipoPermiso: permitTypes[0].id,
        validezDesde: '08:00',
        validezHasta: '18:00',
        checklist: permitTypes[0].questions.map((q, i) => ({ id: Date.now() + i, pregunta: q, estado: 'Cumple', observaciones: '' })),
        personal: [
            { id: 1, nombre: '', dni: '', firma: true }
        ],
        eppRequeridos: ['Casco', 'Calzado de Seguridad', 'Guantes', 'Anteojos'],
        observacionesGenerales: ''
    }));

    const [professional, setProfessional] = useState({
        name: 'Profesional',
        license: '',
        signature: null
    });

    const [showSignatures, setShowSignatures] = useState({
        supervisor: true,
        professional: true
    });

    const [showShare, setShowShare] = useState(false);

    // Load data for editing
    useEffect(() => {
        if (location.state?.editData) {
            setFormData(location.state.editData);
        }
    }, [location.state]);

    // Load professional data
    useEffect(() => {
        const savedData = localStorage.getItem('personalData');
        const savedSigData = localStorage.getItem('signatureStampData');
        if (savedData) {
            const data = JSON.parse(savedData);
            let signature = null;
            if (savedSigData) {
                signature = JSON.parse(savedSigData).signature;
            }
            setProfessional({
                name: data.name || 'Profesional',
                license: data.license || '',
                signature: signature
            });
        }
    }, []);

    const handleTypeChange = (typeId) => {
        const selectedType = permitTypes.find(t => t.id === typeId);
        if (selectedType) {
            setFormData({
                ...formData,
                tipoPermiso: typeId,
                checklist: selectedType.questions.map((q, i) => ({ id: Date.now() + i, pregunta: q, estado: 'Cumple', observaciones: '' }))
            });
        }
    };

    const updateChecklist = (id, field, value) => {
        const newList = formData.checklist.map(item =>
            item.id === id ? { ...item, [field]: value } : item
        );
        setFormData({ ...formData, checklist: newList });
    };

    const addChecklistItem = () => {
        const newItem = {
            id: Date.now(),
            pregunta: '',
            estado: 'Cumple',
            observaciones: ''
        };
        setFormData({
            ...formData,
            checklist: [...formData.checklist, newItem]
        });
    };

    const removeChecklistItem = (id) => {
        setFormData({
            ...formData,
            checklist: formData.checklist.filter(item => item.id !== id)
        });
    };

    const addPersonnel = () => {
        const newId = Math.max(0, ...formData.personal.map(p => p.id)) + 1;
        setFormData({
            ...formData,
            personal: [...formData.personal, { id: newId, nombre: '', dni: '', firma: true }]
        });
    };

    const removePersonnel = (id) => {
        if (formData.personal.length > 1) {
            setFormData({
                ...formData,
                personal: formData.personal.filter(p => p.id !== id)
            });
        }
    };

    const updatePersonnel = (id, field, value) => {
        setFormData({
            ...formData,
            personal: formData.personal.map(p => p.id === id ? { ...p, [field]: value } : p)
        });
    };

    const handleSave = async () => {
        requirePro(async () => {
            if (!formData.empresa) {
                toast.error('Por favor complete el nombre de la empresa');
                return;
            }
            const historyRaw = localStorage.getItem('work_permits_history');
            const history = historyRaw ? JSON.parse(historyRaw) : [];
            const entryId = formData.id || Date.now().toString();

            const newEntry = {
                ...formData,
                id: entryId,
                professionalName: professional.name,
                professionalLicense: professional.license,
                professionalSignature: professional.signature,
                createdAt: formData.createdAt || new Date().toISOString()
            };

            let updated;
            if (formData.id) {
                updated = history.map(h => h.id === entryId ? newEntry : h);
            } else {
                updated = [newEntry, ...history];
            }

            localStorage.setItem('work_permits_history', JSON.stringify(updated));
            await syncCollection('work_permits_history', updated);
            toast.success('Permiso de Trabajo guardado con éxito');
            navigate('/work-permit-history');
        });
    };

    const handlePrint = () => requirePro(() => window.print());
    const handleShare = () => requirePro(() => setShowShare(true));

    const selectedTypeLabel = permitTypes.find(t => t.id === formData.tipoPermiso)?.label || 'Permiso de Trabajo';

    return (
        <div className="container" style={{ maxWidth: '1000px', paddingBottom: '8rem' }}>
            <ShareModal
                open={showShare}
                onClose={() => setShowShare(false)}
                title={`Permiso de Trabajo – ${formData.empresa}`}
                text={`📄 Permiso de Trabajo: ${selectedTypeLabel}\n🏗️ Empresa: ${formData.empresa}\n📅 Fecha: ${formData.fecha}\n⏰ Validez: ${formData.validezDesde} a ${formData.validezHasta}\n\nGenerado con Asistente HYS`}
                elementIdToPrint="pdf-content"
            />

            {/* Action Bar */}
            <div className="no-print floating-action-bar">
                <button onClick={handleSave} className="btn-floating-action" style={{ background: '#36B37E', color: '#ffffff' }}>
                    <Save size={18} /> GUARDAR
                </button>
                <button onClick={handleShare} className="btn-floating-action" style={{ background: '#0052CC', color: '#ffffff' }}>
                    <Share2 size={18} /> COMPARTIR
                </button>
                <button onClick={handlePrint} className="btn-floating-action" style={{ background: '#FF8B00', color: '#ffffff' }}>
                    <Printer size={18} /> IMPRIMIR PDF
                </button>
            </div>

            <div className="no-print" style={{
                marginBottom: '2rem',
                padding: '2rem',
                background: 'var(--color-surface)',
                borderRadius: '20px',
                border: '1px solid #EBECF0',
                display: 'flex',
                justifyContent: 'space-between',
                gap: '1.5rem',
                alignItems: 'center'
            }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                    <button onClick={() => navigate('/#tools')} style={{ padding: '0.5rem', background: 'var(--color-background)', borderRadius: '10px', border: 'none', cursor: 'pointer', color: 'var(--color-text)' }}>
                        <ArrowLeft size={20} />
                    </button>
                    <div>
                        <h1 style={{ margin: 0, fontSize: '1.5rem', fontWeight: 900, color: 'var(--color-text)' }}>Permisos de Trabajo</h1>
                        <p style={{ margin: 0, color: 'var(--color-text-muted)', fontWeight: 600, fontSize: '0.8rem', textTransform: 'uppercase' }}>Gestión de Riesgos Especiales</p>
                    </div>
                </div>
            </div>

            {/* Print Area */}
            <div id="pdf-content" className="bg-white text-black p-6 sm:p-10 shadow-xl mx-auto print-area border border-slate-200 rounded-2xl print:shadow-none print:border-none" style={{ width: '100%', boxSizing: 'border-box' }}>

                {/* Header */}
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 2fr 1fr', alignItems: 'center', borderBottom: '4px solid #333', paddingBottom: '1.5rem', marginBottom: '2rem', width: '100%', gap: '1.5rem' }}>
                    <div style={{ textAlign: 'left' }}>
                        <p style={{ margin: 0, fontWeight: 700, fontSize: '0.65rem', textTransform: 'uppercase', color: '#64748b', letterSpacing: '0.05em' }}>Sistema de Gestión</p>
                        <p style={{ margin: 0, fontWeight: 900, fontSize: '0.75rem', textTransform: 'uppercase', color: '#1e293b' }}>Control H&S</p>
                    </div>

                    <div style={{ textAlign: 'center' }}>
                        <h2 style={{ margin: 0, fontSize: '1.2rem', fontWeight: 900, color: 'var(--color-primary)', textTransform: 'uppercase', letterSpacing: '1px', lineHeight: 1.2 }}>
                            Permiso de Trabajo
                        </h2>
                        <p style={{ margin: '4px 0 0 0', fontSize: '0.65rem', color: '#64748b', fontWeight: 600 }}>{selectedTypeLabel}</p>
                    </div>

                    <div style={{ display: 'flex', justifyContent: 'flex-end', alignItems: 'center', gap: '10px' }}>
                        <div style={{ textAlign: 'right', display: 'flex', flexDirection: 'column' }}>
                             <span style={{ fontSize: '0.6rem', fontWeight: 800, color: '#999' }}>N° PERMISO</span>
                             <span style={{ fontSize: '1rem', fontWeight: 900 }}>{formData.numeroPermiso || '____'}</span>
                        </div>
                        <CompanyLogo style={{ height: '40px', width: 'auto', maxWidth: '120px', objectFit: 'contain' }} />
                    </div>
                </div>

                {/* Form Grid */}
                <div style={{ border: '2px solid #ddd', borderRadius: '10px', overflow: 'hidden', marginBottom: '2rem' }}>
                    <div className="grid grid-cols-1 sm:grid-cols-2">
                        <DocBox label="CLIENTE / EMPRESA" value={formData.empresa} onChange={v => setFormData({ ...formData, empresa: v })} />
                        <DocBox label="OBRA / UBICACIÓN" value={formData.obra} onChange={v => setFormData({ ...formData, obra: v })} borderLeft />
                    </div>
                    <div className="grid grid-cols-1 sm:grid-cols-4">
                        <DocBox label="FECHA" value={formData.fecha} onChange={v => setFormData({ ...formData, fecha: v })} type="date" borderTop />
                        <DocBox label="HORA INICIO" value={formData.validezDesde} onChange={v => setFormData({ ...formData, validezDesde: v })} type="time" borderLeft borderTop />
                        <DocBox label="HORA FIN" value={formData.validezHasta} onChange={v => setFormData({ ...formData, validezHasta: v })} type="time" borderLeft borderTop />
                        <DocBox label="TIPO DE TRABAJO" borderLeft borderTop noInput>
                            <select
                                value={formData.tipoPermiso}
                                onChange={e => handleTypeChange(e.target.value)}
                                className="no-print"
                                style={{ border: 'none', background: 'transparent', fontWeight: 800, width: '100%', outline: 'none' }}
                            >
                                {permitTypes.map(t => <option key={t.id} value={t.id}>{t.label}</option>)}
                            </select>
                            <div className="print-only" style={{ fontWeight: 800 }}>{selectedTypeLabel}</div>
                        </DocBox>
                    </div>
                </div>

                {/* Checklist Section */}
                <div style={{ marginBottom: '2.5rem' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
                        <h3 style={{ fontSize: '1rem', fontWeight: 900, margin: 0, color: 'var(--color-text)', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                            <ShieldCheck size={20} /> VERIFICACIÓN PREVENTIVA (CHECKLIST)
                        </h3>
                        <button className="no-print" onClick={addChecklistItem} style={{ background: '#3b82f6', color: '#ffffff', border: 'none', padding: '0.4rem 0.8rem', borderRadius: '8px', fontSize: '0.7rem', fontWeight: 800, cursor: 'pointer' }}>
                            + AGREGAR PREGUNTA
                        </button>
                    </div>
                    <div style={{ border: '1px solid #eee', borderRadius: '12px', overflow: 'hidden' }}>
                        <div style={{ display: 'grid', gridTemplateColumns: '2fr 100px 1.5fr 40px', background: 'var(--color-background)', padding: '0.6rem 1rem', borderBottom: '2px solid #ddd', fontWeight: 800, fontSize: '0.7rem', color: '#666' }} className="hidden sm:grid">
                            <div>PREGUNTA / ITEM</div>
                            <div style={{ textAlign: 'center' }}>ESTADO</div>
                            <div>OBSERVACIONES</div>
                            <div className="no-print"></div>
                        </div>
                        {formData.checklist.map((item, idx) => (
                            <div key={item.id} style={{ padding: '1rem', borderBottom: '1px solid #f0f0f0', background: idx % 2 === 0 ? '#fafafa' : 'var(--color-surface)' }} className="grid grid-cols-1 sm:grid-cols-[2fr_100px_1.5fr_40px] gap-4 sm:gap-4 items-center">
                                <div className="flex flex-col sm:block">
                                    <span className="sm:hidden text-[0.6rem] font-bold text-blue-500 uppercase mb-1">Item/Pregunta:</span>
                                    <input
                                        type="text"
                                        value={item.pregunta}
                                        onChange={e => updateChecklist(item.id, 'pregunta', e.target.value)}
                                        style={{ border: 'none', background: 'transparent', width: '100%', outline: 'none', fontWeight: 600, fontSize: '0.85rem' }}
                                        placeholder="Descripción de la tarea o riesgo..."
                                    />
                                </div>
                                <div className="flex items-center justify-between sm:justify-center">
                                    <span className="sm:hidden text-[0.6rem] font-bold text-blue-500 uppercase">Estado:</span>
                                    <div className="no-print" style={{ display: 'flex', gap: '5px' }}>
                                        <StatusBtn active={item.estado === 'Cumple'} onClick={() => updateChecklist(item.id, 'estado', 'Cumple')} label="SI" />
                                        <StatusBtn active={item.estado === 'No Cumple'} onClick={() => updateChecklist(item.id, 'estado', 'No Cumple')} label="NO" color="#FF4D4F" />
                                    </div>
                                    <div className="print-only" style={{ fontWeight: 900, color: item.estado === 'No Cumple' ? '#FF4D4F' : 'inherit' }}>{item.estado === 'Cumple' ? 'SI' : 'NO'}</div>
                                </div>
                                <div className="flex flex-col sm:block">
                                    <span className="sm:hidden text-[0.6rem] font-bold text-blue-500 uppercase mb-1">Observaciones:</span>
                                    <input
                                        type="text"
                                        value={item.observaciones}
                                        onChange={e => updateChecklist(item.id, 'observaciones', e.target.value)}
                                        style={{ border: 'none', borderBottom: '1px solid #eee', background: 'transparent', width: '100%', outline: 'none', fontSize: '0.8rem' }}
                                        placeholder="Detalle / Sector..."
                                    />
                                </div>
                                <div className="no-print text-right">
                                    <button onClick={() => removeChecklistItem(item.id)} style={{ background: 'transparent', border: 'none', color: '#ff4d4f', cursor: 'pointer' }}>
                                        <Trash2 size={16} />
                                    </button>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Personnel Section */}
                <div style={{ marginBottom: '2.5rem' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
                        <h3 style={{ fontSize: '1rem', fontWeight: 900, margin: 0, color: 'var(--color-text)', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                            <Users size={20} /> PERSONAL AUTORIZADO
                        </h3>
                        <button className="no-print" onClick={addPersonnel} style={{ background: '#3b82f6', color: '#ffffff', border: 'none', padding: '0.4rem 0.8rem', borderRadius: '8px', fontSize: '0.7rem', fontWeight: 800, cursor: 'pointer' }}>
                            + AGREGAR PERSONAL
                        </button>
                    </div>
                    <div style={{ border: '1px solid #ddd', borderRadius: '12px', overflow: 'hidden' }}>
                        <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr 1fr 40px', background: 'var(--color-background)', padding: '0.6rem 1rem', borderBottom: '2px solid #ddd', fontWeight: 800, fontSize: '0.7rem', color: '#666' }} className="hidden sm:grid">
                            <div>NOMBRE Y APELLIDO</div>
                            <div>DNI</div>
                            <div>FIRMA</div>
                            <div></div>
                        </div>
                        {formData.personal.map((p, idx) => (
                            <div key={p.id} style={{ display: 'grid', gridTemplateColumns: '1fr', gap: '10px', padding: '1rem', borderBottom: '1px solid #eee' }} className="sm:grid sm:grid-cols-[2fr_1fr_1fr_40px] sm:items-center">
                                <div className="flex flex-col sm:block">
                                    <span className="sm:hidden text-[0.6rem] font-bold text-blue-500 uppercase mb-1">Nombre:</span>
                                    <input
                                        type="text"
                                        value={p.nombre}
                                        placeholder="Nombre Completo"
                                        onChange={e => updatePersonnel(p.id, 'nombre', e.target.value)}
                                        style={{ border: 'none', background: 'transparent', width: '100%', outline: 'none', fontWeight: 600 }}
                                    />
                                </div>
                                <div className="flex flex-col sm:block">
                                    <span className="sm:hidden text-[0.6rem] font-bold text-blue-500 uppercase mb-1">DNI:</span>
                                    <input
                                        type="text"
                                        value={p.dni}
                                        placeholder="DNI"
                                        onChange={e => updatePersonnel(p.id, 'dni', e.target.value)}
                                        style={{ border: 'none', background: 'transparent', width: '100%', outline: 'none' }}
                                    />
                                </div>
                                <div className="flex items-center gap-2">
                                    <span className="sm:hidden text-[0.6rem] font-bold text-blue-500 uppercase">Firma:</span>
                                    <div style={{ width: '100%', height: '1px', background: '#ccc' }} className="hidden sm:block"></div>
                                </div>
                                <button className="no-print" onClick={() => removePersonnel(p.id)} style={{ background: 'transparent', border: 'none', color: '#ff4d4f', cursor: 'pointer', textAlign: 'right' }}>
                                    <Trash2 size={16} />
                                </button>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Signatures */}
                <div style={{ marginTop: '3rem' }}>
                    <div className="grid grid-cols-1 sm:grid-cols-3 print:grid-cols-3 gap-10 print:gap-6">
                        <div style={{ textAlign: 'center' }}>
                            <div style={{ height: '60px' }}></div>
                            <div style={{ borderTop: '2px solid #333', paddingTop: '10px' }}>
                                <p style={{ margin: 0, fontWeight: 900, fontSize: '0.8rem' }}>SUPERVISOR / RESPONSABLE</p>
                                <p style={{ margin: 0, fontSize: '0.6rem', color: '#666' }}>Aclaración y Firma</p>
                            </div>
                        </div>
                        <div style={{ textAlign: 'center' }}>
                            <div style={{ height: '60px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                {professional.signature && <img src={professional.signature} alt="Firma" style={{ height: '100%', objectFit: 'contain' }} />}
                            </div>
                            <div style={{ borderTop: '2px solid #333', paddingTop: '10px' }}>
                                <p style={{ margin: 0, fontWeight: 900, fontSize: '0.8rem' }}>{professional.name.toUpperCase()}</p>
                                <p style={{ margin: 0, fontSize: '0.6rem', color: '#666' }}>Mat.: {professional.license}</p>
                            </div>
                        </div>
                        <div style={{ textAlign: 'center' }} className="hidden sm:block print:block">
                            <div style={{ height: '60px' }}></div>
                            <div style={{ borderTop: '2px solid #333', paddingTop: '10px' }}>
                                <p style={{ margin: 0, fontWeight: 900, fontSize: '0.8rem' }}>FECHA DE CIERRE</p>
                                <p style={{ margin: 0, fontSize: '0.6rem', color: '#666' }}>Sello y Firma receptora</p>
                            </div>
                        </div>
                    </div>
                </div>

                {/* Footer Notes */}
                <div style={{ marginTop: '3rem', fontSize: '0.65rem', color: '#666', fontStyle: 'italic', borderTop: '1px solid #eee', paddingTop: '1rem' }}>
                    * El presente permiso tiene validez únicamente por la jornada laboral y tareas especificadas.
                    En caso de cambios en las condiciones o personal, se deberá emitir un nuevo permiso.
                </div>
            </div>
        </div>
    );
}

function StatusBtn({ active, onClick, label, color = '#36B37E' }) {
    return (
        <button
            onClick={onClick}
            style={{
                padding: '4px 12px',
                borderRadius: '6px',
                border: '1px solid #ddd',
                background: active ? color : 'var(--color-surface)',
                color: active ? 'white' : '#666',
                fontSize: '0.7rem',
                fontWeight: 800,
                cursor: 'pointer'
            }}
        >
            {label}
        </button>
    );
}

function DocBox({ label, value, onChange, type = "text", borderLeft, borderTop, noInput, children }) {
    return (
        <div style={{
            padding: '1rem',
            borderLeft: borderLeft ? '2px solid #ddd' : 'none',
            borderTop: borderTop ? '2px solid #ddd' : 'none',
            display: 'flex',
            flexDirection: 'column',
            gap: '4px'
        }}>
            <span style={{ fontSize: '0.6rem', fontWeight: 900, color: '#999', textTransform: 'uppercase' }}>{label}</span>
            {noInput ? children : (
                <input
                    type={type}
                    value={value}
                    onChange={e => onChange(e.target.value)}
                    style={{ border: 'none', background: 'transparent', fontWeight: 800, fontSize: '0.9rem', outline: 'none', width: '100%' }}
                />
            )}
        </div>
    );
}

